}
.project-rail-card{
  position:sticky;
  top:12px;
  width:46px;
  min-height:220px;
  border:1px solid #bfdbfe;
  background:linear-gradient(180deg,#eff6ff,#fff);
  border-radius:18px;
  box-shadow:0 10px 26px rgba(15,23,42,.07);
