/* ===== PLM V8.5.104 测试中心证据工作区修正 START ===== */
.test-project-layout{grid-template-columns:minmax(280px,.48fr) minmax(760px,1.52fr)!important;gap:14px!important;align-items:start!important;overflow:visible!important}
.test-project-board{padding:12px!important;min-width:0!important}
