    power:componentText([m.driver_name,m.driver_brand,m.driver_spec]),
    chip:componentText([m.chip_name,m.chip_brand,m.chip_spec]),
    optical:componentText([m.optical_name,m.optical_brand,m.optical_spec])
  };
}
