function testRunsFor(t){return (testRuns||[]).filter(x=>Number(x.test_id)===Number(t?.id||0)).sort((a,b)=>(Number(a.run_no)-Number(b.run_no))||(Number(a.id)-Number(b.id)))}
function testRunText(x){return [x.status,x.result,x.retest_result,x.test_conclusion,x.test_data,x.note].map(v=>String(v||'')).join(' ')}
function testHistoryStats(t,arr){
  const runs=testRunsFor(t);
  const txt=x=>testRunText(x);
  if(runs.length){
    const fail=runs.filter(x=>/不通过|失败|异常|需整改|NG/i.test(txt(x))).length;
    const currentText=txt(t);
    const affect=runs.some(x=>Number(x.affect_sample||0)>0)||Number(t.affect_sample||0)>0;
    const issue=Number(t.issue_id||0)>0||Number(t.problem_generated||0)>0;
    const pendingRetest=/待复测|复测/i.test(currentText)||runs.some(x=>/待复测/i.test(txt(x)));
    const lastRun=runs[runs.length-1]||t;
    const last=(lastRun.result||lastRun.status||t.result||t.status||'待测');
    return {fail,retest:Math.max(0,runs.length-1),runs:runs.length,affect,issue,pendingRetest,last};
  }
  const same=(arr||[]).filter(x=>Number(x.model_id||0)===Number(t.model_id||0)&&String(x.test_type||'').trim()===String(t.test_type||'').trim());
  const fail=same.filter(x=>/不通过|失败|异常|需整改|NG/i.test([x.status,x.result,x.retest_result,x.test_conclusion,x.note].map(v=>String(v||'')).join(' '))).length;
  const retestMarked=same.filter(x=>/复测|重测/i.test([x.status,x.result,x.retest_result,x.test_conclusion,x.note].map(v=>String(v||'')).join(' '))).length;
  const retest=Math.max(retestMarked, same.length>1 ? same.length-1 : 0);
  const currentText=[t.status,t.result,t.retest_result,t.test_conclusion,t.note].map(v=>String(v||'')).join(' ');
  const affect=Number(t.affect_sample||0)>0;
  const issue=Number(t.issue_id||0)>0||Number(t.problem_generated||0)>0;
  const pendingRetest=/待复测|复测/i.test(currentText);
  const last=(t.result||t.status||'待测');
  return {fail,retest,runs:0,affect,issue,pendingRetest,last};
}
function renderTestNodeCard(t,arr,ms){
  const m=(ms||models||[]).find(x=>Number(x.id)===Number(t.model_id));
  const cls=testNodeStatusClass(t);
  const active=Number(t.id)===Number(testSelectedId)?' active':'';
  const hs=testHistoryStats(t,arr);
  const attachCount=(files||[]).filter(f=>Number(f.test_id)===Number(t.id)).length;
  const sampleText=m?testModelLabel(m):'项目公共';
  const date=dateOnly(t.test_date)||'-';
  const op=t.operator||'-';
  const last=hs.last||'-';
  const retest=hs.retest?`<span class="mini-tag orange">复测 ${hs.retest}</span>`:'';
  const issue=hs.issue?'<i class="test-issue-dot" title="有关联问题"></i>':'';
  return `<div class="test-node${active} ${cls}" onclick="testNodeClick(${t.id})" title="${esc(t.test_conclusion||t.note||last||'')}">
    <div class="test-node-row first"><b>${esc(t.title||'未命名测试')}</b><span class="test-node-status ${cls}">${esc(t.status||'待测')}</span></div>
    <div class="test-node-row"><span>${esc(t.test_type||'测试')}</span><span>${esc(sampleText)}</span></div>
    <div class="test-node-row"><span>${esc(date)}</span><span>${esc(op)}</span></div>
    <div class="test-node-row last"><span>${issue}${esc(last||'-')}</span><span>附件 ${attachCount}</span>${retest}</div>
  </div>`;
}

function testReportIsFailed(t){
  const x=[t.status,t.result,t.retest_result,t.test_conclusion,t.test_data,t.note].map(v=>String(v||'')).join(' ');
  return /不通过|失败|异常|需整改|NG/i.test(x)||Number(t.affect_sample||0)>0;
}
function testReportNeedsRetest(t){
  const x=[t.status,t.result,t.retest_result,t.test_conclusion,t.note].map(v=>String(v||'')).join(' ');
  return /待复测|复测|重测/i.test(x);
}
function testReportIsDone(t){
  const x=[t.status,t.result].map(v=>String(v||'')).join(' ');
  return /通过|已完成/.test(x)&&!testReportIsFailed(t)&&!testReportNeedsRetest(t);
}
function testReportCsvCell(v){v=String(v??'').replace(/"/g,'""').replace(/[\r\n]+/g,' ');return '"'+v+'"'}
function exportCurrentProjectTestReport(){
  const p=cur(); if(!p){toast('请先选择项目');return;}
  const arr=pTests(p.id); const ms=pModels(p.id);
  const rows=[['测试类型','测试标题','样品','日期','测试人','状态','结论','重测次数','不通过次数','附件数']];
  arr.forEach(t=>{const m=ms.find(x=>Number(x.id)===Number(t.model_id))||{};const hs=testHistoryStats(t,arr);const ac=(files||[]).filter(f=>Number(f.test_id)===Number(t.id)).length;rows.push([t.test_type||'',t.title||'',m.name||m.model||'',dateOnly(t.test_date)||'',t.operator||'',t.status||'',t.result||t.test_conclusion||'',hs.retest||0,hs.fail||0,ac]);});
  const csv='\ufeff'+rows.map(r=>r.map(testReportCsvCell).join(',')).join('\n');
  const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([csv],{type:'text/csv;charset=utf-8'}));a.download='PLM测试报表_'+(p.name||p.id)+'_'+new Date().toISOString().slice(0,10)+'.csv';document.body.appendChild(a);a.click();setTimeout(()=>{URL.revokeObjectURL(a.href);a.remove()},800);toast('测试报表已导出');
}
function renderTestReportPanel(p,arr,ms,typeCounts,statusCounts){
  const total=arr.length;
  const done=arr.filter(testReportIsDone).length;
  const failed=arr.filter(testReportIsFailed).length;
  const retest=arr.filter(testReportNeedsRetest).length;
  const pending=arr.filter(t=>!testReportIsDone(t)&&!testReportIsFailed(t)&&!testReportNeedsRetest(t)).length;
  const fileTotal=(files||[]).filter(f=>Number(f.project_id)===Number(p.id)&&Number(f.test_id||0)>0).length;
  const rectifyLinks=(dispatchLinks||[]).filter(l=>String(l.link_type||'')==='test_rectify'&&arr.some(t=>Number(t.id)===Number(l.test_id)));
  const rectifyOpen=rectifyLinks.filter(l=>!(Number(l.progress||0)>=100||/完成|已完成|done/i.test(String(l.status||'')))).length;
  const sampleMap={};
  (ms||[]).forEach(m=>sampleMap[Number(m.id)]={name:m.name||m.model||('样品'+m.id),total:0,done:0,failed:0,retest:0,pending:0});
  const typeMap={};
  arr.forEach(t=>{
    const type=(t.test_type||'其它').trim()||'其它';
    if(!typeMap[type]) typeMap[type]={total:0,done:0,failed:0,retest:0,pending:0,files:0};
    const ac=(files||[]).filter(f=>Number(f.test_id)===Number(t.id)).length;
    const sm=sampleMap[Number(t.model_id)]||(sampleMap[Number(t.model_id)]={name:Number(t.model_id)?('样品'+t.model_id):'项目公共',total:0,done:0,failed:0,retest:0,pending:0});
    [typeMap[type],sm].forEach(o=>{o.total++;o.files=(o.files||0)+ac;if(testReportIsFailed(t))o.failed++;else if(testReportNeedsRetest(t))o.retest++;else if(testReportIsDone(t))o.done++;else o.pending++;});
  });
  const typeRows=Object.entries(typeMap).sort((a,b)=>b[1].total-a[1].total).map(([name,o])=>`<tr><td>${esc(name)}</td><td>${o.total}</td><td><span class="tag green">${o.done}</span></td><td><span class="tag red">${o.failed}</span></td><td><span class="tag orange">${o.retest}</span></td><td>${o.pending}</td><td>${o.files||0}</td></tr>`).join('')||`<tr><td colspan="7">暂无测试类型统计</td></tr>`;
  const sampleRows=Object.values(sampleMap).filter(o=>o.total>0).sort((a,b)=>b.failed-a.failed||b.retest-a.retest||b.total-a.total).slice(0,8).map(o=>`<tr><td>${esc(o.name)}</td><td>${o.total}</td><td><span class="tag green">${o.done}</span></td><td><span class="tag red">${o.failed}</span></td><td><span class="tag orange">${o.retest}</span></td><td>${o.pending}</td></tr>`).join('')||`<tr><td colspan="6">暂无样品测试统计</td></tr>`;
  const risks=arr.filter(t=>testReportIsFailed(t)||testReportNeedsRetest(t)||Number(t.issue_id||0)>0||Number(t.affect_sample||0)>0).sort((a,b)=>Number(testReportIsFailed(b))-Number(testReportIsFailed(a))||Number(testReportNeedsRetest(b))-Number(testReportNeedsRetest(a))||Number(b.id)-Number(a.id)).slice(0,8);
  const riskHtml=risks.map(t=>{const m=ms.find(x=>Number(x.id)===Number(t.model_id))||{};const cls=testReportIsFailed(t)?'red':'orange';const reason=testReportIsFailed(t)?'不通过/异常/影响样品':(testReportNeedsRetest(t)?'待复测/重测':'有问题闭环');return `<div class="test-risk-item ${cls}"><div><div class="test-risk-title">${esc(t.test_type||'测试')} · ${esc(t.title||'未命名')}</div><div class="test-risk-meta">${esc(m.name||m.model||'项目公共')} ｜ ${esc(dateOnly(t.test_date)||'-')} ｜ ${esc(t.operator||'-')} ｜ ${esc(reason)}</div></div><button class="btn small" onclick="testNodeClick(${Number(t.id)})">打开</button></div>`}).join('')||'<div class="test-report-muted">当前项目暂无异常测试。</div>';
  const pct=total?Math.round(done*100/total):0;
  const collapsed=localStorage.getItem('plm_v85_test_dashboard_collapsed')==='1';
  const head=`<div class="test-report-head"><div><h3>测试看板 / 报表</h3>${collapsed?`<div class="test-report-mini"><span class="mini-tag">总数 ${total}</span><span class="mini-tag">完成 ${done}</span><span class="mini-tag">异常 ${failed}</span><span class="mini-tag">复测 ${retest}</span><span class="mini-tag">附件 ${fileTotal}</span></div>`:''}</div><div class="actions"><span class="tag blue">完成率 ${pct}%</span><button class="btn small" onclick="toggleTestDashboard()">${collapsed?'展开':'折叠'}</button><button class="btn small" onclick="exportCurrentProjectTestReport()">导出 CSV</button><button class="btn small" onclick="window.print()">打印</button></div></div>`;
  if(collapsed){return `<div class="test-report-panel collapsed">${head}</div>`;}
  return `<div class="test-report-panel">${head}<div class="test-report-body"><div class="test-report-cards"><div class="test-report-card blue"><span>测试总数</span><b>${total}</b></div><div class="test-report-card green"><span>已通过 / 已完成</span><b>${done}</b></div><div class="test-report-card red"><span>异常 / 不通过</span><b>${failed}</b></div><div class="test-report-card orange"><span>待复测</span><b>${retest}</b></div><div class="test-report-card"><span>待测 / 测试中</span><b>${pending}</b></div><div class="test-report-card"><span>测试附件</span><b>${fileTotal}</b></div><div class="test-report-card ${rectifyOpen?'orange':'green'}"><span>整改派工未完</span><b>${rectifyOpen}</b></div><div class="test-report-card"><span>样品覆盖</span><b>${Object.values(sampleMap).filter(o=>o.total>0).length}/${ms.length}</b></div></div><div class="test-report-grid"><div><div class="test-report-subtitle">测试类型汇总</div><table class="test-report-table"><thead><tr><th>类型</th><th>总数</th><th>通过</th><th>异常</th><th>复测</th><th>待测</th><th>附件</th></tr></thead><tbody>${typeRows}</tbody></table><div class="test-report-subtitle">样品测试汇总</div><table class="test-report-table"><thead><tr><th>样品</th><th>总数</th><th>通过</th><th>异常</th><th>复测</th><th>待测</th></tr></thead><tbody>${sampleRows}</tbody></table></div><div><div class="test-report-subtitle">异常 / 待复测清单</div><div class="test-risk-list">${riskHtml}</div></div></div></div></div>`;
}

function toggleTestDashboard(){
  const v=localStorage.getItem('plm_v85_test_dashboard_collapsed')==='1';
  localStorage.setItem('plm_v85_test_dashboard_collapsed',v?'0':'1');
  const p=cur();
  if(p) renderTests(p); else renderDetail();
}
function setTestNodeFilter(v){
  testNodeFilter=v||'all';
  localStorage.setItem('plm_v85_test_node_filter',testNodeFilter);
  renderDetail();
}
function setTestNodeSearch(v){
  testNodeSearch=String(v||'');
  localStorage.setItem('plm_v85_test_node_search',testNodeSearch);
  renderTests(cur());
}
function testNodeMatchesFilter(t){
  const f=testNodeFilter||'all';
  const txt=[t.status,t.result,t.retest_result,t.test_conclusion,t.test_data,t.note].map(v=>String(v||'')).join(' ');
  if(f==='failed')return testFailed(t);
  if(f==='retest')return testStatusValue(t)==='待复测'||testRetestCount(t,tests)>0;
  if(f==='pending')return !testPassed(t)&&!testFailed(t)&&testStatusValue(t)!=='待复测';
  if(f==='done')return testPassed(t);
  if(f==='issue')return Number(t.issue_id||0)>0||Number(t.problem_generated||0)>0||testNeedsIssue(t);
  if(f==='file')return (files||[]).some(x=>Number(x.test_id)===Number(t.id));
  return true;
}
function testNodeMatchesSearch(t,ms){
  const q=String(testNodeSearch||'').trim().toLowerCase();
  if(!q)return true;
  const m=(ms||[]).find(x=>Number(x.id)===Number(t.model_id))||{};
  const txt=[t.test_type,t.title,t.status,t.result,t.operator,t.test_conclusion,t.test_data,t.note,m.name,m.model,m.sample_no].map(v=>String(v||'').toLowerCase()).join(' ');
  return txt.includes(q);
}
function renderTestFilterBar(arr,ms){
  const btn=(key,label,count)=>`<button class="btn small ${testNodeFilter===key?'primary':''}" onclick="setTestNodeFilter('${key}')">${label}${count!==undefined?' '+count:''}</button>`;
  const failed=arr.filter(testReportIsFailed).length;
  const retest=arr.filter(testReportNeedsRetest).length;
  const done=arr.filter(testReportIsDone).length;
  const pending=arr.filter(t=>!testReportIsDone(t)&&!testReportIsFailed(t)&&!testReportNeedsRetest(t)).length;
  const issue=arr.filter(t=>Number(t.issue_id||0)>0||Number(t.problem_generated||0)>0||testNeedsIssue(t)).length;
  const file=arr.filter(t=>(files||[]).some(x=>Number(x.test_id)===Number(t.id))).length;
  return `<div class="test-filter-toolbar"><div class="test-filter-line"><input class="test-filter-search" value="${esc(testNodeSearch||'')}" placeholder="搜索测试/样品/测试人" oninput="setTestNodeSearch(this.value)"><button class="btn small" onclick="testNodeSearch='';localStorage.removeItem('plm_v85_test_node_search');renderDetail()">清空</button></div><div class="test-filter-chips">${btn('all','全部',arr.length)}${btn('failed','异常',failed)}${btn('retest','待复测',retest)}${btn('pending','待测',pending)}${btn('done','通过',done)}${btn('issue','问题',issue)}${btn('file','有附件',file)}</div></div>`;
}
function normalizeTestTypeName(type){
  const s=String(type||'').trim();
  if(!s)return '温升测试';
  if(s==='温升')return '温升测试';
  if(s==='IES')return 'IES配光测试';
  if(s==='积分球')return '积分球测试';
  if(s==='EMC')return 'EMC测试';
  if(s==='IP防水'||s==='防水')return '防水/IP测试';
  if(s==='老化')return '老化测试';
  if(s==='结构装配')return '结构/装配检查';
  return s;
}
function testStatusValue(t){
  const s=String(t?.status||'').trim();
  if(/测试中|进行中/.test(s))return '进行中';
  if(/待复测|需整改/.test(s))return '待复测';
  if(/取消/.test(s))return '已取消';
  if(/通过|不通过|完成|已完成/.test(s))return '已完成';
  return s||'未开始';
}
function testResultValue(t){
  const r=String(t?.result||'').trim();
  const s=String(t?.status||'').trim();
  const text=[t?.result,t?.status,t?.test_conclusion,t?.retest_result,t?.note].map(v=>String(v||'')).join(' ');
  if(/不通过|失败|异常|需整改|NG/i.test(text))return '不通过';
  if(r)return r;
  if(/通过|OK|PASS/i.test(s))return '通过';
  return '待判定';
}
function testPassed(t){return testResultValue(t)==='通过' && testStatusValue(t)==='已完成'}
function testFailed(t){return testResultValue(t)==='不通过'}
function testRetestCount(t,arr){
  const id=Number(t?.id||0), src=Number(t?.source_test_id||0);
  if(src>0)return Number(t?.retest_no||0)||1;
  return (arr||tests||[]).filter(x=>Number(x.source_test_id||0)===id).length;
}
function testFileBuckets(t){
  const list=(files||[]).filter(f=>Number(f.test_id)===Number(t?.id||0)&&Number(f.test_run_id||0)===0);
  const isImg=f=>String(f.mime_type||'').startsWith('image/')||/\.(jpg|jpeg|png|webp|gif)$/i.test(String(f.original_name||f.file_name||f.file_path||''));
  const isReport=f=>/报告|配光|光谱|EMC|PDF/i.test(String(f.category||'')+' '+String(f.title||'')+' '+String(f.original_name||''))||/\.pdf$/i.test(String(f.original_name||f.file_name||''));
  const isRaw=f=>/原始|数据|IES|LDT|CSV|Excel|表格/i.test(String(f.category||'')+' '+String(f.title||'')+' '+String(f.original_name||''))||/\.(ies|ldt|csv|xls|xlsx)$/i.test(String(f.original_name||f.file_name||''));
  const images=list.filter(isImg);
  const reports=list.filter(f=>!isImg(f)&&isReport(f));
  const raw=list.filter(f=>!isImg(f)&&!isReport(f)&&isRaw(f));
  const normal=list.filter(f=>!images.includes(f)&&!reports.includes(f)&&!raw.includes(f));
  return {images,reports,raw,files:normal,all:list};
}
function testSampleName(t,ms){
  const m=(ms||models||[]).find(x=>Number(x.id)===Number(t?.model_id||0));
  return m?testModelLabel(m):'项目公共测试';
}
function testModelLabel(m){return (m.model||m.naming_model_no||m.sample_no||m.name||('样品'+m.id))}
function renderTestProjectCard(t,arr,ms){
  const status=testStatusValue(t), result=testResultValue(t), buckets=testFileBuckets(t);
  const cls=testFailed(t)?'failed':(testPassed(t)?'passed':(status==='待复测'?'retest':(status==='进行中'?'running':'pending')));
  const active=Number(t.id)===Number(testSelectedId)?' active':'';
  const date=dateOnly(t.test_date)||'-';
  const retest=testRetestCount(t,arr);
  return `<button class="test-project-card ${cls}${active}" onclick="testNodeClick(${Number(t.id)})" title="${esc(t.test_conclusion||t.note||'')}">
    <div class="test-card-title"><span class="test-type-icon">${esc(String(t.test_type||'测').slice(0,2))}</span><b>${esc(t.title||t.test_type||'测试项目')}</b><em>${esc(status)}</em></div>
    <div class="test-card-meta"><span class="${result==='不通过'?'bad':(result==='通过'?'good':'')}">结果：${esc(result)}</span><span>${esc(date)}</span></div>
    <div class="test-card-meta"><span>测试人：${esc(t.operator||'-')}</span></div>
    <div class="test-card-files"><span>图片 ${buckets.images.length}</span><span>文件 ${buckets.files.length+buckets.raw.length}</span><span>报告 ${buckets.reports.length}</span><span>复测 ${retest}</span></div>
  </button>`;
}
function renderTestTemplateChooserInline(ms){
  const cards=TEST_TEMPLATE_DEFAULTS.filter(t=>['温升测试','IES配光测试','积分球测试','EMC测试','防水/IP测试','老化测试','结构/装配检查','自定义测试'].includes(t.test_type)).map(t=>`<button class="test-template-card" onclick="createTestFromTemplate('${esc(t.key)}')"><b>${esc(t.name)}</b><span>${esc(t.usage||'添加一个独立测试项目')}</span><em>${esc((t.fields||[]).slice(0,4).map(f=>f.label).join(' / '))}</em><strong>加入测试板</strong></button>`).join('');
  return `<div class="test-template-board"><div class="test-template-board-head"><div><b>添加测试项目</b><span>每个测试项目都会生成独立 test_id，图片、文件和报告分别归档。</span></div><button class="btn small primary" onclick="addCommonTests()">一键加入常用测试</button></div><div class="test-template-card-grid">${cards}</div></div>`;
}
function openAddTestProjectPanel(){const host=document.createElement('div');host.innerHTML=`<div class="modal-mask" onclick="if(event.target===this)this.remove()"><div class="modal" style="width:min(980px,96vw)"><div class="modal-head"><div><h3>添加测试项目</h3><div class="hint">选择模板后会在当前样品下创建独立测试记录。</div></div><button class="btn" onclick="this.closest('.modal-mask').remove()">关闭</button></div><div class="modal-body">${renderTestTemplateChooserInline(pModels(cur()?.id||selectedId))}</div></div></div>`;document.body.appendChild(host.firstElementChild)}
function currentTestModelForCreate(){
  const n=Number(testModelId);
  return n>0?n:0;
}
async function createTestFromTemplate(key){
  const p=cur();if(!p){toast('请先选择项目');return}
  const tpl=templateByKey(key)||TEST_TEMPLATE_DEFAULTS[0];
  const mid=currentTestModelForCreate();
  const exists=pTests(p.id).find(t=>Number(t.model_id||0)===Number(mid)&&normalizeTestTypeName(t.test_type)===normalizeTestTypeName(tpl.test_type)&&Number(t.source_test_id||0)===0);
  if(exists){testCreateMode=false;testSelectedId=Number(exists.id);localStorage.setItem('plm_v85_test_id',testSelectedId);toast('当前样品已存在这个测试项目');renderDetail();return}
  const snap=currentComponentSnapshot(mid);
  const r=await api('save_test',{project_id:p.id,model_id:mid,test_type:tpl.test_type,title:tpl.name,status:'未开始',result:'待判定',test_date:'',operator:'',template_key:tpl.key,template_name:tpl.name,template_fields_json:{_test_power:snap.power,_test_chip:snap.chip,_test_optical:snap.optical,_test_custom_component:''}});
  toast(r.ok?'测试项目已加入':r.error);
  if(r.ok&&r.id){testCreateMode=false;testSelectedId=Number(r.id);localStorage.setItem('plm_v85_test_id',testSelectedId);const mask=document.querySelector('.modal-mask');if(mask)mask.remove()}
  await load();
}
async function addCommonTests(){
  const p=cur();if(!p){toast('请先选择项目');return}
  const keys=['builtin_temp','builtin_ies','builtin_sphere'];let added=0, skipped=0;
  for(const key of keys){
    const tpl=templateByKey(key);if(!tpl)continue;
    const mid=currentTestModelForCreate();
    const exists=pTests(p.id).some(t=>Number(t.model_id||0)===Number(mid)&&normalizeTestTypeName(t.test_type)===normalizeTestTypeName(tpl.test_type)&&Number(t.source_test_id||0)===0);
    if(exists){skipped++;continue}
    const snap=currentComponentSnapshot(mid);
    const r=await api('save_test',{project_id:p.id,model_id:mid,test_type:tpl.test_type,title:tpl.name,status:'未开始',result:'待判定',template_key:tpl.key,template_name:tpl.name,template_fields_json:{_test_power:snap.power,_test_chip:snap.chip,_test_optical:snap.optical,_test_custom_component:''}});
    if(r.ok){added++;testSelectedId=Number(r.id);localStorage.setItem('plm_v85_test_id',testSelectedId)}else{toast(r.error);break}
  }
  toast(`常用测试已加入 ${added} 个，跳过已有 ${skipped} 个`);
  await load();
}

function renderTests(p){
  if(!p){$('tabbody').innerHTML='<div class="empty">请选择项目</div>';return}
  const arr=pTests(p.id).sort((a,b)=>Number(b.id)-Number(a.id));
  const ms=pModels(p.id);
  if(ms.length && (!testModelId || (testModelId>0 && !ms.some(m=>Number(m.id)===Number(testModelId))))){
    testModelId=flowModelId&&ms.some(m=>Number(m.id)===Number(flowModelId))?Number(flowModelId):Number(ms[0].id||0);
    localStorage.setItem('plm_v85_test_model',testModelId);
  }
  if(!ms.length && !testModelId){testModelId=0;localStorage.setItem('plm_v85_test_model',0)}
  const currentModel=ms.find(m=>Number(m.id)===Number(testModelId))||null;
  const scoped=arr.filter(t=>Number(testModelId)<0 || Number(t.model_id||0)===Number(testModelId||0));
  const filtered=scoped;
  if(!testCreateMode){
    if(testSelectedId&&!filtered.some(x=>Number(x.id)===Number(testSelectedId))){testSelectedId=filtered[0]?Number(filtered[0].id):0;localStorage.setItem('plm_v85_test_id',testSelectedId||0)}
    if(!testSelectedId&&filtered[0]){testSelectedId=Number(filtered[0].id);localStorage.setItem('plm_v85_test_id',testSelectedId||0)}
  }
  const selected=testCreateMode?null:(arr.find(x=>Number(x.id)===Number(testSelectedId))||null);
  const modelOptions=`<option value="-1" ${Number(testModelId)<0?'selected':''}>全部测试</option><option value="0" ${Number(testModelId)===0?'selected':''}>项目公共测试</option>`+ms.map(m=>`<option value="${m.id}" ${Number(m.id)===Number(testModelId)?'selected':''}>${esc(testModelLabel(m))}</option>`).join('');
  const total=scoped.length, passed=scoped.filter(testPassed).length, failed=scoped.filter(testFailed).length, retest=scoped.filter(t=>testStatusValue(t)==='待复测'||testRetestCount(t,arr)>0).length;
  const pct=total?Math.round(passed*100/total):0;
  const stat=`<div class="test-brief-stat"><span><b>${pct}%</b>完成率</span><span><b>${passed}/${total}</b>测试</span><span class="good"><b>${passed}</b>通过</span><span class="bad"><b>${failed}</b>不通过</span><span class="warn"><b>${retest}</b>待复测</span></div>`;
  const nodes=filtered.map(t=>renderTestProjectCard(t,scoped,ms)).join('')||`<div class="test-empty-small">${scoped.length?'当前筛选下暂无测试记录。':'当前样品暂无测试项目。'}<br><button class="btn small primary" onclick="openAddTestProjectPanel()">添加测试项目</button></div>`;
  const detailHtml=(!testCreateMode&&!selected)?`<div class="test-detail-empty"><b>请选择测试记录</b><span>从左侧选择一条测试记录，或点击“新增测试”。</span><button class="btn primary" onclick="newTestNode(activeTestType||'温升')">新增测试</button></div>`:renderTestDetailForm(p,selected,ms);
  $('tabbody').innerHTML=`<div class="test-workbench">
    <div class="test-project-layout">
      <div class="test-project-board"><div class="test-left-controls"><select class="test-model-picker" onchange="setTestModel(this.value)">${modelOptions}</select><div class="test-left-actions"><button class="btn primary" onclick="openAddTestProjectPanel()">新增测试</button><button class="btn good" onclick="addCommonTests()">常用测试</button><details class="test-more-menu"><summary>更多</summary><div><button class="btn small" onclick="openTestTemplateDrawer()">测试模板管理</button><button class="btn small" onclick="exportCurrentProjectTestReport()">导出 CSV</button><button class="btn small" onclick="window.print()">打印</button><button class="btn small" onclick="openTestDashboardModal()">测试报表</button></div></details></div></div>${stat}<div class="test-node-head"><h3>测试项目</h3></div>
        <div class="test-card-grid">${nodes}</div>
        ${!scoped.length?renderTestTemplateChooserInline(ms):''}
      </div>
      <aside class="test-detail-side">${detailHtml}</aside>
    </div>
  </div>`;
}
function renderTemplateSelect(t){const tpl=templateForTest(t);const list=allTestTemplates();return `<select id="t_template" onchange="changeTestTemplate()">${list.map(x=>`<option value="${esc(x.key)}" ${(tpl&&String(x.key)===String(tpl.key))?'selected':''}>${esc(x.name)}${x.builtin?'':' · 自定义'}</option>`).join('')}</select>`}
function testTplHasBind(tpl,bind){return !!((tpl&&tpl.fields)||[]).some(f=>String(f.bind||'')===String(bind))}
function hiddenTestTextarea(id,val){return `<textarea id="${esc(id)}" style="display:none">${esc(val||'')}</textarea>`}
function issueForTest(t){
  if(!t)return null;
  const tid=Number(t.id||0);const iid=Number(t.issue_id||0);
  let it=(issues||[]).find(x=>iid>0&&Number(x.id)===iid);
  if(it)return it;
  it=(issues||[]).find(x=>Number(x.test_id||0)===tid);
  if(it)return it;
  return (issues||[]).find(x=>Number(x.project_id)===Number(t.project_id)&&String(x.note||'').includes('自动来源测试ID:'+tid))||null;
}
function testNeedsIssue(t){
  if(!t)return false;
  const x=String(t.status||'')+' '+String(t.result||'')+' '+String(t.retest_result||'');
  return /不通过|失败|异常|需整改|待复测/.test(x)||Number(t.affect_sample||0)>0;
}

function userSelectOptions(selectedId=0,selectedName=''){
  const list=(plmPermissionUsers||[]).filter(u=>u&&((u.id||0)>0||u.name||u.username));
  const opts=['<option value="0">选择负责人</option>'].concat(list.map(u=>`<option value="${Number(u.id||0)}" ${(Number(selectedId)>0&&Number(u.id)===Number(selectedId))||(!selectedId&&selectedName&&String(u.name||u.username)===String(selectedName))?'selected':''}>${esc(u.name||u.username||('用户'+u.id))}</option>`));
  if(selectedName&&!list.some(u=>String(u.name||u.username)===String(selectedName))) opts.push(`<option value="0" selected>${esc(selectedName)}</option>`);
  return opts.join('');
}
function testRectifyLink(issueId,testId){
  issueId=Number(issueId||0);testId=Number(testId||0);
  return (dispatchLinks||[]).find(x=>String(x.link_type||'')==='test_rectify'&&((issueId&&Number(x.issue_id)===issueId)||(testId&&Number(x.test_id)===testId)))||null;
}
function renderTestRectifyDispatchPanel(t,it){
  if(!t||!it)return '';
  const link=testRectifyLink(it.id,t.id);
  if(link){
    const done=/done|完成|已完成|approved|已确认/i.test(String(link.status||''))||Number(link.progress||0)>=100;
    const url=link.dispatch_url||(`dispatch_next.php?open_task=${Number(link.task_id||0)}&single_task=1`);
    return `<div class="test-rectify-panel ${done?'done':''}"><div class="test-rectify-head"><span>整改派工</span><span class="tag ${done?'green':'blue'}">${esc(link.status||'已生成')}</span></div><div class="test-rectify-meta">负责人：${esc(link.assignee_name||'-')} ｜ 进度：${Number(link.progress||0)}% ｜ 截止：${esc(dateOnly(link.due_at)||'-')} ｜ 派工ID：${esc(link.task_id||'')}</div><div class="actions"><button class="btn small primary" onclick="window.open('${esc(url)}','_blank')">查看派工</button>${done?'<span class="mini-tag green">整改完成，测试会回写为待复测</span>':'<span class="mini-tag blue">等待工程整改</span>'}</div></div>`;
  }
  return `<div class="test-rectify-panel"><div class="test-rectify-head"><span>整改派工</span><span class="tag orange">未生成</span></div><div class="test-rectify-meta">测试异常后，可一键生成派工给工程整改。派工完成后，问题闭环会更新，测试状态会回写为待复测。</div><div class="test-rectify-actions"><select id="test_rectify_user_${Number(t.id)}">${userSelectOptions(0,it.owner||t.operator||'')}</select><input id="test_rectify_due_${Number(t.id)}" type="date" title="整改截止日期"><button class="btn small warn" onclick="createTestRectifyDispatch(${Number(t.id)},${Number(it.id)})">生成整改派工</button></div></div>`;
}
async function createTestRectifyDispatch(testId,issueId){
  const sel=$(`test_rectify_user_${testId}`);const due=$(`test_rectify_due_${testId}`);
  let assignee_id=sel?Number(sel.value||0):0;let assignee_name='';
  if(sel&&sel.selectedOptions&&sel.selectedOptions[0])assignee_name=sel.selectedOptions[0].textContent.trim();
  if(assignee_name==='选择负责人')assignee_name='';
  if(!assignee_id&&!assignee_name){assignee_name=prompt('填写整改负责人姓名','')||'';}
  if(!assignee_id&&!assignee_name){toast('请选择或填写负责人');return;}
  const r=await api('create_test_rectify_dispatch',{test_id:testId,issue_id:issueId,assignee_id,assignee_name,due_at:due?due.value:''});
  toast(r.ok?(r.exists?'已有关联整改派工':'整改派工已生成'):r.error);
  await load();
}
function renderTestIssuePanel(t){
  const it=issueForTest(t);const need=testNeedsIssue(t);const cls=it?' good':'';
  const status=it?(it.status||'待处理'):(need?'待生成':'正常');
  const sev=it?(it.severity||'中'):(Number(t.affect_sample||0)?'高':'中');
  const title=it?(it.title||'测试问题闭环'):(need?'测试异常，建议生成问题闭环':'当前测试没有异常');
  const meta=it?`问题ID：${esc(it.id)} ｜ 状态：${esc(status)} ｜ 严重程度：${esc(sev)} ｜ 负责人：${esc(it.owner||'-')}`:`状态/结论出现不通过、待复测、异常、需整改，或勾选影响样品时，系统会自动生成问题闭环。`;
  const badges=[];
  if(need)badges.push(`<span class="mini-tag red">测试异常</span>`);
  if(Number(t.affect_sample||0)>0)badges.push(`<span class="mini-tag red">影响样品</span>`);
  if(it)badges.push(`<span class="mini-tag blue">已关联问题</span>`); else if(!need)badges.push(`<span class="mini-tag green">无需闭环</span>`);
  const actions=it?`<button class="btn small primary" onclick="gotoIssueFromTest(${Number(it.id)})">查看问题</button><button class="btn small" onclick="gotoTab('issues')">问题中心</button>`:`${need?`<button class="btn small warn" onclick="createIssueFromCurrentTest(${Number(t.id)})">生成问题闭环</button>`:''}<button class="btn small" onclick="gotoTab('issues')">问题中心</button>`;
  const rectify=it?renderTestRectifyDispatchPanel(t,it):'';
  return `<div class="test-form-section test-issue-section${cls}"><h4>问题闭环</h4><div class="test-issue-panel${cls}"><div><div class="test-issue-title">${esc(title)}</div><div class="test-issue-meta">${meta}</div><div class="test-issue-badges">${badges.join('')}</div></div><div class="test-issue-actions">${actions}</div></div>${rectify}</div>`;
}
async function createIssueFromCurrentTest(testId,runId=0){
  if(!testId){toast('请先保存测试节点');return}
  const r=await api('create_issue_from_test',{test_id:testId,test_run_id:runId});
  toast(r.ok?'问题闭环已生成/已关联':r.error);
  await load();
}
function gotoIssueFromTest(issueId){
  tab='issues';localStorage.setItem('plm_v85_tab','issues');renderDetail();
  setTimeout(()=>{const el=document.querySelector(`[data-issue-id="${issueId}"]`);if(el){el.scrollIntoView({behavior:'smooth',block:'center'});el.classList.add('issue-highlight');setTimeout(()=>el.classList.remove('issue-highlight'),1800)}},80);
}

function testEvidenceCounts(t){
  const b=testFileBuckets(t), it=issueForTest(t), runs=testRunsFor(t);
  return {images:b.images.length,files:b.files.length,reports:b.reports.length,raw:b.raw.length,issues:it?1:0,runs:runs.length||0};
}
function testEvidenceTabButton(key,label,count){
  const active=testEvidenceTab===key?' active':'';
  return `<button class="test-evidence-tab${active}" onclick="setTestEvidenceTab('${key}')">${esc(label)} <b>${Number(count||0)}</b></button>`;
}
function setTestEvidenceTab(key){
  testEvidenceTab=key||'images';
  localStorage.setItem('plm_v85_test_evidence_tab',testEvidenceTab);
  renderDetail();
}
function testEvidenceCategoryForTab(tab,testType){
  if(tab==='images')return '测试图片';
  if(tab==='reports')return testTypeDefaultFileCat(testType||'测试').replace('图片','报告');
  if(tab==='raw')return /IES/i.test(String(testType||''))?'IES文件':'原始数据';
  return '测试附件';
}
function testEvidenceAcceptForTab(tab){
  if(tab==='images')return 'image/*';
  if(tab==='reports')return '.pdf,.doc,.docx,.xls,.xlsx,.csv,.txt,.ies,.ldt,.zip';
  if(tab==='raw')return '.ies,.ldt,.csv,.txt,.xls,.xlsx,.zip';
  return '.pdf,.doc,.docx,.xls,.xlsx,.csv,.txt,.ies,.ldt,.zip,image/*';
}
function renderTestEvidenceUpload(t,tab){
  const uid='ev_'+Number(t.id)+'_'+tab;
  const cat=testEvidenceCategoryForTab(tab,t.test_type);
  return `<div class="test-evidence-upload" id="${uid}_drop" ondragover="event.preventDefault();this.classList.add('dragging')" ondragleave="this.classList.remove('dragging')" ondrop="handleTestEvidenceDrop(event,'${uid}')" tabindex="0" onpaste="handleTestEvidencePaste(event,'${uid}')">
    <div class="test-evidence-drop-main"><b>将图片或文件拖到这里</b><span>也可以点击选择，或粘贴截图。当前上传到：${esc(t.title||t.test_type||'测试项目')}</span></div>
    <input id="${uid}_file" type="file" multiple accept="${esc(testEvidenceAcceptForTab(tab))}" onchange="renderTestUploadQueue('${uid}')">
    <div class="test-evidence-upload-grid"><select id="${uid}_cat">${uniq([...TEST_FILE_CATS,cat]).map(c=>`<option ${c===cat?'selected':''}>${esc(c)}</option>`).join('')}</select><input id="${uid}_title" placeholder="文件标题，可不填"></div>
    <textarea id="${uid}_note" placeholder="资料说明 / 图片备注"></textarea>
    <div id="${uid}_queue" class="test-upload-queue"></div>
    <div class="actions"><button class="btn small primary" onclick="uploadTestEvidence('${uid}',${Number(t.id)},${Number(t.model_id||0)},0)">开始上传</button><button class="btn small" onclick="$('${uid}_file').click()">选择文件</button></div>
  </div>`;
}
function renderTestUploadQueue(uid){
  const box=$(uid+'_queue'), input=$(uid+'_file');
  if(!box||!input)return;
  const list=[...(input.files||[])];
  box.innerHTML=list.length?list.map(f=>`<div class="test-upload-row"><span>${esc(f.name)}</span><b>${fileSize(f.size)}</b><em>等待上传</em></div>`).join(''):'';
}
function handleTestEvidenceDrop(ev,uid){
  ev.preventDefault();
  ev.currentTarget.classList.remove('dragging');
  const input=$(uid+'_file');
  if(!input||!ev.dataTransfer)return;
  input.files=ev.dataTransfer.files;
  renderTestUploadQueue(uid);
}
function handleTestEvidencePaste(ev,uid){
  const input=$(uid+'_file');
  if(!input||!ev.clipboardData)return;
  const files=[];
  [...ev.clipboardData.items].forEach((item,i)=>{
    if(item.kind==='file'){
      const f=item.getAsFile();
      if(f){
        const ext=(f.type||'image/png').split('/').pop()||'png';
        files.push(new File([f], 'clipboard_'+new Date().toISOString().replace(/[:.]/g,'-')+'_'+i+'.'+ext, {type:f.type||'image/png'}));
      }
    }
  });
  if(!files.length)return;
  const dt=new DataTransfer();
  files.forEach(f=>dt.items.add(f));
  input.files=dt.files;
  renderTestUploadQueue(uid);
  ev.preventDefault();
}
function uploadApiProgress(form,onProgress){
  return new Promise(resolve=>{
    const xhr=new XMLHttpRequest();
    xhr.open('POST',API+'?action=upload_file',true);
    xhr.withCredentials=true;
    xhr.upload.onprogress=e=>{if(e.lengthComputable&&onProgress)onProgress(Math.round(e.loaded*100/e.total));};
    xhr.onload=()=>{try{resolve(JSON.parse(xhr.responseText||'{}'))}catch(e){resolve({ok:false,error:'上传接口异常：'+String(xhr.responseText||'').slice(0,300)})}};
    xhr.onerror=()=>resolve({ok:false,error:'网络上传失败'});
    xhr.send(form);
  });
}
async function uploadTestEvidence(uid,testId,modelId,runId=0){
  const p=cur();if(!p)return;
  const input=$(uid+'_file'), box=$(uid+'_queue');
  const list=[...(input?.files||[])];
  if(!testId){toast('请先保存测试项目');return}
  if(!list.length){toast('请选择或拖入文件');return}
  const sizeErrors=list.map(plmImageUploadError).filter(Boolean);
  if(sizeErrors.length){toast(sizeErrors[0]);if(box)box.innerHTML=sizeErrors.map(x=>`<div class="test-upload-row fail"><span>${esc(x)}</span><em>未上传</em></div>`).join('');return}
  const existing=pFiles(p.id).filter(f=>Number(f.test_id)===Number(testId));
  const duplicates=list.filter(file=>existing.some(f=>String(f.original_name||'')===String(file.name)&&Number(f.file_size||0)===Number(file.size||0)));
  if(duplicates.length&&!confirm(`当前测试已存在 ${duplicates.length} 个同名同大小文件。继续保留两份？`))return;
  if(box)box.innerHTML=list.map(f=>`<div class="test-upload-row" data-name="${esc(f.name)}"><span>${esc(f.name)}</span><b>${fileSize(f.size)}</b><em>0%</em></div>`).join('');
  let ok=0,fail=0;
  for(const file of list){
    const row=box?[...box.querySelectorAll('.test-upload-row')].find(x=>x.dataset.name===file.name):null;
    const fd=new FormData();
    fd.append('project_id',p.id);
    fd.append('model_id',modelId||0);
    fd.append('test_id',testId||0);
    fd.append('test_run_id',runId||0);
    fd.append('source_module','test');
    fd.append('category',$(uid+'_cat')?.value||'测试附件');
    fd.append('title',$(uid+'_title')?.value||'');
    fd.append('note',$(uid+'_note')?.value||'');
    fd.append('customer_visible',1);
    fd.append('file',file);
    const r=await uploadApiProgress(fd,pct=>{if(row)row.querySelector('em').textContent=pct+'%'});
    if(r.ok){ok++;if(row){row.classList.add('ok');row.querySelector('em').textContent='完成'}}else{fail++;if(row){row.classList.add('fail');row.querySelector('em').textContent='失败：'+(r.error||'未知错误')}}
  }
  toast(`上传完成：成功 ${ok}，失败 ${fail}`);
  await load();
}
function renderEvidenceImageGrid(list){
  if(!list.length)return '<div class="test-evidence-empty">暂无测试图片。可拖入现场照片、温升照片或截图。</div>';
  return `<div class="test-image-grid">${list.map(f=>`<div class="test-image-item"><button onclick="openTestImageLightbox(${Number(f.id)})"><img src="${esc(f.file_path)}" alt="${esc(f.title||f.original_name||'测试图片')}"></button><div><b>${esc(f.title||f.original_name||'图片')}</b><span>${esc(f.created_at||'')}</span></div><div class="actions"><button class="btn small" onclick="openTestImageLightbox(${Number(f.id)})">预览</button><a class="btn small" href="${esc(f.file_path)}" download>下载</a><button class="btn small danger" onclick="deleteFile(${Number(f.id)})">删除</button></div></div>`).join('')}</div>`;
}
function evidenceFileKind(f){
  const name=String(f.original_name||f.file_name||f.file_path||'');
  if(/\.(pdf)$/i.test(name))return 'PDF';
  if(/\.(ies|ldt)$/i.test(name))return 'IES/LDT';
  if(/\.(csv|txt)$/i.test(name))return '文本';
  if(/\.(xls|xlsx)$/i.test(name))return '表格';
  if(/\.(doc|docx)$/i.test(name))return '文档';
  if(/\.(zip|rar|7z)$/i.test(name))return '压缩包';
  return '文件';
}
function renderEvidenceFileList(list,empty){
  if(!list.length)return `<div class="test-evidence-empty">${esc(empty||'暂无资料')}</div>`;
  return `<div class="test-evidence-file-list">${list.slice(0,6).map(f=>`<div class="test-evidence-file-row"><div><b>${esc(f.title||f.original_name||f.file_name||'文件')}</b><span>${esc(evidenceFileKind(f))} ｜ ${fileSize(f.file_size)} ｜ ${esc(f.created_at||'')}</span><em>${esc(f.note||'')}</em></div><div class="actions"><button class="btn small" onclick="openTestFilePreview(${Number(f.id)})">在线预览</button><a class="btn small" href="${esc(f.file_path)}" download>下载</a><button class="btn small danger" onclick="deleteFile(${Number(f.id)})">删除</button></div></div>`).join('')}${list.length>6?`<div class="hint">还有 ${list.length-6} 个，进入文件中心可查看全部。</div>`:''}</div>`;
}
function renderTestEvidencePanel(t){
  const b=testFileBuckets(t), counts=testEvidenceCounts(t);
  if(!['images','files','reports','raw','issues','runs'].includes(testEvidenceTab))testEvidenceTab='images';
  const tabs=`<div class="test-evidence-tabs">${testEvidenceTabButton('images','图片',counts.images)}${testEvidenceTabButton('files','文件',counts.files)}${testEvidenceTabButton('reports','报告',counts.reports)}${testEvidenceTabButton('raw','原始数据',counts.raw)}${testEvidenceTabButton('issues','问题',counts.issues)}${testEvidenceTabButton('runs','复测',counts.runs)}</div>`;
  let body='';
  if(testEvidenceTab==='images')body=renderEvidenceImageGrid(b.images);
  else if(testEvidenceTab==='files')body=renderEvidenceFileList(b.files,'暂无测试文件。');
  else if(testEvidenceTab==='reports')body=renderEvidenceFileList(b.reports,'暂无测试报告。');
  else if(testEvidenceTab==='raw')body=renderEvidenceFileList(b.raw,'暂无原始数据。');
  else if(testEvidenceTab==='issues')body=renderTestIssuePanel(t);
  else body=renderTestRunHistory(t);
  const uploadTabs=['images','files','reports','raw'];
  return `<div class="test-evidence-panel" id="testNodeFileSection"><div class="test-evidence-head"><h4>附件资料</h4>${uploadTabs.includes(testEvidenceTab)?`<button class="btn small primary" onclick="toggleTestEvidenceUpload()">上传</button>`:''}</div>${tabs}<div id="testEvidenceUploadWrap" class="test-evidence-upload-wrap" style="display:none">${uploadTabs.includes(testEvidenceTab)?renderTestEvidenceUpload(t,testEvidenceTab):''}</div><div class="test-evidence-body">${body}</div></div>`;
}
function toggleTestEvidenceUpload(){
  const el=$('testEvidenceUploadWrap');
  if(el)el.style.display=el.style.display==='none'?'block':'none';
}
function openTestUploadModal(testId,modelId,testType){
  if(!testId){toast('请先保存测试节点');return;}
  const t=tests.find(x=>Number(x.id)===Number(testId))||{id:testId,model_id:modelId,test_type:testType,title:testType};
  const uid='test_modal_upload_'+Math.random().toString(36).slice(2,8);
  const host=document.createElement('div');
  host.innerHTML=`<div class="modal-mask" onclick="if(event.target===this)this.remove()"><div class="modal test-upload-modal" style="max-width:760px"><div class="modal-head"><div><h3>上传测试资料</h3><div class="hint">当前上传到：${esc(t.title||testType||'测试项目')}。附件绑定当前 test_id。</div></div><button class="btn" onclick="this.closest('.modal-mask').remove()">关闭</button></div><div class="modal-body">${renderTestEvidenceUpload(t,'files').replace(/ev_${Number(t.id)}_files/g,uid)}</div></div></div>`;
  document.body.appendChild(host.firstElementChild);
}
function scrollToTestFiles(){
  const el=document.getElementById('testNodeFileSection');
  if(el){el.scrollIntoView({behavior:'smooth',block:'center'});el.style.boxShadow='0 0 0 3px rgba(37,99,235,.18)';setTimeout(()=>el.style.boxShadow='',1200)}
}
function renderTestComponentsSection(t,custom,modelId){
  const snap=currentComponentSnapshot(modelId);
  const vals={
    power:(custom._test_power!==undefined?custom._test_power:(t?'' : snap.power)),
    chip:(custom._test_chip!==undefined?custom._test_chip:(t?'' : snap.chip)),
    optical:(custom._test_optical!==undefined?custom._test_optical:(t?'' : snap.optical)),
    other:(custom._test_custom_component!==undefined?custom._test_custom_component:'')
  };
  return `<div class="test-form-section"><div class="test-section-headline"><h4>关键元器件</h4><button class="btn small" onclick="syncTestComponentsFromSample()">从样品同步</button></div><div class="test-component-grid"><div class="field"><label>电源</label><input id="t_comp_power" data-test-custom-key="_test_power" value="${esc(vals.power||'')}" placeholder="电源品牌 / 型号 / 规格" title="${esc(vals.power||'')}"></div><div class="field"><label>芯片</label><input id="t_comp_chip" data-test-custom-key="_test_chip" value="${esc(vals.chip||'')}" placeholder="LED芯片品牌 / 型号 / 规格" title="${esc(vals.chip||'')}"></div><div class="field"><label>光学</label><input id="t_comp_optical" data-test-custom-key="_test_optical" value="${esc(vals.optical||'')}" placeholder="透镜 / 反光杯 / 光学件" title="${esc(vals.optical||'')}"></div><div class="field"><label>自定义</label><input id="t_comp_custom" data-test-custom-key="_test_custom_component" value="${esc(vals.other||'')}" placeholder="填写其他关键件或测试变量" title="${esc(vals.other||'')}"></div></div></div>`;
}
function syncTestComponentsFromSample(){
  const mid=Number($('t_model_id')?.value||testModelId||0);
  const snap=currentComponentSnapshot(mid);
  const ids=['t_comp_power','t_comp_chip','t_comp_optical'];
  const has=ids.some(id=>String($(id)?.value||'').trim());
  if(has&&!confirm('当前测试已有关键元器件内容，是否用当前样品资料覆盖电源、芯片和光学？'))return;
  if($('t_comp_power'))$('t_comp_power').value=snap.power||'';
  if($('t_comp_chip'))$('t_comp_chip').value=snap.chip||'';
  if($('t_comp_optical'))$('t_comp_optical').value=snap.optical||'';
}

function closeTestActionMenus(skip=null){
  document.querySelectorAll('.test-action-menu[open]').forEach(el=>{if(el!==skip)el.removeAttribute('open')});
}
function handleTestMoreToggle(el){
  if(el.open)closeTestActionMenus(el);
}
function focusTestEvidence(tab='images'){
  setTestEvidenceTab(tab);
  setTimeout(()=>scrollToTestFiles(),0);
}
function testActionItem(label,action,icon='',tone=''){
  return `<button type="button" class="btn small test-menu-item ${tone}" onclick="closeTestActionMenus();${action}"><span class="menu-icon">${esc(icon||'•')}</span><span>${esc(label)}</span></button>`;
}
function testJsArg(v){return esc(JSON.stringify(String(v??'')));}
function testActionGroup(title,items,cls=''){
  if(!items.length)return '';
  return `<div class="test-action-group ${cls}"><h5>${esc(title)}</h5>${items.join('')}</div>`;
}
function testCanCreateRetestByState(t){
  if(!t||!Number(t.id||0))return false;
  const status=testStatusValue(t), result=testResultValue(t);
  return status==='待复测'||result==='不通过';
}
async function saveTestAndOpenUpload(pid){
  const d=collectTestFormData(pid);
  const r=await api('save_test',d);
  if(!r.ok){toast(r.error||'测试保存失败，未上传资料');return}
  testCreateMode=false;
  localStorage.setItem('plm_v85_test_create_mode','0');
  const id=Number(r.id||d.id||0);
  testSelectedId=id;
  localStorage.setItem('plm_v85_test_id',id);
  await load();
  const t=tests.find(x=>Number(x.id)===id);
  if(t)openTestUploadModal(id,Number(t.model_id||0),t.test_type||'测试');
}
function renderTestMoreMenu(p,t){
  const saved=!!(t&&Number(t.id||0));
  const status=saved?testStatusValue(t):'未开始';
  const result=saved?testResultValue(t):'待判定';
  const testOps=[];
  if(saved&&status==='未开始')testOps.push(testActionItem('开始测试',"markTestStatus('进行中')",'▶',''));
  if(saved&&status==='进行中')testOps.push(testActionItem('完成测试',"markTestStatus('已完成')",'✓','good'));
  if(saved&&status==='已完成'&&(!result||result==='待判定')){
    testOps.push(testActionItem('判定通过',"markTestResult('通过')",'✓','good'));
    testOps.push(testActionItem('判定不通过',"markTestResult('不通过')",'!','warn'));
  }
  if(testCanCreateRetestByState(t))testOps.push(testActionItem('创建复测',`createRetestFromCurrent(${Number(p.id)})`,'↻','warn'));
  const related=saved?[
    testActionItem('进入问题闭环',"gotoTab('issues')",'?',''),
    testActionItem('文件中心',"gotoTab('files')",'▣','')
  ]:[`<div class="test-menu-note">保存测试后可进入问题闭环和文件中心定位当前测试。</div>`];
  const evidence=saved?[
    testActionItem('上传附件',`openTestUploadModal(${Number(t.id)},${Number(t.model_id||0)},${testJsArg(t.test_type||'测试')})`,'↑',''),
    testActionItem('查看当前测试资料',"focusTestEvidence('images')",'◎','')
  ]:[
    testActionItem('保存并上传附件',`saveTestAndOpenUpload(${Number(p.id)})`,'↑','')
  ];
  const tools=[
    testActionItem('测试模板',"openTestTemplateDrawer()",'⚙',''),
    testActionItem('导出 CSV',"exportCurrentProjectTestReport()",'⇩',''),
    testActionItem('打印/报表',saved?`openSingleTestReport(${Number(t.id)})`:'window.print()','⎙','')
  ];
  const danger=saved?[testActionItem('删除测试',`deleteTest(${Number(t.id)})`,'×','danger')]:[];
  const body=[
    testActionGroup('测试操作',testOps.length?testOps:[`<div class="test-menu-note">当前状态暂无可执行的状态操作。</div>`]),
    testActionGroup('关联处理',related),
    testActionGroup('资料管理',evidence),
    testActionGroup('工具',tools),
    testActionGroup('危险操作',danger,'danger')
  ].join('');
  return `<details class="test-more-menu test-action-menu" ontoggle="handleTestMoreToggle(this)"><summary>更多 ▾</summary><div>${body}</div></details>`;
}
if(!window.__plmTestActionMenuBound){
  window.__plmTestActionMenuBound=true;
  document.addEventListener('click',e=>{if(!e.target.closest('.test-action-menu'))closeTestActionMenus()});
  document.addEventListener('keydown',e=>{if(e.key==='Escape')closeTestActionMenus()});
  window.addEventListener('scroll',()=>closeTestActionMenus(),true);
}

function renderTestDetailForm(p,t,ms){
  const isNew=!t;const tpl=isNew?(templateForType(activeTestType)||TEST_TEMPLATE_DEFAULTS[0]):templateForTest(t);const custom=testCustomValues(t);
  const type=isNew?(tpl.test_type||activeTestType):(t.test_type||tpl.test_type||activeTestType);
  const title=t?.title||type+'测试';
  const preserveHidden=[
    testTplHasBind(tpl,'test_standard')?'':hiddenTestTextarea('t_standard',t?.test_standard||''),
    testTplHasBind(tpl,'test_data')?'':hiddenTestTextarea('t_data',t?.test_data||''),
    testTplHasBind(tpl,'test_conclusion')?'':hiddenTestTextarea('t_conclusion',t?.test_conclusion||'')
  ].join('');
  if(!isNew&&!t)return `<div class="test-detail-empty"><b>请选择测试项目</b><span>从看板选择一个测试项目，或添加新的测试项目。</span><button class="btn primary" onclick="openAddTestProjectPanel()">添加测试项目</button></div>`;
  const sampleName=t?testSampleName(t,ms):(ms.find(m=>Number(m.id)===Number(testModelId))?testModelLabel(ms.find(m=>Number(m.id)===Number(testModelId))):'项目公共测试');
  const fallbackResult=!testTplHasBind(tpl,'test_conclusion')?`<div class="field wide"><label>测试结论 / 整改建议</label><textarea id="t_conclusion" placeholder="记录测试结论、整改建议或客户确认要求">${esc(t?.test_conclusion||'')}</textarea></div>`:'';
  const retestField=(t&&(Number(t.source_test_id||0)>0||Number(t.retest_no||0)>0||String(t.retest_result||'').trim()))?`<div class="field small-field"><label>复测结果</label><input id="t_retest" value="${esc(t?.retest_result||'')}" placeholder="复测结果"></div>`:`<input id="t_retest" type="hidden" value="${esc(t?.retest_result||'')}">`;
  const titleCustom=String(title||'')!==String(tpl.name||type||'')||normalizeTestTypeName(type)==='自定义测试';
  const titleRow=`<div class="test-title-inline ${titleCustom?'':'collapsed'}"><div class="field"><label>自定义标题</label><input id="t_custom_title" value="${esc(title)}" placeholder="自定义测试标题" oninput="$('t_title').value=this.value"></div><button class="btn small" onclick="toggleCustomTestTitle()">收起</button></div>`;
  return `<div class="test-detail-head"><div><h3>${esc(testProjectLabel(t||{title:tpl.name,test_type:type},tpl))}</h3><div class="hint">${esc(sampleName)} ｜ ${esc(testStatusValue(t||{status:'未开始'}))} ｜ ${esc(testResultValue(t||{result:'待判定'}))}</div></div><div class="actions"><button class="btn primary" onclick="saveNewTest(${p.id})">保存测试</button><button class="btn" onclick="testCreateMode=false;localStorage.setItem('plm_v85_test_create_mode','0');renderDetail()">取消</button>${renderTestMoreMenu(p,t)}</div></div>
  <div class="test-detail-form"><input id="t_id" type="hidden" value="${t?.id||0}"><input id="t_source_test_id" type="hidden" value="${Number(t?.source_test_id||0)}"><input id="t_retest_no" type="hidden" value="${Number(t?.retest_no||0)}">${preserveHidden}
    <div class="test-detail-main-grid"><div class="test-data-column">
      <div class="test-form-section"><h4>基础信息</h4><div class="test-compact-grid test-basic-grid"><div class="field project-field"><label>测试项目</label>${renderTestProjectSelect(t||{test_type:type,title},tpl)}</div><div class="field small-field"><label>日期</label><input id="t_date" type="date" value="${esc(dateOnly(t?.test_date)||new Date().toISOString().slice(0,10))}"></div><div class="field medium-field"><label>测试人</label><input id="t_operator" value="${esc(t?.operator||'')}" placeholder="测试人"></div><div class="field small-field"><label>测试状态</label><select id="t_status">${opt(['未开始','进行中','已完成','待复测','已取消'],testStatusValue(t||{status:'未开始'}))}</select></div><div class="field small-field"><label>测试结果</label><select id="t_result">${opt(['待判定','通过','不通过'],testResultValue(t||{result:'待判定'}))}</select></div><div class="field medium-field"><label>影响样品</label><select id="t_affect"><option value="0" ${Number(t?.affect_sample||0)?'':'selected'}>不影响</option><option value="1" ${Number(t?.affect_sample||0)?'selected':''}>影响通过</option></select></div><div class="field medium-field"><label>归属样品</label><select id="t_model_id"><option value="0">项目公共测试</option>${ms.map(m=>`<option value="${m.id}" ${Number((t?.model_id??testModelId)||0)===Number(m.id)?'selected':''}>${esc(testModelLabel(m))}</option>`).join('')}</select></div><button class="btn small" onclick="toggleCustomTestTitle()">自定义标题</button>${titleRow}${retestField}</div></div>
      ${renderTestComponentsSection(t,custom,Number(t?.model_id??testModelId)||0)}
      <div class="test-form-section"><h4>${esc(tpl.name||'测试参数')}</h4><div class="test-template-fields">${(tpl.fields||[]).map(f=>renderTestTemplateField(f,t,custom)).join('')||'<div class="hint">这个模板暂无字段，可通过顶部“测试模板”维护。</div>'}</div></div>
      <div class="test-form-section"><h4>备注 / 整改</h4><div class="test-result-grid">${fallbackResult}<div class="field wide"><label>备注 / 整改建议</label><textarea id="t_note" placeholder="补充异常说明、整改建议或备注">${esc(t?.note||'')}</textarea></div></div></div>
    </div><aside class="test-evidence-column">${t?renderTestEvidencePanel(t):'<div class="test-unsaved-upload"><span>请先保存测试，再上传资料。</span><button class="btn small primary" onclick="saveNewTest('+p.id+')">保存并继续上传</button></div>'}</aside></div>
  </div>`
}

function testReportText(t){
  return [t.test_data,t.test_conclusion,t.note,t.retest_result].map(x=>String(x||'').trim()).filter(Boolean).join('\n');
}
function testReportFileLinks(list){
  if(!list||!list.length)return '<div class="hint">暂无附件</div>';
  return '<div class="test-report-files">'+list.map(f=>`<a href="${esc(f.file_path||'')}" target="_blank">${esc(f.title||f.original_name||f.file_name||'附件')}</a>`).join('')+'</div>';
}
function openSingleTestReport(testId){
  const p=cur(); if(!p){toast('请先选择项目');return;}
  const t=tests.find(x=>Number(x.id)===Number(testId)); if(!t){toast('测试不存在');return;}
  const m=models.find(x=>Number(x.id)===Number(t.model_id))||{};
  const runs=testRunsFor(t);
  const nodeFiles=(files||[]).filter(f=>Number(f.test_id)===Number(t.id)&&Number(f.test_run_id||0)===0);
  const statusCls=testStatusClass(t.status,t.result);
  const hs=testHistoryStats(t,tests);
  const runHtml=(runs.length?runs:[{id:0,run_no:1,status:t.status,result:t.result,test_date:t.test_date,operator:t.operator,test_data:t.test_data,test_conclusion:t.test_conclusion,note:t.note,affect_sample:t.affect_sample,_virtual:true}]).map(r=>{
    const bad=/不通过|失败|异常|需整改|NG/i.test(testRunText(r));
    const rfs=r._virtual?[]:runFilesFor(r.id,t.id);
    const txt=[r.test_data,r.test_conclusion,r.note].map(x=>String(x||'').trim()).filter(Boolean).join('\n')||'暂无关键记录';
    return `<div class="test-report-run ${bad?'bad':''}"><b>第 ${esc(r.run_no||1)} 次测试 · ${esc(r.result||r.status||'待测')}</b><div class="hint">日期：${esc(dateOnly(r.test_date)||'-')} ｜ 测试人：${esc(r.operator||'-')} ｜ ${Number(r.affect_sample||0)?'影响样品':'不影响样品'}</div><div class="test-report-textbox">${esc(txt)}</div><h3>本次附件</h3>${testReportFileLinks(rfs)}</div>`;
  }).join('');
  const custom=testCustomValues(t);
  const tpl=templateForTest(t);
  const tplRows=(tpl.fields||[]).map(f=>{const key=f.bind||f.key||'';const val=((custom[f.key]!==undefined&&custom[f.key]!==null)?custom[f.key]:((key&&t[key]!==undefined&&t[key]!==null)?t[key]:(f.default||'')));return `<div><b>${esc(f.label||f.key||'字段')}</b>${esc(String(val||'-'))}</div>`}).join('');
  const html=`<div class="modal-mask" onclick="if(event.target===this)closeSingleTestReport(this)"><div class="modal test-single-report-modal"><div class="modal-head"><div><h3>测试报告</h3><div class="hint">单项测试打印/查看，不影响原测试数据。</div></div><div class="actions"><button class="btn small primary" onclick="printSingleTestReport()">打印</button><button class="btn small" onclick="closeSingleTestReport(this)">关闭</button></div></div><div class="modal-body"><div class="test-single-report"><h2>${esc(t.test_type||'测试')} · ${esc(t.title||'未命名')}</h2><div class="tags"><span class="test-node-status ${statusCls}">${esc(t.status||'待测')}</span><span class="mini-tag blue">记录 ${hs.runs||runs.length||1}</span>${hs.fail?`<span class="mini-tag red">不通过 ${hs.fail}</span>`:''}${hs.retest?`<span class="mini-tag orange">重测 ${hs.retest}</span>`:''}</div><div class="test-report-info-grid"><div><b>项目</b>${esc(p.name||'-')}</div><div><b>样品</b>${esc(m.name||m.model||'项目公共')}</div><div><b>型号</b>${esc(m.model||m.sample_no||'-')}</div><div><b>测试日期</b>${esc(dateOnly(t.test_date)||'-')}</div><div><b>测试人</b>${esc(t.operator||'-')}</div><div><b>结论</b>${esc(t.result||t.test_conclusion||'-')}</div></div><h3>模板字段</h3><div class="test-report-info-grid">${tplRows||'<div><b>模板字段</b>暂无</div>'}</div><h3>关键记录 / 结论</h3><div class="test-report-textbox">${esc(testReportText(t)||'暂无关键记录')}</div><h3>测试节点附件</h3>${testReportFileLinks(nodeFiles)}<h3>重测历史</h3>${runHtml}</div></div></div></div>`;
  const host=document.createElement('div'); host.innerHTML=html; document.body.appendChild(host.firstElementChild);
}
function closeSingleTestReport(el){
  const mask=el?.classList?.contains('modal-mask')?el:el?.closest?.('.modal-mask');
  document.body.classList.remove('print-single-test');
  if(mask)mask.remove();
}
function printSingleTestReport(){
  document.body.classList.add('print-single-test');
  window.print();
  setTimeout(()=>document.body.classList.remove('print-single-test'),500);
}

function runStatusClass(r){return testStatusClass(r.status,r.result)}
function runFilesFor(runId,testId){return (files||[]).filter(f=>Number(f.test_id)===Number(testId)&&Number(f.test_run_id||0)===Number(runId||0))}
function renderTestRunHistory(t){
  const runs=testRunsFor(t);
  const rows=runs.length?runs:[{id:0,test_id:t.id,run_no:1,status:t.status,result:t.result,test_date:t.test_date,operator:t.operator,test_data:t.test_data,test_conclusion:t.test_conclusion,note:t.note,affect_sample:t.affect_sample,created_at:t.created_at,_virtual:true}];
  const cards=rows.slice().reverse().map(r=>{
    const failed=/不通过|失败|异常|需整改|NG/i.test(testRunText(r));
    const status=r.result||r.status||'待测';
    const data=[r.test_data,r.test_conclusion,r.note].map(x=>String(x||'').trim()).filter(Boolean).join(' ｜ ');
    const rfs=r._virtual?[]:runFilesFor(r.id,t.id);
    const filesHtml=rfs.map(f=>fileChip(f,'run-file')).join('')||'<div class="hint">本次暂无附件</div>';
    const uploadHtml=r._virtual?'':`<details class="test-run-upload"><summary>上传本次测试附件</summary>${uploadBox(testTypeDefaultFileCat(t.test_type),t.model_id||0,t.id,true,0,r.id)}</details>`;
    return `<div class="test-run-card ${failed?'bad':''}"><div class="test-run-head"><b>第 ${esc(r.run_no||1)} 次测试</b><span class="test-node-status ${runStatusClass(r)}">${esc(status)}</span></div><div class="test-run-meta">日期：${esc(dateOnly(r.test_date)||'-')} ｜ 测试人：${esc(r.operator||'-')} ｜ ${Number(r.affect_sample||0)?'影响样品':'不影响样品'} ｜ 附件 ${rfs.length}</div><div class="test-run-note">${esc(data||'暂无关键记录')}</div><div class="test-run-files"><div class="test-run-files-head"><span>本次测试附件</span>${rfs.length?`<span class="tag blue">${rfs.length} 个</span>`:''}</div><div class="test-run-files-list">${filesHtml}</div>${uploadHtml}</div>${r._virtual?'<div class="hint">旧记录尚未写入历史表，保存后系统会自动补一条初始记录。</div>':`<div class="test-run-actions">${failed?`<button class="btn small warn" onclick="createIssueFromCurrentTest(${Number(t.id)},${Number(r.id)})">生成问题</button>`:''}<button class="btn small danger" onclick="deleteTestRun(${r.id})">删除本次</button></div>`}</div>`
  }).join('');
  const totalFiles=(files||[]).filter(f=>Number(f.test_id)===Number(t.id)).length;
  return `<div class="test-form-section test-run-section"><div class="test-run-title"><h4>测试历史 / 重测记录</h4><div class="actions"><span class="tag blue">附件 ${totalFiles}</span><button class="btn small" onclick="prepareNewTestRun()">新增一次重测</button><button class="btn small good" onclick="saveAsTestRun(${Number(t.project_id||cur()?.id||0)})">保存为重测记录</button></div></div><div class="hint">每次重测可单独上传附件。比如第一次不通过的照片、第二次复测报告，会分别归到对应记录下面；文件中心仍能统一查看。</div><div class="test-run-list">${cards}</div></div>`;
}
function prepareNewTestRun(){
  if($('t_status')) $('t_status').value='待复测';
  if($('t_result')) $('t_result').value='';
  if($('t_retest')) $('t_retest').value='';
  if($('t_date')) $('t_date').value=new Date().toISOString().slice(0,10);
  toast('已切到新增重测状态，填写数据后点“保存为重测记录”。');
}
async function deleteTestRun(runId){
  if(!confirm('删除这一条重测历史记录？不会删除测试节点。'))return;
  const r=await api('delete_test_run',{run_id:runId});toast(r.ok?'重测记录已删除':r.error);await load();
}

function splitTemplateOptions(opt){
  if(Array.isArray(opt)) return opt.map(x=>String(x||'').trim()).filter(Boolean);
  return String(opt||'').split(/[\n,，、|\/]+/).map(x=>x.trim()).filter(Boolean);
}
function bindFieldIdMap(){return {ambient_temp:'t_ambient',led_temp:'t_led',driver_temp:'t_driver',shell_temp:'t_shell',max_temp:'t_max',sphere_lumen:'t_lumen',sphere_power:'t_power',sphere_efficiency:'t_eff',cct:'t_cct',cri:'t_cri',ies_angle:'t_angle',ies_lumen:'t_ies_lumen',test_standard:'t_standard',test_data:'t_data',test_conclusion:'t_conclusion'}}
function renderTestTemplateField(f,t,custom){
  f=f||{};
  const bind=f.bind||'';
  const key=f.key||bind||('field_'+Math.random().toString(36).slice(2,6));
  const label=f.label||key;
  const type=f.type||'text';
  const bindIds=bindFieldIdMap();
  const values={ambient_temp:t?.ambient_temp,led_temp:t?.led_temp,driver_temp:t?.driver_temp,shell_temp:t?.shell_temp,max_temp:t?.max_temp,sphere_lumen:t?.sphere_lumen,sphere_power:t?.sphere_power,sphere_efficiency:t?.sphere_efficiency,cct:t?.cct,cri:t?.cri,ies_angle:t?.ies_angle,ies_lumen:t?.ies_lumen,test_standard:t?.test_standard,test_data:t?.test_data,test_conclusion:t?.test_conclusion};
  const id=bindIds[bind]||('tc_'+String(key).replace(/[^a-zA-Z0-9_]/g,'_'));
  let val=bind ? (values[bind]??'') : (custom[key]??'');
  if((val===undefined||val===null||String(val)==='') && f.default!==undefined) val=f.default;
  const req=f.required?' required':'';
  const data=bind?'':` data-test-custom-key="${esc(key)}"`;
  const ph=f.placeholder||'';
  const labelText=String(label||'');
  const compactBinds=['ambient_temp','led_temp','driver_temp','shell_temp','max_temp','sphere_lumen','sphere_power','sphere_efficiency','cct','cri','ies_angle','ies_lumen'];
  const isCompact=type==='number'||type==='date'||compactBinds.includes(bind)||/(环境温度|LED温度|电源温度|驱动温度|壳体温度|外壳温度|最高温度|测试时长|老化时长|测试数量|失效数量|功率|色温|光束角|峰值|光强|光通量|光效|功率因数|PF|CRI|R9|SDCM|角度|温度|时长)/i.test(labelText);
  const isMedium=!isCompact&&(bind==='test_standard'||/(判定标准|测试标准|测试机构|测试设备|配光类型|防护等级|目标等级|报告编号|测试项目)/.test(labelText));
  const isWide=!isMedium&&!isCompact&&(type==='textarea'||type==='file'||bind==='test_data'||bind==='test_conclusion'||/(测试条件|测试结论|异常说明|整改建议|备注|装配异常|测试图片|检查图片|配光报告|光谱报告|EMC报告)/.test(labelText));
  const cls=isWide?' wide':(isMedium?' medium':(isCompact?' compact':''));
  if(type==='textarea'||bind==='test_standard'||bind==='test_data'||bind==='test_conclusion')return `<div class="test-template-field${cls}"><label>${esc(label)}${f.required?' *':''}</label><textarea id="${esc(id)}" placeholder="${esc(ph)}"${data}${req}>${esc(val||'')}</textarea></div>`;
  if(type==='date')return `<div class="test-template-field${cls}"><label>${esc(label)}${f.required?' *':''}</label><input id="${esc(id)}" type="date" value="${esc(dateOnly(val)||'')}" placeholder="${esc(ph)}"${data}${req}></div>`;
  if(type==='number')return `<div class="test-template-field${cls}"><label>${esc(label)}${f.required?' *':''}</label><input id="${esc(id)}" type="number" step="0.01" inputmode="decimal" value="${esc(val??'')}" placeholder="${esc(ph)}"${data}${req}></div>`;
  if(type==='select'){
    const opts=splitTemplateOptions(f.options||'通过\n不通过\n待确认');
    return `<div class="test-template-field${cls}"><label>${esc(label)}${f.required?' *':''}</label><select id="${esc(id)}"${data}${req}><option value="">请选择</option>${opts.map(o=>`<option value="${esc(o)}" ${String(val)===String(o)?'selected':''}>${esc(o)}</option>`).join('')}</select></div>`;
  }
  if(type==='yesno')return `<div class="test-template-field${cls||' compact'}"><label>${esc(label)}${f.required?' *':''}</label><select id="${esc(id)}"${data}${req}><option value="">请选择</option><option value="是" ${String(val)==='是'?'selected':''}>是</option><option value="否" ${String(val)==='否'?'selected':''}>否</option></select></div>`;
  if(type==='file'){const fileTab=/IES|LDT|原始|数据/i.test(labelText)?'raw':'reports';return `<div class="test-template-field medium test-template-file-hint"><label>${esc(label)}${f.required?' *':''}</label><input id="${esc(id)}" type="hidden" value="${esc(val??'')}"${data}${req}><div class="hint">在右侧附件资料上传和预览。</div><button class="btn small" onclick="setTestEvidenceTab('${fileTab}')">查看资料</button></div>`;}
  return `<div class="test-template-field${cls}"><label>${esc(label)}${f.required?' *':''}</label><input id="${esc(id)}" value="${esc(val??'')}" placeholder="${esc(ph)}"${data}${req}></div>`;
}
function testTemplateBindOptions(selected=''){
  const list=[['','不绑定/自定义字段'],['ambient_temp','环境温度'],['led_temp','LED温度'],['driver_temp','驱动温度'],['shell_temp','外壳温度'],['max_temp','最高温度'],['sphere_lumen','积分球光通量'],['sphere_power','积分球功率'],['sphere_efficiency','光效'],['cct','色温 CCT'],['cri','显指 CRI'],['ies_angle','IES角度'],['ies_lumen','IES光通量'],['test_standard','测试标准'],['test_data','关键测试数据'],['test_conclusion','测试结论/整改建议']];
  return list.map(([v,l])=>`<option value="${esc(v)}" ${String(v)===String(selected||'')?'selected':''}>${esc(l)}</option>`).join('');
}
function testTemplateTypeOptions(selected='text'){
  const list=[['text','文本'],['number','数字'],['date','日期'],['select','下拉'],['yesno','是否'],['textarea','多行备注'],['file','附件说明']];
  return list.map(([v,l])=>`<option value="${v}" ${String(v)===String(selected||'text')?'selected':''}>${l}</option>`).join('');
}
function fieldKeyFromLabel(label,i){
  const base=String(label||'field').trim().replace(/\s+/g,'_').replace(/[^\u4e00-\u9fa5a-zA-Z0-9_]/g,'_').slice(0,40);
  return (base||'field')+'_'+(i+1);
}
function renderTplEditorRow(f={},i=0){
  const label=f.label||'';
  const key=f.key||fieldKeyFromLabel(label,i);
  const type=f.type||'text';
  const bind=f.bind||'';
  const required=!!f.required;
  const options=f.options||'';
  const def=f.default||'';
  return `<div class="tpl-field-row" draggable="true" ondragstart="tplFieldDragStart(event)" ondragover="tplFieldDragOver(event)" ondrop="tplFieldDrop(event)"><span class="tpl-drag" title="拖动排序">☰</span><div class="tpl-field-main"><label class="tpl-mini-field"><span>字段名称</span><input class="tpl-label" value="${esc(label)}" placeholder="如：环境温度"></label><label class="tpl-mini-field"><span>类型</span><select class="tpl-type" onchange="tplFieldTypeChanged(this)">${testTemplateTypeOptions(type)}</select></label><label class="tpl-mini-field"><span>绑定字段</span><select class="tpl-bind">${testTemplateBindOptions(bind)}</select></label><label class="tpl-mini-field"><span>必填</span><span class="tpl-required-card"><input type="checkbox" ${required?'checked':''}> 必填</span></label><label class="tpl-mini-field"><span>下拉选项</span><input class="tpl-options" value="${esc(options)}" placeholder="通过,不通过"></label><label class="tpl-mini-field"><span>默认值</span><input class="tpl-default" value="${esc(def)}" placeholder="默认值"></label><label class="tpl-mini-field wide"><span>字段Key</span><input class="tpl-key" value="${esc(key)}" title="字段Key，一般不用改"></label></div><div class="tpl-field-actions"><button class="btn small" onclick="moveTplFieldRow(this,-1)">↑</button><button class="btn small" onclick="moveTplFieldRow(this,1)">↓</button><button class="btn small danger" onclick="removeTplFieldRow(this)">删</button></div></div>`;
}
function tplEditorCollapsed(){try{return localStorage.getItem('plm_test_template_editor_collapsed_v8579')==='1'}catch(e){return false}}
function setTplEditorCollapsed(v){try{localStorage.setItem('plm_test_template_editor_collapsed_v8579',v?'1':'0')}catch(e){}}
function toggleTplEditor(){const box=document.querySelector('.test-template-editor');if(!box)return;const next=!box.classList.contains('collapsed');box.classList.toggle('collapsed',next);setTplEditorCollapsed(next);const btn=box.querySelector('.tpl-toggle-btn');if(btn)btn.textContent=next?'展开':'折叠';}
function renderTestTemplateManager(tpl){
  tpl=tpl||templateForType(activeTestType)||{};
  const customs=allTestTemplates().filter(x=>!x.builtin);
  const editingId=(!tpl.builtin && tpl.id)?tpl.id:0;
  const nameVal=!tpl.builtin?(tpl.name||''):'';
  const collapsed=tplEditorCollapsed();
  return `<div class="test-form-section test-template-editor ${collapsed?'collapsed':''}"><div class="tpl-collapse-head"><div><h4>模板字段管理</h4><div class="tpl-collapse-sub">可自己决定每种测试要填哪些字段；已改成卡片网格，一排自动显示 2～3 个字段。</div></div><button class="btn small tpl-toggle-btn" onclick="toggleTplEditor()">${collapsed?'展开':'折叠'}</button></div><div class="tpl-editor-body"><input id="tpl_edit_id" type="hidden" value="${editingId}"><div class="tpl-editor-top"><input id="new_tpl_name" value="${esc(nameVal)}" placeholder="模板名称，如 温升简版"><select id="new_tpl_type">${TEST_TYPES.map(x=>`<option ${x===(tpl?.test_type||activeTestType)?'selected':''}>${esc(x)}</option>`).join('')}</select><button class="btn small" onclick="addTplFieldRow()">+ 字段</button><button class="btn small" onclick="loadActiveTemplateToEditor()">载入当前模板</button><button class="btn small primary" onclick="saveTestTemplateFromEditor()">保存模板</button></div><div class="tpl-editor-head"><span></span><span>字段名称</span><span>类型</span><span>绑定标准字段</span><span>必填</span><span>选项</span><span>默认值</span><span>Key</span><span>操作</span></div><div id="tpl_field_rows" class="tpl-field-rows">${(tpl.fields&&tpl.fields.length?tpl.fields:[{label:'测试结论',type:'textarea',bind:'test_conclusion',required:0}]).map(renderTplEditorRow).join('')}</div><div class="test-template-manage">${customs.map(x=>`<div class="test-template-chip"><div><b>${esc(x.name)}</b><div class="hint">${esc(x.test_type||'通用')} · ${x.fields.length}项</div></div><div class="actions"><button class="btn small" onclick="editCustomTestTemplate(${x.id})">编辑</button><button class="btn small danger" onclick="deleteCustomTestTemplate(${x.id})">删</button></div></div>`).join('')||'<div class="hint">暂无自定义模板</div>'}</div></div></div>`;
}
function openTestTemplateDrawer(){
  const tpl=templateForType(activeTestType)||TEST_TEMPLATE_DEFAULTS[0];
