function modelLabel(m){return (m.name||m.model||m.sample_no||('样品'+m.id))}
function flowModelLabel(m){return (m?.model||m?.naming_model_no||m?.sample_no||m?.name||('样品'+m.id))}
function fileModelLabel(m){
  const code=m?.model||m?.naming_model_no||m?.model_no||m?.product_model||m?.sample_no||'';
  const name=m?.name||'';
  const ver=m?.sample_version||'';
  return [code||name||('型号'+m.id), name&&name!==code?name:'', ver].filter(Boolean).join(' · ');
}
function modelSelectHtml(id,val=0,includeAll=false){
  const ms=pModels(cur()?.id||selectedId);
  const valStr=String(val ?? '');
  let html='';
  if(includeAll) html+=`<option value="" ${valStr===''?'selected':''}>全部产品/样品</option>`;
  html+=`<option value="0" ${(valStr!=='' && Number(val)===0)?'selected':''}>项目公共文件</option>`;
  html+=ms.map(m=>`<option value="${m.id}" ${(valStr!=='' && Number(val)===Number(m.id))?'selected':''}>${esc(modelLabel(m))}</option>`).join('');
  return `<select id="${id}">${html}</select>`
}
function fileModelSelectHtml(id,val=0,includeAll=false){
  const ms=pModels(cur()?.id||selectedId);
  const valStr=String(val ?? '');
  let html='';
  if(includeAll) html+=`<option value="" ${valStr===''?'selected':''}>全部型号</option>`;
  html+=`<option value="0" ${(valStr!=='' && Number(val)===0)?'selected':''}>项目公共文件</option>`;
  html+=ms.map(m=>`<option value="${m.id}" ${(valStr!=='' && Number(val)===Number(m.id))?'selected':''}>${esc(fileModelLabel(m))}</option>`).join('');
  return `<select id="${id}">${html}</select>`
}
function isTestFile(f){
  const cat=String(f?.category||'');
  const name=[f?.title,f?.original_name,f?.file_name,f?.note].join(' ');
  if(Number(f?.test_id)>0) return true;
  if(TEST_FILE_CATS.includes(cat)) return true;
  return /(温升|IES|积分球|EMC|IP防水|防水|老化|测试|报告|光电|光谱|配光)/i.test(cat+' '+name);
}
function stepSelectHtml(id,val=0,modelId=0,includeAllModels=false){const p=cur();const pid=p?Number(p.id):selectedId;let list=steps.filter(x=>Number(x.project_id)===Number(pid));if(!includeAllModels&&Number(modelId)>0)list=list.filter(x=>Number(x.model_id)===Number(modelId));list=list.sort((a,b)=>(Number(a.model_id)-Number(b.model_id))||(Number(a.sort_order)-Number(b.sort_order))||(Number(a.id)-Number(b.id)));let html='<option value="0">不绑定步骤</option>';html+=list.map(s=>{const m=models.find(x=>Number(x.id)===Number(s.model_id));const prefix=m?modelLabel(m)+' / ':'项目公共 / ';return `<option value="${s.id}" ${Number(val)===Number(s.id)?'selected':''}>${esc(prefix+(s.title||'步骤'))}</option>`}).join('');return `<select id="${id}">${html}</select>`}
function fileTypeLabel(f){return isTestFile(f)?'测试中心':'文件中心'}
function absUrl(path){try{return new URL(path, location.href).href}catch(e){return path}}
function uploadBox(defaultCat,modelId=0,testId=0,isTest=false,stepId=0,testRunId=0){const uid='u_'+Math.random().toString(36).slice(2,9);const cats=isTest?TEST_FILE_CATS:FILE_CATS;return `<div class="grid2" style="margin-top:8px"><select id="${uid}_cat">${cats.map(c=>`<option ${c===defaultCat?'selected':''}>${esc(c)}</option>`).join('')}</select><input id="${uid}_title" placeholder="标题，可不填"></div><input id="${uid}_file" type="file" style="margin-top:8px"><textarea id="${uid}_note" placeholder="备注" style="margin-top:8px"></textarea><label class="hint"><input id="${uid}_vis" type="checkbox" checked style="width:auto"> 可发客户</label><br><button class="btn small primary" onclick="uploadFile('${uid}',${modelId},${testId},${stepId},${testRunId})">上传</button>`}
function uploadProjectFileBox(defaultCat='产品图片'){const uid='u_'+Math.random().toString(36).slice(2,9);return `<div class="grid2" style="margin-top:8px"><select id="${uid}_cat">${FILE_CATS.map(c=>`<option ${c===defaultCat?'selected':''}>${esc(c)}</option>`).join('')}</select><input id="${uid}_title" placeholder="标题，可不填"></div><div class="field"><label>归属型号</label>${fileModelSelectHtml(uid+'_model',0,false)}</div><div class="field"><label>关联开发步骤</label>${stepSelectHtml(uid+'_step',0,0,true)}</div><input id="${uid}_file" type="file" style="margin-top:8px"><textarea id="${uid}_note" placeholder="备注" style="margin-top:8px"></textarea><label class="hint"><input id="${uid}_vis" type="checkbox" checked style="width:auto"> 可发客户</label><br><button class="btn small primary" onclick="uploadFileFromBox('${uid}',0,0,0)">上传</button>`}
async function uploadFile(uid,modelId,testId,stepId=0,testRunId=0,issueId=0,sourceModule=''){const p=cur();if(!p)return;const f=$(uid+'_file').files[0];if(!f){toast('请选择文件');return}const sizeError=plmImageUploadError(f);if(sizeError){toast(sizeError);return}const fd=new FormData();fd.append('project_id',p.id);fd.append('model_id',modelId||0);fd.append('test_id',testId||0);fd.append('test_run_id',testRunId||0);fd.append('step_id',stepId||0);fd.append('issue_id',issueId||0);fd.append('source_module',sourceModule||'');fd.append('category',$(uid+'_cat').value);fd.append('title',$(uid+'_title').value);fd.append('note',$(uid+'_note').value);fd.append('customer_visible',$(uid+'_vis').checked?1:0);fd.append('file',f);const r=await uploadApi(fd);toast(r.ok?'文件已上传':r.error);await load()}
async function uploadFileFromBox(uid,testId=0,stepId=0,testRunId=0){const mid=Number($(uid+'_model')?.value||0);const sid=Number($(uid+'_step')?.value||stepId||0);return uploadFile(uid,mid,testId,sid,testRunId)}
function openFileUploadDrawer(ctx={}){
  const p=cur();if(!p)return;
  const uid='fu_'+Math.random().toString(36).slice(2,8);
  const mid=Number(ctx.model_id||0), stepId=Number(ctx.step_id||0), testId=Number(ctx.test_id||0), issueId=Number(ctx.issue_id||0);
  const source=ctx.source_module||(testId?'test':(issueId?'issue':(stepId?'flow':(mid?'model':'file'))));
  const host=document.createElement('div');
  host.innerHTML=`<div class="modal-mask file-upload-mask" onclick="if(event.target===this)this.remove()"><div class="modal file-upload-drawer"><div class="modal-head"><div><h3>上传文件</h3><div class="hint">当前项目：${esc(p.name||'未命名项目')}。支持一次选择多个文件。</div></div><button class="btn" onclick="this.closest('.modal-mask').remove()">关闭</button></div><div class="modal-body"><div class="file-upload-form"><section><h4>上传目标</h4><div class="grid2"><div class="field"><label>归属型号</label>${fileModelSelectHtml(uid+'_model',mid,false)}</div><div class="field"><label>来源模块</label><select id="${uid}_source"><option value="file" ${source==='file'?'selected':''}>文件中心上传</option><option value="project" ${source==='project'?'selected':''}>项目基础资料</option><option value="model" ${source==='model'?'selected':''}>样品管理</option><option value="flow" ${source==='flow'?'selected':''}>开发导航图</option><option value="test" ${source==='test'?'selected':''}>测试中心</option><option value="issue" ${source==='issue'?'selected':''}>问题闭环</option></select></div></div><div class="field"><label>关联开发步骤</label>${stepSelectHtml(uid+'_step',stepId,mid,true)}</div><div class="field"><label>关联测试项目</label>${testSelectHtml(uid+'_test',testId,mid,true)}</div><div class="field"><label>关联问题</label>${issueSelectHtml(uid+'_issue',issueId,mid,true)}</div></section><section><h4>文件资料</h4><div class="grid2"><div class="field"><label>文件分类</label><select id="${uid}_cat">${uniq([...FILE_CATS,...TEST_FILE_CATS]).map(c=>`<option>${esc(c)}</option>`).join('')}</select></div><div class="field"><label>文件标题</label><input id="${uid}_title" placeholder="可不填，默认用文件名"></div></div><input id="${uid}_file" type="file" multiple><textarea id="${uid}_note" placeholder="文件备注"></textarea></section><section><h4>权限</h4><label class="hint"><input id="${uid}_vis" type="checkbox" checked style="width:auto"> 可发客户</label><div class="hint">取消勾选即内部资料，不能进入客户资料包。</div></section><div id="${uid}_result" class="upload-result"></div></div></div><div class="modal-foot"><button class="btn" onclick="this.closest('.modal-mask').remove()">取消</button><button class="btn primary" onclick="uploadFilesFromDrawer('${uid}')">开始上传</button></div></div></div>`;
  document.body.appendChild(host.firstElementChild);
}
async function uploadFilesFromDrawer(uid){
  const p=cur();if(!p)return;
  const input=$(uid+'_file'), list=[...(input?.files||[])], box=$(uid+'_result');
  if(!list.length){toast('请选择文件');return}
  const sizeErrors=list.map(plmImageUploadError).filter(Boolean);
  if(sizeErrors.length){toast(sizeErrors[0]);if(box)box.innerHTML=sizeErrors.map(x=>`<div>${esc(x)}：未上传</div>`).join('');return}
  const duplicates=list.filter(file=>pFiles(p.id).some(f=>String(f.original_name||'')===String(file.name)&&Number(f.file_size||0)===Number(file.size||0)));
  if(duplicates.length&&!confirm(`当前项目已存在 ${duplicates.length} 个同名同大小文件。继续保留两份？`))return;
  if(box)box.innerHTML='';
  let ok=0, fail=0;
  for(const file of list){
    const fd=new FormData();
    fd.append('project_id',p.id);fd.append('model_id',Number($(uid+'_model')?.value||0));fd.append('step_id',Number($(uid+'_step')?.value||0));fd.append('test_id',Number($(uid+'_test')?.value||0));fd.append('issue_id',Number($(uid+'_issue')?.value||0));fd.append('source_module',$(uid+'_source')?.value||'file');fd.append('category',$(uid+'_cat')?.value||'其它');fd.append('title',$(uid+'_title')?.value||'');fd.append('note',$(uid+'_note')?.value||'');fd.append('customer_visible',$(uid+'_vis')?.checked?1:0);fd.append('file',file);
    if(box)box.insertAdjacentHTML('beforeend',`<div>${esc(file.name)}：上传中...</div>`);
    const r=await uploadApi(fd);
    if(r.ok){ok++;if(box)box.lastElementChild.textContent=file.name+'：完成'}else{fail++;if(box)box.lastElementChild.textContent=file.name+'：失败 - '+(r.error||'未知错误')}
  }
  toast(`上传完成：成功 ${ok}，失败 ${fail}`);
  await load();
}
function fileChip(f,extraClass=''){return `<span class="file-chip ${esc(extraClass)}"><a href="${esc(f.file_path)}" target="_blank">${esc(f.title||f.original_name||f.file_name)}</a><button class="btn small" onclick="openTestFilePreview(${Number(f.id)})">预览</button><button class="btn small danger" onclick="deleteFile(${f.id})">×</button></span>`}
function openTestFilePreview(id){const f=files.find(x=>Number(x.id)===Number(id));if(!f){toast('文件不存在');return}const name=esc(f.title||f.original_name||f.file_name||'文件预览');const host=document.createElement('div');host.innerHTML=`<div class="modal-mask" onclick="if(event.target===this)this.remove()"><div class="modal test-file-preview-modal"><div class="modal-head"><div><h3>${name}</h3><div class="hint">弹窗预览，不占用测试详情页面空间。</div></div><div class="actions"><a class="btn small" href="${esc(f.file_path)}" target="_blank">新窗口打开</a><button class="btn small" onclick="this.closest('.modal-mask').remove()">关闭</button></div></div><div class="modal-body">${filePreviewLarge(f)}</div></div></div>`;document.body.appendChild(host.firstElementChild)}
function testCompletionMissing(d){
  const tpl=templateByKey(d.template_key)||templateForType(d.test_type||activeTestType);
  const miss=[];
  (tpl.fields||[]).forEach(f=>{
    if(!Number(f.required||0))return;
    const key=f.bind||f.key||'';
    let val='';
    if(f.bind&&d[f.bind]!==undefined)val=d[f.bind];
    else if(d.template_fields_json&&d.template_fields_json[f.key]!==undefined)val=d.template_fields_json[f.key];
    if(String(val??'').trim()==='')miss.push(f.label||f.key||'必填字段');
  });
  if(!d.result||d.result==='待判定')miss.push('测试结果未判定');
  const t=tests.find(x=>Number(x.id)===Number(d.id));
  const b=t?testFileBuckets(t):{images:[],reports:[],raw:[]};
  const type=String(d.test_type||'');
  if(/IES|配光/i.test(type)){
    if(!b.raw.some(f=>/\.(ies|ldt)$/i.test(String(f.original_name||f.file_name||''))))miss.push('IES/LDT 原始文件');
    if(!b.reports.length)miss.push('配光报告');
  }
  if(/积分球|EMC|防水|IP/i.test(type)&&!b.reports.length)miss.push('测试报告');
  if(/温升|防水|老化|结构|装配/i.test(type)&&!b.images.length)miss.push('测试图片');
  return uniq(miss);
}
function openTestImageLightbox(fileId){
  const t=tests.find(x=>Number(x.id)===Number(testSelectedId));
  const imgs=t?testFileBuckets(t).images:(files||[]).filter(f=>String(f.mime_type||'').startsWith('image/'));
  const idx=Math.max(0,imgs.findIndex(f=>Number(f.id)===Number(fileId)));
  if(!imgs.length){toast('没有图片');return}
  const f=imgs[idx];
  const host=document.createElement('div');
  host.innerHTML=`<div class="modal-mask test-lightbox" data-index="${idx}" onclick="if(event.target===this)this.remove()" onkeydown="handleTestLightboxKey(event)" tabindex="0"><div class="test-lightbox-bar"><button class="btn small" onclick="moveTestLightbox(-1)">上一张</button><b>${esc(f.title||f.original_name||'测试图片')}</b><button class="btn small" onclick="moveTestLightbox(1)">下一张</button><a class="btn small" href="${esc(f.file_path)}" download>下载</a><button class="btn small" onclick="this.closest('.modal-mask').remove()">关闭</button></div><img class="test-lightbox-img" src="${esc(f.file_path)}" alt="${esc(f.title||f.original_name||'测试图片')}"></div>`;
  document.body.appendChild(host.firstElementChild);
  document.querySelector('.test-lightbox')?.focus();
}
function currentLightboxImages(){
  const t=tests.find(x=>Number(x.id)===Number(testSelectedId));
  return t?testFileBuckets(t).images:[];
}
function moveTestLightbox(delta){
  const lb=document.querySelector('.test-lightbox');if(!lb)return;
  const imgs=currentLightboxImages();if(!imgs.length)return;
  let idx=Number(lb.dataset.index||0)+delta;
  if(idx<0)idx=imgs.length-1;if(idx>=imgs.length)idx=0;
  lb.dataset.index=idx;
  const f=imgs[idx], img=lb.querySelector('.test-lightbox-img'), title=lb.querySelector('.test-lightbox-bar b'), link=lb.querySelector('.test-lightbox-bar a');
  if(img)img.src=f.file_path||''; if(title)title.textContent=f.title||f.original_name||'测试图片'; if(link)link.href=f.file_path||'';
}
function handleTestLightboxKey(ev){
  if(ev.key==='Escape')ev.currentTarget.remove();
  if(ev.key==='ArrowLeft')moveTestLightbox(-1);
  if(ev.key==='ArrowRight')moveTestLightbox(1);
}
function renderFiles(p){
  const arr=pFiles(p.id);
  if(customerFileInitializedProject!==Number(p.id)){
    customerFileInitializedProject=Number(p.id);
    customerFileSelected=new Set(arr.filter(f=>Number(f.customer_visible)===1).map(f=>Number(f.id)));
    fileSelectedId=arr[0]?Number(arr[0].id):0;
    localStorage.setItem('plm_v85_file_id',fileSelectedId||0);
  }
  if(fileSelectedId && !arr.some(f=>Number(f.id)===Number(fileSelectedId))){fileSelectedId=arr[0]?Number(arr[0].id):0;localStorage.setItem('plm_v85_file_id',fileSelectedId||0)}
  const s=fileStats(arr), cats=uniq([...FILE_CATS,...TEST_FILE_CATS,...arr.map(f=>f.category).filter(Boolean)]), sourceCounts=fileSourceCounts(arr);
  $('tabbody').innerHTML=`<div class="file-center-v104">
    <div class="file-center-toolbar"><div class="file-center-title"><b>文件中心</b><span>${esc(p.name||'当前项目')}</span></div><div class="file-center-search"><input id="fm_file_search" placeholder="搜索文件名 / 标题 / 备注 / 上传人" oninput="renderFileManagerTable()">${fileModelSelectHtml('fm_model','',true)}<select id="fm_cat" onchange="renderFileManagerTable()"><option value="">全部分类</option>${cats.map(c=>`<option>${esc(c)}</option>`).join('')}</select><select id="fm_source" onchange="renderFileManagerTable()"><option value="all">全部来源</option>${fileSourceOptions(arr)}</select></div><div class="file-center-actions"><button class="btn primary" onclick="openFileUploadDrawer()">上传文件</button><button class="btn good" onclick="openCustomerPackageModal()">客户资料包</button><button class="btn" onclick="openProjectPackageModal()">项目资料包</button><details class="test-more-menu"><summary>更多</summary><div><button class="btn small" onclick="selectCustomerFilesFromManager('current')">当前筛选加入资料包</button><button class="btn small" onclick="selectCustomerFilesFromManager('allCustomer')">全部可发加入资料包</button></div></details></div></div>
    <div class="file-statbar"><span><b>${s.total}</b> 文件</span><span class="good"><b>${s.customer}</b> 可发客户</span><span class="warn"><b>${s.internal}</b> 内部</span><span><b>${s.images}</b> 图片</span><span class="info"><b>${s.tests}</b> 测试资料</span><span><b>${s.reports}</b> 报告</span><span><b>${fileSize(s.bytes)}</b> 总大小</span></div>
    <div class="file-workbench">
      <aside class="file-tree">
        <div class="file-tree-head"><h3>文件筛选</h3></div>
        <div class="file-filter-group"><b>文件范围</b><button class="tree-btn active" data-kind="scope" data-val="all" onclick="setFmFilter('scope','all')">全部文件 <b>${s.total}</b></button><button class="tree-btn" data-kind="scope" data-val="customer" onclick="setFmFilter('scope','customer')">可发客户 <b>${s.customer}</b></button><button class="tree-btn" data-kind="scope" data-val="internal" onclick="setFmFilter('scope','internal')">内部资料 <b>${s.internal}</b></button><button class="tree-btn" data-kind="scope" data-val="currentModel" onclick="setFmFilter('scope','currentModel')">当前样品 <b>${arr.filter(f=>Number(f.model_id)===Number($('fm_model')?.value||0)&&Number(f.model_id)>0).length}</b></button><button class="tree-btn" data-kind="scope" data-val="public" onclick="setFmFilter('scope','public')">项目公共 <b>${arr.filter(f=>!Number(f.model_id||0)).length}</b></button></div>
        <div class="file-filter-group"><b>文件来源</b>${Object.entries(sourceCounts).map(([k,n])=>`<button class="tree-btn" data-kind="source" data-val="${esc(k)}" onclick="setFmFilter('source','${esc(k)}')">${esc(fileSourceLabel(k))} <b>${n}</b></button>`).join('')}</div>
        <div class="file-filter-group"><b>文件分类</b>${cats.slice(0,12).map(c=>`<button class="tree-btn" data-kind="cat" data-val="${esc(c)}" onclick="setFmFilter('cat','${esc(c)}')">${esc(fileCategoryLabel(c))} <b>${arr.filter(f=>f.category===c).length}</b></button>`).join('')||'<div class="hint">暂无分类</div>'}</div>
      </aside>
      <section class="file-list-pane">
        <div class="file-list-head"><div><h3>文件列表</h3><div class="hint">点击文件行查看预览和属性；测试附件按 test_id 独立归档。</div></div><select id="fm_sort" onchange="renderFileManagerTable()"><option value="new">最近上传</option><option value="name">文件名称</option><option value="type">文件类型</option><option value="size">文件大小</option><option value="source">来源模块</option></select></div>
        <div class="fm-table-wrap" id="fm_table_wrap"></div>
      </section>
      <aside class="file-preview-pane"><div id="file_detail_panel"></div></aside>
    </div>
  </div>`;
  $('fm_model').onchange=renderFileManagerTable;
  renderFileManagerTable();
}
function fileSourceKey(f){
  const s=String(f.source_module||'').trim();
  if(s)return s;
  if(Number(f.issue_id||0)>0)return 'issue';
  if(Number(f.test_id||0)>0)return 'test';
  if(Number(f.step_id||0)>0)return 'flow';
  if(Number(f.model_id||0)>0)return 'model';
  return 'file';
}
function fileSourceLabel(k){return {project:'项目基础资料',model:'样品管理',flow:'开发导航图',test:'测试中心',issue:'问题闭环',file:'文件中心上传',filecenter:'文件中心上传',testcenter:'测试中心'}[k]||k||'文件中心'}
function fileCategoryLabel(c){const s=String(c||'');if(/IES|LDT/i.test(s))return 'IES / LDT';if(/报告|PDF/i.test(s))return '测试报告';if(/图片|照片|图/.test(s))return s;return s||'其他'}
function fileStats(arr){return {total:arr.length,customer:arr.filter(f=>Number(f.customer_visible)===1).length,internal:arr.filter(f=>Number(f.customer_visible)!==1).length,images:arr.filter(fileIsImage).length,tests:arr.filter(f=>fileSourceKey(f)==='test'||isTestFile(f)).length,reports:arr.filter(fileIsReport).length,bytes:arr.reduce((n,f)=>n+Number(f.file_size||0),0)}}
function fileIsImage(f){const name=String(f.original_name||f.file_name||'').toLowerCase();return String(f.mime_type||'').startsWith('image/')||/\.(jpg|jpeg|png|webp|gif)$/.test(name)}
function fileIsPdf(f){const name=String(f.original_name||f.file_name||'').toLowerCase();return String(f.mime_type||'').includes('pdf')||/\.pdf$/.test(name)}
function fileIsReport(f){const x=String(f.category||'')+' '+String(f.title||'')+' '+String(f.original_name||'');return /报告|PDF|光谱|配光|EMC/i.test(x)||fileIsPdf(f)}
function fileSourceCounts(arr){const out={};arr.forEach(f=>{const k=fileSourceKey(f);out[k]=(out[k]||0)+1});return out}
function fileSourceOptions(arr){return Object.keys(fileSourceCounts(arr)).map(k=>`<option value="${esc(k)}">${esc(fileSourceLabel(k))}</option>`).join('')}
function setFmFilter(kind,val){if(kind==='scope'){fileScopeFilter=val||'all'}else if(kind==='source'&&$('fm_source')){$('fm_source').value=val}else if(kind==='cat'&&$('fm_cat')){$('fm_cat').value=val}renderFileManagerTable()}
let fileScopeFilter='all';
function currentFileManagerFiles(){const p=cur();if(!p)return[];const q=($('fm_file_search')?.value||'').trim().toLowerCase();const mid=$('fm_model')?.value??'';const cat=$('fm_cat')?.value??'';const scope=fileScopeFilter||'all';const source=$('fm_source')?.value||'all';const sort=$('fm_sort')?.value||'new';let list=pFiles(p.id).filter(f=>{const hay=[f.title,f.original_name,f.file_name,f.category,f.note,f.uploaded_by_name].join(' ').toLowerCase();if(q&&!hay.includes(q))return false;if(mid!==''&&Number(f.model_id)!==Number(mid))return false;if(cat&&f.category!==cat)return false;if(scope==='customer'&&Number(f.customer_visible)!==1)return false;if(scope==='internal'&&Number(f.customer_visible)===1)return false;if(scope==='currentModel'&&!(Number(mid)>0&&Number(f.model_id)===Number(mid)))return false;if(scope==='public'&&Number(f.model_id||0)>0)return false;if(source!=='all'&&fileSourceKey(f)!==source)return false;return true});list=list.slice().sort((a,b)=>{if(sort==='name')return String(a.title||a.original_name||'').localeCompare(String(b.title||b.original_name||''),'zh-Hans-CN');if(sort==='type')return String(a.category||'').localeCompare(String(b.category||''),'zh-Hans-CN');if(sort==='size')return Number(b.file_size||0)-Number(a.file_size||0);if(sort==='source')return fileSourceLabel(fileSourceKey(a)).localeCompare(fileSourceLabel(fileSourceKey(b)),'zh-Hans-CN');return Number(b.id||0)-Number(a.id||0)});return list}
function renderFileManagerTable(){
  const list=currentFileManagerFiles();
  if(!list.length){
    fileSelectedId=0;
    localStorage.setItem('plm_v85_file_id',0);
  }else if(!fileSelectedId || !list.some(f=>Number(f.id)===Number(fileSelectedId))){
    fileSelectedId=Number(list[0].id);
    localStorage.setItem('plm_v85_file_id',fileSelectedId);
  }
  const rows=list.map(f=>fileRow(f)).join('');
  const emptyRow=`<tr><td colspan="9"><div class="empty">当前筛选条件下暂无文件。<br><button class="btn small" onclick="clearFileFilters()">清空筛选</button></div></td></tr>`;
  if($('fm_table_wrap'))$('fm_table_wrap').innerHTML=`<table class="fm-table file-table-v104"><thead><tr><th>选择</th><th>文件</th><th>归属</th><th>分类</th><th>来源</th><th>权限</th><th>大小</th><th>更新时间</th><th>操作</th></tr></thead><tbody>${rows||emptyRow}</tbody></table>`;
  syncFmTreeActive();
  renderFileDetailPanel()
}
function clearFileFilters(){fileScopeFilter='all';if($('fm_cat'))$('fm_cat').value='';if($('fm_source'))$('fm_source').value='all';if($('fm_file_search'))$('fm_file_search').value='';renderFileManagerTable()}
function syncFmTreeActive(){
  const scope=fileScopeFilter||'all', source=$('fm_source')?.value||'all', cat=$('fm_cat')?.value||'';
  document.querySelectorAll('.file-tree .tree-btn').forEach(btn=>{
    const k=btn.dataset.kind, v=btn.dataset.val;
    btn.classList.toggle('active', (k==='scope'&&v===scope) || (k==='source'&&v===source) || (k==='cat'&&v===cat));
  });
}
function fileLinkSummary(f){const st=steps.find(x=>Number(x.id)===Number(f.step_id));const t=tests.find(x=>Number(x.id)===Number(f.test_id));const it=issues.find(x=>Number(x.id)===Number(f.issue_id));const bits=[];if(st)bits.push('步骤：'+(st.title||st.step_name||st.id));if(t)bits.push('测试：'+(t.title||t.test_type||t.id));if(it)bits.push('问题：'+(it.title||it.id));return bits.join(' · ')}
function testSelectHtml(id,val=0,modelId=0,includeAll=true){let list=tests.filter(t=>Number(t.project_id)===Number(cur()?.id||selectedId));if(Number(modelId)>0)list=list.filter(t=>Number(t.model_id)===Number(modelId));let html=includeAll?'<option value="0">不绑定测试</option>':'';html+=list.map(t=>`<option value="${t.id}" ${Number(val)===Number(t.id)?'selected':''}>${esc((t.test_type||'测试')+' / '+(t.title||t.result||t.status||'未命名'))}</option>`).join('');return `<select id="${id}">${html}</select>`}
function issueSelectHtml(id,val=0,modelId=0,includeAll=true){let list=issues.filter(i=>Number(i.project_id)===Number(cur()?.id||selectedId));if(Number(modelId)>0)list=list.filter(i=>Number(i.model_id)===Number(modelId));let html=includeAll?'<option value="0">不绑定问题</option>':'';html+=list.map(i=>`<option value="${i.id}" ${Number(val)===Number(i.id)?'selected':''}>${esc((i.status||'问题')+' / '+(i.title||i.note||i.id))}</option>`).join('');return `<select id="${id}">${html}</select>`}
function fileRow(f){const m=models.find(x=>Number(x.id)===Number(f.model_id));const active=Number(fileSelectedId)===Number(f.id);const source=fileSourceLabel(fileSourceKey(f));const link=fileLinkSummary(f);const visible=Number(f.customer_visible)===1;return `<tr class="${active?'active':''}" onclick="selectFile(${f.id})"><td onclick="event.stopPropagation()"><input type="checkbox" data-file-select="${Number(f.id)}" onchange="toggleCustomerFile(${Number(f.id)},this.checked)" ${customerFileSelected.has(Number(f.id))?'checked':''}></td><td><div class="file-row-main">${fileIcon(f)}<div class="file-row-text"><div class="file-main-name">${esc(f.title||f.original_name||f.file_name)}</div><div class="hint">${esc(f.original_name||'')} ${link?'｜ '+esc(link):''}</div></div></div></td><td>${esc(m?fileModelLabel(m):'项目公共文件')}</td><td>${esc(fileCategoryLabel(f.category||''))}</td><td>${esc(source)}</td><td>${visible?'<span class="tag green">可发客户</span>':'<span class="tag orange">内部资料</span>'}</td><td>${fileSize(f.file_size)}</td><td class="nowrap">${esc(f.created_at||'')}</td><td onclick="event.stopPropagation()"><div class="file-row-actions"><button class="btn small" onclick="selectFile(${Number(f.id)})">预览</button><a class="btn small" href="${esc(f.file_path)}" target="_blank">下载</a><details class="test-more-menu"><summary>更多</summary><div><button class="btn small" onclick="selectFile(${Number(f.id)})">修改资料</button>${visible?`<button class="btn small good" onclick="customerFileSelected.add(${Number(f.id)});renderFileManagerTable();toast('已加入客户资料包')">加入资料包</button>`:''}<button class="btn small" onclick="copyFileLink(${Number(f.id)})">复制链接</button><button class="btn small danger" onclick="deleteFile(${Number(f.id)})">删除</button></div></details></div></td></tr>`}
function selectFile(id){fileSelectedId=Number(id)||0;localStorage.setItem('plm_v85_file_id',fileSelectedId);renderFileManagerTable()}
function fileIcon(f){const mt=String(f.mime_type||''),path=String(f.file_path||''),name=String(f.original_name||f.file_name||'').toLowerCase();if(mt.startsWith('image/')||/\.(jpg|jpeg|png|webp|gif)$/.test(name))return `<div class="file-ico"><img src="${esc(path)}"></div>`;const ext=(name.split('.').pop()||'FILE').slice(0,4).toUpperCase();return `<div class="file-ico">${esc(ext)}</div>`}
function fileSize(n){n=Number(n)||0;if(!n)return'-';if(n<1024)return n+' B';if(n<1024*1024)return Math.round(n/1024)+' KB';return (n/1024/1024).toFixed(1)+' MB'}
function toggleFilePreview(){
  const willOpen = filePreviewCollapsed;
  filePreviewCollapsed=!filePreviewCollapsed;
  localStorage.setItem('plm_v855_file_preview_collapsed',filePreviewCollapsed?'1':'0');
  if(willOpen){
    // V8.5.29：展开文件预览时，自动让项目中心和文件筛选变窄，给预览留空间。
    fileFilterCollapsed=true;
    localStorage.setItem('plm_v8529_file_filter_collapsed','1');
  }else{
    // V8.5.29：收起预览时，主动恢复项目中心；文件筛选也恢复完整，仍可手动再收起。
    fileFilterCollapsed=false;
    localStorage.setItem('plm_v8529_file_filter_collapsed','0');
  }
  renderFiles(cur());
}
function toggleFileFilterRail(){fileFilterCollapsed=!fileFilterCollapsed;localStorage.setItem('plm_v8529_file_filter_collapsed',fileFilterCollapsed?'1':'0');renderFiles(cur())}
function renderFileDetailPanel(){const f=files.find(x=>Number(x.id)===Number(fileSelectedId));if(!$('file_detail_panel'))return;if(!f){$('file_detail_panel').innerHTML='<div class="file-preview-head"><h3>文件预览</h3></div><div class="file-empty-note"><b>选择一个文件</b><span>右侧会显示预览、归属、测试/步骤/问题绑定和客户权限。</span><button class="btn primary" onclick="openFileUploadDrawer()">上传文件</button></div>';return}const m=models.find(x=>Number(x.id)===Number(f.model_id));const st=steps.find(x=>Number(x.id)===Number(f.step_id));const t=tests.find(x=>Number(x.id)===Number(f.test_id));const it=issues.find(x=>Number(x.id)===Number(f.issue_id));const visible=Number(f.customer_visible)===1;const previewHtml=filePreviewLarge(f);$('file_detail_panel').innerHTML=`<div class="file-preview-head"><div><h3>${esc(f.title||f.original_name||'文件预览')}</h3><div class="hint">${esc(fileCategoryLabel(f.category||''))} ｜ ${visible?'可发客户':'内部资料'} ｜ ${esc(fileSourceLabel(fileSourceKey(f)))}</div></div></div>${previewHtml}<div class="tags"><span class="file-source-badge ${fileSourceKey(f)==='test'?'test':'file'}">${esc(fileSourceLabel(fileSourceKey(f)))}</span>${visible?'<span class="tag green">可发客户</span>':'<span class="tag orange">内部资料</span>'}${st?`<span class="tag blue">步骤：${esc(st.title||'')}</span>`:''}${t?`<span class="tag purple">测试：${esc(t.title||t.test_type||'')}</span>`:''}${it?`<span class="tag red">问题：${esc(it.title||'')}</span>`:''}</div><div class="file-meta-row"><b>文件名</b><span>${esc(f.original_name||f.file_name||'')}</span></div><div class="file-meta-row"><b>归属型号</b><span>${esc(m?fileModelLabel(m):'项目公共文件')}</span></div><div class="file-meta-row"><b>大小</b><span>${fileSize(f.file_size)}</span></div><div class="file-meta-row"><b>上传</b><span>${esc(f.uploaded_by_name||'-')} ｜ ${esc(f.created_at||'')}</span></div><div class="step-bind"><div class="grid2"><div class="field"><label>文件标题</label><input id="f_title_${f.id}" value="${esc(f.title||'')}" placeholder="标题"></div><div class="field"><label>文件分类</label><select id="f_cat_${f.id}">${uniq([...FILE_CATS,...TEST_FILE_CATS, f.category||'']).filter(Boolean).map(c=>`<option ${c===f.category?'selected':''}>${esc(c)}</option>`).join('')}</select></div></div><div class="field"><label>归属型号</label>${fileModelSelectHtml('f_model_'+f.id,f.model_id||0,false)}</div><div class="field"><label>来源模块</label><select id="f_source_${f.id}">${[['file','文件中心上传'],['project','项目基础资料'],['model','样品管理'],['flow','开发导航图'],['test','测试中心'],['issue','问题闭环']].map(([v,l])=>`<option value="${v}" ${fileSourceKey(f)===v?'selected':''}>${l}</option>`).join('')}</select></div><div class="field"><label>关联开发步骤</label>${stepSelectHtml('f_step_'+f.id,f.step_id||0,f.model_id||0,true)}</div><div class="field"><label>关联测试项目</label>${testSelectHtml('f_test_'+f.id,f.test_id||0,0,true)}</div><div class="field"><label>关联问题</label>${issueSelectHtml('f_issue_'+f.id,f.issue_id||0,0,true)}</div><textarea id="f_note_${f.id}" placeholder="备注">${esc(f.note||'')}</textarea><label class="hint"><input id="f_vis_${f.id}" type="checkbox" ${visible?'checked':''} style="width:auto"> 可发客户（取消后作为内部资料，不进入客户资料包）</label><div class="file-actions-line"><a class="btn small" href="${esc(f.file_path)}" target="_blank">打开</a><a class="btn small" href="${esc(f.file_path)}" download>下载</a><button class="btn small good" onclick="saveFileMeta(${f.id})">保存文件资料</button>${visible?`<button class="btn small primary" onclick="customerFileSelected.add(${Number(f.id)});toast('已加入客户资料包')">加入客户资料包</button>`:''}<button class="btn small danger" onclick="deleteFile(${f.id})">删除</button></div></div>`}
function filePreviewLarge(f){const mt=String(f.mime_type||''),path=String(f.file_path||''),name=String(f.original_name||f.file_name||'').toLowerCase();const ext=(name.split('.').pop()||'文件').toUpperCase();if(mt.startsWith('image/')||/\.(jpg|jpeg|png|webp|gif)$/.test(name))return `<div class="file-preview-large"><img src="${esc(path)}"></div>`;if(mt.includes('pdf')||/\.pdf$/.test(name))return `<div class="file-preview-large"><iframe src="${esc(path)}"></iframe></div>`;let tip='此格式可下载或打开链接查看';if(/\.(ies|ldt)$/.test(name))tip='IES / LDT 文件当前提供下载查看，不伪造配光预览';if(/\.(xls|xlsx|doc|docx)$/.test(name))tip='Office 文件如无法在线预览，请下载查看';if(/\.zip$/.test(name))tip='ZIP 文件不在线展开，请下载查看';return `<div class="file-preview-large"><div class="empty" style="border:0;background:transparent"><b>${esc(ext)}</b><br><span class="hint">${esc(tip)}</span><div style="margin-top:10px"><a class="btn small" href="${esc(path)}" target="_blank">打开</a><a class="btn small primary" href="${esc(path)}" download>下载</a></div></div></div>`}
async function copyFileLink(id){const f=files.find(x=>Number(x.id)===Number(id));if(!f){toast('文件不存在');return}const url=absUrl(f.file_path);try{await navigator.clipboard.writeText(url);toast('文件链接已复制')}catch(e){prompt('复制文件链接',url)}}
function selectCustomerFilesFromManager(mode){const p=cur();if(!p)return;if(mode==='allCustomer')pFiles(p.id).filter(f=>Number(f.customer_visible)===1).forEach(f=>customerFileSelected.add(Number(f.id)));else currentFileManagerFiles().forEach(f=>customerFileSelected.add(Number(f.id)));renderCustomerFileList();toast('已加入客户资料包')}

function customerPackagePanel(p){const cats=uniq(pFiles(p.id).map(f=>f.category));return `<div class="customer-panel"><h3>发给客户 / 客户资料包</h3><div class="customer-tools">${fileModelSelectHtml('cf_model','',true)}<select id="cf_cat"><option value="">全部文件类型</option>${cats.map(c=>`<option>${esc(c)}</option>`).join('')}</select><select id="cf_scope"><option value="all">全部资料</option><option value="customer">仅可发客户</option><option value="filecenter">仅文件中心</option><option value="testcenter">仅测试中心</option></select><button class="btn" onclick="renderCustomerFileList()">筛选</button></div><div class="actions" style="margin-top:10px"><button class="btn small good" onclick="selectCustomerFiles('visible')">勾选当前筛选</button><button class="btn small" onclick="selectCustomerFiles('all')">勾选全部</button><button class="btn small" onclick="selectCustomerFiles('none')">清空</button><button class="btn small primary" onclick="copyCustomerLinks()">复制客户链接清单</button><button class="btn small warn" onclick="createCustomerZip()">生成ZIP资料包</button></div><div id="pkg_result" class="pkg-result"></div><div id="customer_file_list" class="file-list-wrap"></div><textarea id="customer_links" class="copybox" readonly placeholder="选择文件后，点击“复制客户链接清单”会生成清单。"></textarea></div>`}
function openCustomerPackageModal(){
  const p=cur();if(!p)return;
  const cats=uniq(pFiles(p.id).filter(f=>Number(f.customer_visible)===1).map(f=>f.category).filter(Boolean));
  const total=pFiles(p.id).filter(f=>Number(f.customer_visible)===1).length;
  const bytes=pFiles(p.id).filter(f=>Number(f.customer_visible)===1).reduce((n,f)=>n+Number(f.file_size||0),0);
  const host=document.createElement('div');
  host.innerHTML=`<div class="modal-mask" onclick="if(event.target===this)this.remove()"><div class="modal customer-package-modal"><div class="modal-head"><div><h3>客户资料包</h3><div class="hint">${esc(p.name||'当前项目')} ｜ 客户：${esc(p.customer||'-')} ｜ 可发文件 ${total} ｜ ${fileSize(bytes)}</div></div><button class="btn" onclick="this.closest('.modal-mask').remove()">关闭</button></div><div class="modal-body"><div class="customer-panel"><div class="customer-tools">${fileModelSelectHtml('cf_model','',true)}<select id="cf_cat"><option value="">全部文件类型</option>${cats.map(c=>`<option>${esc(c)}</option>`).join('')}</select><select id="cf_scope"><option value="customer" selected>仅可发客户</option><option value="filecenter">仅文件中心</option><option value="testcenter">仅测试中心</option></select><button class="btn" onclick="renderCustomerFileList()">筛选</button></div><div class="actions" style="margin-top:10px"><button class="btn small good" onclick="selectCustomerFiles('visible')">勾选当前筛选</button><button class="btn small" onclick="selectCustomerFiles('all')">勾选全部可发</button><button class="btn small" onclick="selectCustomerFiles('none')">清空</button><button class="btn small primary" onclick="copyCustomerLinks()">复制客户链接</button><button class="btn small warn" onclick="createCustomerZip()">生成ZIP</button></div><div id="pkg_result" class="pkg-result"></div><div id="customer_file_list" class="file-list-wrap"></div><textarea id="customer_links" class="copybox" readonly placeholder="选择文件后生成客户链接清单"></textarea></div></div></div></div>`;
  document.body.appendChild(host.firstElementChild);
  renderCustomerFileList();
}
function currentCustomerFiles(){const p=cur();if(!p)return[];const mid=$('cf_model')?.value??'';const cat=$('cf_cat')?.value??'';const scope=$('cf_scope')?.value??'all';return pFiles(p.id).filter(f=>{if(mid!==''&&Number(f.model_id)!==Number(mid))return false;if(cat&&f.category!==cat)return false;if(scope==='customer'&&Number(f.customer_visible)!==1)return false;if(scope==='filecenter'&&isTestFile(f))return false;if(scope==='testcenter'&&!isTestFile(f))return false;return true})}
function renderCustomerFileList(){const list=currentCustomerFiles();const rows=list.map(f=>{const m=models.find(x=>Number(x.id)===Number(f.model_id));const checked=customerFileSelected.has(Number(f.id));const title=esc(f.title||f.original_name||f.file_name||'未命名文件');const origin=esc(f.original_name||f.file_name||'');const group=esc(m?fileModelLabel(m):'项目公共文件');const cat=esc(f.category||'文件');const source=esc(fileTypeLabel(f));const vis=Number(f.customer_visible)===1;return `<label class="customer-file-row ${checked?'checked':''}"><input type="checkbox" data-cfid="${f.id}" ${checked?'checked':''} onchange="toggleCustomerFile(${f.id},this.checked)"><span class="customer-file-main"><span class="customer-file-title">${title}</span><span class="customer-file-sub">${group} · ${cat} · ${source}</span><span class="customer-file-origin">${origin}</span></span><span class="customer-file-badges">${vis?'<b class="tag green">可发</b>':'<b class="tag orange">内部</b>'}</span></label>`}).join('');const html=`<div class="customer-mini-head"><span>选</span><span>文件 / 归属 / 类型</span><span>权限</span></div><div class="customer-mini-list">${rows||'<div class="empty">当前筛选下没有文件</div>'}</div>`;if($('customer_file_list'))$('customer_file_list').innerHTML=html;refreshCustomerLinksText(false)}
function toggleCustomerFile(id,on){if(on)customerFileSelected.add(Number(id));else customerFileSelected.delete(Number(id));refreshCustomerLinksText(false)}
function selectCustomerFiles(mode){const p=cur();if(!p)return;if(mode==='none')customerFileSelected.clear();else if(mode==='all')pFiles(p.id).filter(f=>Number(f.customer_visible)===1).forEach(f=>customerFileSelected.add(Number(f.id)));else currentCustomerFiles().filter(f=>Number(f.customer_visible)===1).forEach(f=>customerFileSelected.add(Number(f.id)));renderCustomerFileList()}
function selectedCustomerFiles(){const p=cur();if(!p)return[];return pFiles(p.id).filter(f=>customerFileSelected.has(Number(f.id))&&Number(f.customer_visible)===1)}
function buildCustomerLinksText(){const p=cur();const list=selectedCustomerFiles();const lines=[];lines.push(`项目：${p?(p.name||'未命名项目'):''}`);lines.push(`客户：${p?(p.customer||'-'):''}`);lines.push(`文件数量：${list.length}`);lines.push('');let last='';list.forEach((f,i)=>{const m=models.find(x=>Number(x.id)===Number(f.model_id));const group=m?fileModelLabel(m):'项目公共文件';if(group!==last){lines.push('【'+group+'】');last=group;}lines.push(`${i+1}. ${f.title||f.original_name||f.file_name}（${f.category||'文件'}）`);lines.push(absUrl(f.file_path));});return lines.join('\n')}
function refreshCustomerLinksText(force){const el=$('customer_links');if(!el)return;el.value=buildCustomerLinksText();if(force)el.focus()}
async function copyCustomerLinks(){refreshCustomerLinksText(true);const txt=$('customer_links').value;if(!selectedCustomerFiles().length){toast('请先选择文件');return}try{await navigator.clipboard.writeText(txt);toast('客户链接清单已复制')}catch(e){toast('浏览器不允许自动复制，可手动复制下方文本')}}
async function createCustomerZip(){const list=selectedCustomerFiles();if(!list.length){toast('请先选择文件');return}const r=await api('create_customer_zip',{project_id:cur().id,file_ids:list.map(f=>f.id)});if(!r.ok){toast(r.error||'生成ZIP失败');return}const url=absUrl(r.url);const box=$('pkg_result');box.classList.add('show');box.innerHTML=`已生成 ZIP：<a class="link" href="${esc(r.url)}" target="_blank">${esc(r.name||'客户资料包.zip')}</a> ｜ ${r.count} 个文件 <button class="btn small" onclick="navigator.clipboard.writeText('${esc(url)}')">复制ZIP链接</button>`;toast('ZIP资料包已生成')}
function filePreview(f){const mt=String(f.mime_type||''),path=String(f.file_path||''),name=String(f.original_name||f.file_name||'').toLowerCase();if(mt.startsWith('image/')||/\.(jpg|jpeg|png|webp|gif)$/.test(name))return `<img class="thumb" src="${esc(path)}">`;if(mt.includes('pdf')||/\.pdf$/.test(name))return `<div class="pdfbox"><iframe src="${esc(path)}"></iframe></div>`;return `<div class="empty" style="padding:18px">${esc((name.split('.').pop()||'文件').toUpperCase())}</div>`}
function fileCard(f){const isTest=TEST_FILE_CATS.includes(f.category);const m=models.find(x=>Number(x.id)===Number(f.model_id));return `<div class="file-card" style="border-left-color:${isTest?'#7c3aed':'#2563eb'}">${filePreview(f)}<h3>${esc(f.title||f.original_name||f.file_name)}</h3><div class="hint">${esc(f.category||'')} ｜ ${esc(f.original_name||'')} ｜ ${esc(f.created_at||'')}</div><div class="hint">归属：${esc(m?fileModelLabel(m):'项目公共文件')} ｜ ${esc(f.note||'')}</div><div class="tags">${f.customer_visible==1?'<span class="tag green">可发客户</span>':'<span class="tag orange">内部资料</span>'}${isTest?'<span class="tag purple">测试资料</span>':'<span class="tag blue">文件中心</span>'}</div><div class="grid2"><input id="f_title_${f.id}" value="${esc(f.title||'')}" placeholder="标题"><select id="f_cat_${f.id}">${[...FILE_CATS,...TEST_FILE_CATS].map(c=>`<option ${c===f.category?'selected':''}>${esc(c)}</option>`).join('')}</select></div><div class="field"><label>归属型号</label>${fileModelSelectHtml('f_model_'+f.id,f.model_id||0,false)}</div><textarea id="f_note_${f.id}" placeholder="备注">${esc(f.note||'')}</textarea><label class="hint"><input id="f_vis_${f.id}" type="checkbox" ${Number(f.customer_visible)===1?'checked':''} style="width:auto"> 可发客户</label><div class="actions"><a class="btn small" href="${esc(f.file_path)}" target="_blank">打开</a><button class="btn small good" onclick="saveFileMeta(${f.id})">保存</button><button class="btn small danger" onclick="deleteFile(${f.id})">删除</button></div></div>`}
async function saveFileMeta(id){const f=files.find(x=>Number(x.id)===Number(id))||{};const r=await api('update_file_meta',{id,title:$('f_title_'+id).value,category:$('f_cat_'+id).value,note:$('f_note_'+id).value,customer_visible:$('f_vis_'+id)?.checked?1:0,model_id:Number($('f_model_'+id)?.value||0),test_id:Number($('f_test_'+id)?.value??f.test_id??0),test_run_id:f.test_run_id||0,step_id:Number($('f_step_'+id)?.value??f.step_id??0),issue_id:Number($('f_issue_'+id)?.value??f.issue_id??0),source_module:$('f_source_'+id)?.value||fileSourceKey(f)});toast(r.ok?'文件信息已保存':r.error);await load()}
async function deleteFile(id){if(!confirm('删除这个文件记录和服务器文件？'))return;const r=await api('delete_file',{id});toast(r.ok?'文件已删除':r.error);await load()}

function openProjectPackageModal(){
  if(!guardPerm('export_package','导出项目资料包'))return;
  const p=cur(); if(!p){toast('请先选择项目');return}
  const ms=pModels(p.id);
  const host=document.createElement('div');
  host.innerHTML=`<div class="modal-mask" onclick="if(event.target===this)this.remove()"><div class="modal" style="width:min(860px,96vw)"><div class="modal-head"><div><h3>项目资料包</h3><div class="hint">导出项目或单个样品资料包，包含项目资料、样品资料、测试记录、问题闭环、开发流程、文件清单和实际附件。</div></div><button class="btn" onclick="this.closest('.modal-mask').remove()">关闭</button></div><div class="modal-body"><div class="grid2"><div class="field"><label>资料包类型</label><select id="pkg_model"><option value="0">整个项目资料包</option>${ms.map(m=>`<option value="${m.id}">样品：${esc(modelLabel(m))}</option>`).join('')}</select></div><div class="field"><label>附件范围</label><select id="pkg_include"><option value="all">全部附件</option><option value="customer">仅可发客户资料</option><option value="filecenter">仅文件中心资料</option><option value="test">仅测试中心资料</option><option value="none">只导出汇总和清单，不带附件</option></select></div></div><div class="search-card" style="margin-top:10px"><h3 style="margin-top:0">将包含</h3><div class="tags"><span class="tag">项目基础资料</span><span class="tag">样品资料</span><span class="tag green">测试记录</span><span class="tag orange">问题闭环</span><span class="tag blue">开发流程</span><span class="tag">文件清单</span><span class="tag">实际附件</span></div><div class="hint" style="margin-top:8px">第一版为 ZIP 资料包。ZIP 内会带 00_项目资料汇总.html、CSV 清单、JSON 原始资料，以及按“样品/分类”整理的附件文件。</div></div><div id="pkg_full_result" class="pkg-result" style="margin-top:12px"></div></div><div class="modal-foot"><button class="btn" onclick="this.closest('.modal-mask').remove()">取消</button><button class="btn primary" onclick="createProjectPackageZip()">生成资料包 ZIP</button></div></div></div>`;
  document.body.appendChild(host.firstElementChild);
}
async function createProjectPackageZip(){
  if(!guardPerm('export_package','导出项目资料包'))return;
  const p=cur(); if(!p)return;
  const mid=Number($('pkg_model')?.value||0);
  const include=$('pkg_include')?.value||'all';
  const box=$('pkg_full_result');
  if(box){box.classList.add('show');box.innerHTML='正在生成资料包，请稍候...';}
  const r=await api('create_project_package',{project_id:p.id,model_id:mid,include});
  if(!r.ok){ if(box)box.innerHTML='生成失败：'+esc(r.error||'未知错误'); toast(r.error||'生成失败'); return; }
  const url=absUrl(r.url);
  if(box)box.innerHTML=`已生成：<a class="link" href="${esc(r.url)}" target="_blank">${esc(r.name||'项目资料包.zip')}</a> ｜ 附件 ${Number(r.count||0)} 个 <button class="btn small" onclick="navigator.clipboard.writeText('${esc(url)}')">复制链接</button>`;
  toast('资料包已生成');
}

function gotoTab(t){tab=t;localStorage.setItem('plm_v85_tab',tab);renderDetail()}
function pctMini(done,total){done=Number(done||0);total=Number(total||0);return total?Math.round(done*100/total):0}
function isStepOpen(s){return !['已完成','跳过'].includes(String(s.status||''))}
function isStepLate(s){const d=dateOnly(s.plan_end||s.plan_date||'');return d && d < new Date().toISOString().slice(0,10) && isStepOpen(s)}
function summaryAction(title,desc,btn,click,cls='primary',extra=''){return `<div class="next-action-card ${esc(cls)}"><div><b>${esc(title)}</b><small>${esc(desc)}</small>${extra?`<div class="summary-risk-mini">${extra}</div>`:''}</div><button class="btn small ${cls}" onclick="${click}">${esc(btn)}</button></div>`}
function setSummarySample(id){summarySampleId=Number(id)||0;localStorage.setItem('plm_v85_summary_sample_id',summarySampleId);renderSummary(cur())}
const SUMMARY_SECTION_DEFS=[
  {key:'overview',label:'项目一眼看清'},
  {key:'actions',label:'下一步与风险提醒'},
  {key:'samples',label:'样品推进'},
  {key:'flow',label:'当前开发流程'},
  {key:'tests',label:'测试与问题'},
  {key:'files',label:'最近资料'},
  {key:'logs',label:'最近动态'}
];
function summaryVisibleMap(){
  const def={};SUMMARY_SECTION_DEFS.forEach(x=>def[x.key]=true);
  try{
    const raw=localStorage.getItem('plm_v85_summary_sections');
    const saved=raw?JSON.parse(raw):{};
    const merged=Object.assign(def,saved||{});
    const visibleCount=SUMMARY_SECTION_DEFS.filter(x=>merged[x.key]!==false).length;
    if(!visibleCount)return def;
    merged.overview=true;
    return merged;
  }catch(e){return def;}
}
function saveSummaryVisibleMap(v){localStorage.setItem('plm_v85_summary_sections',JSON.stringify(v||{}));}
function isSummaryVisible(k){const v=summaryVisibleMap();return v[k]!==false;}
function setSummarySection(k,on){const v=summaryVisibleMap();if(k==='overview'&&!on){toast('项目一眼看清必须保留');return}v[k]=!!on;saveSummaryVisibleMap(v);renderSummary(cur());}
function resetSummarySections(){localStorage.removeItem('plm_v85_summary_sections');renderSummary(cur())}
function showAllSummarySections(){const v=summaryVisibleMap();SUMMARY_SECTION_DEFS.forEach(x=>v[x.key]=true);saveSummaryVisibleMap(v);renderSummary(cur())}
function summaryVisibilityBar(){
  const v=summaryVisibleMap();
  const chips=SUMMARY_SECTION_DEFS.map(x=>`<label class="summary-toggle-chip ${v[x.key]!==false?'on':''}"><input type="checkbox" ${v[x.key]!==false?'checked':''} onchange="setSummarySection('${x.key}',this.checked)">${esc(x.label)}</label>`).join('');
  return `<details class="summary-settings"><summary>总览设置</summary><div class="summary-settings-menu"><div class="summary-toggle-list">${chips}</div><div class="actions"><button class="btn small" onclick="showAllSummarySections()">全部显示</button><button class="btn small" onclick="resetSummarySections()">恢复默认</button></div></div></details>`;
}
function summaryTestStats(ts){
  const total=ts.length;
  const passed=ts.filter(t=>testResultValue(t)==='通过').length;
  const failed=ts.filter(t=>testResultValue(t)==='不通过').length;
  const retest=ts.filter(t=>testStatusValue(t)==='待复测'||testRetestCount(t,ts)>0).length;
  const running=ts.filter(t=>testStatusValue(t)==='进行中').length;
  const pending=ts.filter(t=>['未开始','待测'].includes(testStatusValue(t))).length;
  return {total,passed,failed,retest,running,pending,pct:total?Math.round(passed*100/total):0};
}
function closedIssue(i){return ['已解决','已关闭','关闭','完成'].includes(String(i.status||''))}
function seriousIssue(i){return /严重|高|P1|S1/i.test(String(i.severity||i.priority||''))}
function stepDone(s){return ['已完成','跳过'].includes(String(s.status||''))}
function flowStatsForSteps(st){const done=st.filter(stepDone).length;return {total:st.length,done,pct:st.length?Math.round(done/st.length*100):0}}
function componentReady(m){
  const keys=['chip','optical','driver','accessories'];
  const done=keys.filter(k=>String(m[k+'_name']||m[k+'_brand']||m[k+'_material_id']||m[k+'_material_ids']||'').trim()!=='').length;
  return {done,total:4,ok:done>=3};
}
function projectHasBomForModel(m){
  return logs.some(l=>Number(l.project_id)===Number(m.project_id)&&String(l.target_type||'').toLowerCase()==='bom'&&String(l.note||'').includes(String(m.id)))||String(m.bom_note||'').trim()!=='';
}
function summaryJump(tabName,opts={}){
  if(Object.prototype.hasOwnProperty.call(opts,'model_id')){summarySampleId=Number(opts.model_id)||0;flowModelId=summarySampleId;testModelId=summarySampleId;issueModelFilter=summarySampleId?String(summarySampleId):'';localStorage.setItem('plm_v85_summary_sample_id',summarySampleId);localStorage.setItem('plm_v85_flow_model',flowModelId);localStorage.setItem('plm_v85_test_model',testModelId);localStorage.setItem('plm_v85_issue_model',issueModelFilter);}
  if(opts.step_id){flowSelectedStepId=Number(opts.step_id);localStorage.setItem('plm_v85_step_id',flowSelectedStepId);}
  if(opts.test_id){testSelectedId=Number(opts.test_id);localStorage.setItem('plm_v85_test_id',testSelectedId);testCreateMode=false;localStorage.setItem('plm_v85_test_create_mode','0');}
  if(opts.issue_id){issueSelectedId=Number(opts.issue_id);issueCreateMode=false;localStorage.setItem('plm_v85_issue_id',issueSelectedId);localStorage.setItem('plm_v85_issue_create','0');}
  if(opts.file_id){fileSelectedId=Number(opts.file_id);localStorage.setItem('plm_v85_file_id',fileSelectedId);}
  tab=tabName;localStorage.setItem('plm_v85_tab',tab);renderDetail();
}
function summaryItem(title,meta,click='',cls=''){
  return `<div class="summary-list-row ${esc(cls)}"><div><b>${esc(title||'-')}</b><span>${esc(meta||'')}</span></div>${click?`<button class="btn small" onclick="${click}">查看</button>`:''}</div>`;
}
function currentAndNextStep(st){
  const sorted=[...st].sort((a,b)=>(Number(a.sort_order||0)-Number(b.sort_order||0))||(Number(a.id||0)-Number(b.id||0)));
  const current=sorted.find(s=>String(s.status||'')==='进行中')||sorted.find(s=>isStepOpen(s));
  const idx=current?sorted.findIndex(s=>Number(s.id)===Number(current.id)):-1;
  const next=idx>=0?sorted.slice(idx+1).find(s=>isStepOpen(s)):sorted.find(s=>isStepOpen(s));
  const recent=[...sorted].reverse().filter(stepDone).slice(0,2);
  return {current,next,recent};
}
function summaryBestAction(data){
  const {ms,openIssues,seriousIssues,failedTests,retestTests,lateSteps,abnormalSteps,openSteps,fs,ts,ss}=data;
  const first=(arr)=>arr&&arr.length?arr[0]:null;
  let x=first(seriousIssues); if(x)return summaryAction('严重问题未关闭',x.title||'存在严重问题','查看问题',`summaryJump('issues',{model_id:${Number(x.model_id||0)}})`,'danger');
  x=first(failedTests); if(x)return summaryAction('测试不通过',`${x.test_type||'测试'} · ${x.title||''}`,'查看测试',`summaryJump('tests',{model_id:${Number(x.model_id||0)},test_id:${Number(x.id)}})`,'danger');
  x=first(retestTests); if(x)return summaryAction('存在待复测',`${x.test_type||'测试'} 需要复测确认`,'查看测试',`summaryJump('tests',{model_id:${Number(x.model_id||0)},test_id:${Number(x.id)}})`,'warn');
  x=first(lateSteps); if(x)return summaryAction('流程节点延期',`${x.title||'步骤'} 计划 ${dateOnly(x.plan_end||x.plan_date)||'-'}`,'查看流程',`summaryJump('flow',{model_id:${Number(x.model_id||0)},step_id:${Number(x.id)}})`,'warn');
  x=first(abnormalSteps); if(x)return summaryAction('流程存在异常/退回',x.title||'流程节点异常','查看流程',`summaryJump('flow',{model_id:${Number(x.model_id||0)},step_id:${Number(x.id)}})`,'warn');
  x=openSteps.find(s=>!String(s.owner||s.owner_name||'').trim()); if(x)return summaryAction('当前步骤未指定负责人',x.title||'待分配步骤','查看流程',`summaryJump('flow',{model_id:${Number(x.model_id||0)},step_id:${Number(x.id)}})`,'primary');
  x=openSteps.find(s=>!dispatchSummary(s.id).total); if(x)return summaryAction('当前步骤尚未生成派工',x.title||'待派工步骤','生成派工',`summaryJump('flow',{model_id:${Number(x.model_id||0)},step_id:${Number(x.id)}})`,'primary');
  x=openSteps.find(s=>String(s.status||'')!=='进行中'); if(x)return summaryAction('下一流程尚未开始',x.title||'下一步骤','查看流程',`summaryJump('flow',{model_id:${Number(x.model_id||0)},step_id:${Number(x.id)}})`,'primary');
  const notReady=ms.find(m=>!componentReady(m).ok); if(notReady)return summaryAction('关键元器件未完成',modelLabel(notReady),'查看样品',`summaryJump('models',{model_id:${Number(notReady.id)}})`,'warn');
  const noBom=ms.find(m=>!projectHasBomForModel(m)); if(noBom)return summaryAction('BOM 尚未生成或不完整',modelLabel(noBom),'生成 BOM',`summaryJump('models',{model_id:${Number(noBom.id)}})`,'warn');
  if(!ts.length)return summaryAction('必需测试尚未建立','当前项目还没有测试记录','进入测试',`summaryJump('tests')`,'primary');
  if(!fs.filter(f=>Number(f.customer_visible)===1).length)return summaryAction('客户资料尚不完整','还没有可发客户文件','进入文件',`summaryJump('files')`,'primary');
  if(ss.length&&ss.every(stepDone)&&ts.length&&summaryTestStats(ts).failed===0)return summaryAction('开发与测试已完成','可以整理客户资料包','客户资料包',"openCustomerPackageModal()",'good');
  return summaryAction('当前没有阻塞异常','继续按计划推进项目即可','查看流程',`summaryJump('flow')`,'good');
}
function renderSummary(p){
  const ms=pModels(p.id),ts=pTests(p.id),fs=pFiles(p.id),ss=steps.filter(s=>Number(s.project_id)===Number(p.id)),is=issues.filter(x=>Number(x.project_id)===Number(p.id));
  const openIssues=is.filter(x=>!['已解决','已关闭'].includes(String(x.status||'')));
  const failTests=ts.filter(t=>['不通过','需整改','待复测'].includes(String(t.status||''))||['不通过','待复测'].includes(String(t.result||'')));
  const lateSteps=ss.filter(isStepLate);
  const doingSteps=ss.filter(s=>String(s.status||'')==='进行中');
  const openSteps=ss.filter(isStepOpen);
  const g=prog(p.id);
  const typeCounts={};ts.forEach(t=>typeCounts[t.test_type||'其它']=(typeCounts[t.test_type||'其它']||0)+1);
  const recentLogs=logs.filter(l=>Number(l.project_id)===Number(p.id)).slice(0,8);
  const recentFiles=fs.slice(0,8);
  const actions=[];
  if(!ms.length) actions.push(summaryAction('先建样品','一个项目可以多个样品，每个样品独立流程和测试。','去新增',"gotoTab('models')"));
  if(openIssues.length) actions.push(summaryAction('处理未关闭问题','还有 '+openIssues.length+' 个问题未关闭，建议先处理。','看问题',"gotoTab('issues')",'warn'));
  if(failTests.length) actions.push(summaryAction('复核异常测试','有 '+failTests.length+' 条测试不通过/需复测。','看测试',"gotoTab('tests')",'warn'));
  if(lateSteps.length) actions.push(summaryAction('检查逾期流程','有 '+lateSteps.length+' 个流程节点已过计划日期。','看流程',"gotoTab('flow')",'danger'));
  if(openSteps.length && !lateSteps.length) actions.push(summaryAction('推进开发流程','还有 '+openSteps.length+' 个流程节点未完成。','看流程',"gotoTab('flow')"));
  if(!fs.length) actions.push(summaryAction('补充项目资料','建议上传产品图、结构图、测试资料，后续资料包才完整。','传文件',"gotoTab('files')"));
  if(!actions.length) actions.push(summaryAction('项目状态不错','流程、测试、问题都比较清楚，可以生成项目资料包。','资料包',"openProjectPackageModal()",'good'));
  if(ms.length && !ms.some(m=>Number(m.id)===Number(summarySampleId))){summarySampleId=Number(ms[0].id)||0;localStorage.setItem('plm_v85_summary_sample_id',summarySampleId)}
  const scopedSample=ms.find(m=>Number(m.id)===Number(summarySampleId))||null;
  const scopedSampleId=scopedSample?Number(scopedSample.id):0;
  const scopedLabel=scopedSample?`当前样品：${modelLabel(scopedSample)}`:'当前项目全部样品';
  const viewSteps=scopedSampleId?ss.filter(s=>Number(s.model_id)===scopedSampleId):ss;
  const viewTests=scopedSampleId?ts.filter(t=>Number(t.model_id)===scopedSampleId):ts;
  const viewIssues=scopedSampleId?is.filter(i=>Number(i.model_id)===scopedSampleId):is;
  const viewOpenIssues=viewIssues.filter(i=>!closedIssue(i));
  const viewFiles=scopedSampleId?fs.filter(f=>Number(f.model_id)===scopedSampleId):fs;
  const viewCurrentSteps=viewSteps.filter(s=>String(s.status||'')==='进行中').sort((a,b)=>(Number(a.sort_order||0)-Number(b.sort_order||0))||(Number(a.id||0)-Number(b.id||0)));
  const viewLateSteps=viewSteps.filter(isStepLate);
  const viewAbnormalSteps=viewSteps.filter(s=>/异常|退回|重来|卡住/i.test(String(s.status||'')));
  const viewOpenSteps=viewSteps.filter(isStepOpen).sort((a,b)=>(Number(a.sort_order||0)-Number(b.sort_order||0))||(Number(a.id||0)-Number(b.id||0)));
  const viewTstat=summaryTestStats(viewTests);
  const viewFailedTests=viewTests.filter(t=>testResultValue(t)==='不通过');
  const viewRetestTests=viewTests.filter(t=>testStatusValue(t)==='待复测'||testRetestCount(t,ts)>0);
  const viewRunningTests=viewTests.filter(t=>testStatusValue(t)==='进行中');
  const viewPendingTests=viewTests.filter(t=>['未开始','待测'].includes(testStatusValue(t)));
  const activeSample=ms.find(m=>Number(m.id)===Number(summarySampleId)) || ms[0] || null;
  const sampleTabsHtml=ms.map(m=>{
    const mSteps=ss.filter(s=>Number(s.model_id)===Number(m.id));
    const mTests=ts.filter(t=>Number(t.model_id)===Number(m.id));
    const mIssues=openIssues.filter(x=>Number(x.model_id)===Number(m.id)).length;
    const name=modelLabel(m);
    return `<button class="sample-tab-btn ${Number(m.id)===Number(summarySampleId)?'active':''}" onclick="setSummarySample(${Number(m.id)||0})">${esc(name)} · 流程 ${mSteps.filter(s=>['已完成','跳过'].includes(String(s.status||''))).length}/${mSteps.length} · 测试 ${mTests.filter(t=>['通过','已完成'].includes(String(t.status||''))||String(t.result||'')==='通过').length}/${mTests.length}${mIssues?` · 问题 ${mIssues}`:''}</button>`;
  }).join('');
  const sampleDetailHtml=activeSample?(()=>{
    const m=activeSample;
    const mSteps=ss.filter(s=>Number(s.model_id)===Number(m.id));
    const mTests=ts.filter(t=>Number(t.model_id)===Number(m.id));
    const mFiles=fs.filter(f=>Number(f.model_id)===Number(m.id));
    const mIssuesAll=is.filter(x=>Number(x.model_id)===Number(m.id));
    const mIssuesOpen=mIssuesAll.filter(x=>!['已关闭','关闭','完成','已解决'].includes(String(x.status||'')));
    const flowDone=mSteps.filter(s=>['已完成','跳过'].includes(String(s.status||''))).length;
    const testDone=mTests.filter(t=>['通过','已完成'].includes(String(t.status||''))||String(t.result||'')==='通过').length;
    const flowPct=pctMini(flowDone,mSteps.length);
    const testPct=pctMini(testDone,mTests.length);
    const sizeText=[m.opening_size?('开孔 '+m.opening_size):'',m.diameter?('直径 '+m.diameter):'',m.length_mm||m.width_mm||m.height_mm?([m.length_mm,m.width_mm,m.height_mm].filter(Boolean).join('*')):''].filter(Boolean).join(' ｜ ')||'-';
    const kv=(k,v)=>`<div class="sample-kv"><span>${esc(k)}</span><b title="${esc(v||'-')}">${esc(v||'-')}</b></div>`;
    const stepRows=[...mSteps].sort((a,b)=>(Number(a.sort_order||0)-Number(b.sort_order||0))||(Number(a.id||0)-Number(b.id||0))).slice(0,8).map(s=>`<tr><td>${esc(s.title||'步骤')}</td><td>${esc(s.status||'未开始')}</td><td>${esc(dateOnly(s.plan_end||s.plan_date)||'-')}</td></tr>`).join('')||'<tr><td colspan="3">暂无流程步骤</td></tr>';
    const testRows=[...mTests].sort((a,b)=>String(b.test_date||b.updated_at||b.created_at||'').localeCompare(String(a.test_date||a.updated_at||a.created_at||''))).slice(0,6).map(t=>`<tr><td>${esc(t.test_type||'测试')}</td><td>${esc(t.status||t.result||'-')}</td><td>${esc(t.test_conclusion||t.note||'-')}</td></tr>`).join('')||'<tr><td colspan="3">暂无测试记录</td></tr>';
    const issueRows=mIssuesAll.slice(0,5).map(i=>`<tr><td>${esc(i.title||'问题')}</td><td>${esc(i.status||'待处理')}</td><td>${esc(i.owner||i.severity||'-')}</td></tr>`).join('')||'<tr><td colspan="3">暂无问题</td></tr>';
    const fileRows=mFiles.slice(0,5).map(f=>`<tr><td>${esc(f.category||'文件')}</td><td>${fileChip(f)}</td><td>${esc(dateOnly(f.created_at)||'-')}</td></tr>`).join('')||'<tr><td colspan="3">暂无文件</td></tr>';
    return `<div class="sample-tab-panel"><div class="sample-tab-head"><div class="sample-tab-title"><b>${esc(modelLabel(m))}</b><div class="hint">${esc(m.model||m.naming_model_no||'-')} ｜ ${esc(m.power||'-')} ｜ ${esc(m.beam||'-')} ｜ ${esc(m.cct||'-')} ｜ ${esc(m.sample_version||'V1')}</div></div><div class="sample-tab-actions"><button class="btn small" onclick="flowModelId=${Number(m.id)||0};gotoTab('flow')">开发流程</button><button class="btn small" onclick="gotoTab('tests')">测试中心</button><button class="btn small" onclick="gotoTab('issues')">问题闭环</button><button class="btn small" onclick="gotoTab('files')">文件资料</button><button class="btn small good" onclick="createBomFromModel(${Number(m.id)||0})">BOM</button></div></div><div class="mini-progress"><span>流程</span><div class="bar"><i style="width:${flowPct}%"></i></div><b>${flowDone}/${mSteps.length}</b></div><div class="mini-progress"><span>测试</span><div class="bar green"><i style="width:${testPct}%"></i></div><b>${testDone}/${mTests.length}</b></div><div class="tags" style="margin-top:10px"><span class="tag ${mIssuesOpen.length?'red':'green'}">未关闭问题 ${mIssuesOpen.length}</span><span class="tag blue">文件 ${mFiles.length}</span><span class="tag">数量 ${esc(m.qty||1)}</span>${statusTag(m.status||'开发中')}</div><div class="sample-detail-grid"><div class="sample-detail-box"><h4>规格 / 物料一览</h4><div class="sample-kv-grid">${kv('状态',m.status||'开发中')}${kv('型号',m.model||m.naming_model_no||'-')}${kv('版本',m.sample_version||'V1')}${kv('产品类别',m.product_category||m.naming_category||'-')}${kv('功率',m.power||'-')}${kv('角度',m.beam||'-')}${kv('色温',m.cct||'-')}${kv('尺寸/开孔',sizeText)}${kv('芯片',m.chip_name||m.chip_brand||'-')}${kv('电源',m.driver_name||m.driver_brand||'-')}${kv('光学',m.optical_name||m.optical_brand||'-')}${kv('附件',m.accessories_name||'-')}</div></div><div class="sample-detail-box"><h4>流程节点</h4><table class="sample-mini-table"><thead><tr><th>步骤</th><th>状态</th><th>计划</th></tr></thead><tbody>${stepRows}</tbody></table></div><div class="sample-detail-box"><h4>测试记录</h4><table class="sample-mini-table"><thead><tr><th>类型</th><th>状态</th><th>结论/说明</th></tr></thead><tbody>${testRows}</tbody></table></div><div class="sample-detail-box"><h4>问题 / 文件</h4><table class="sample-mini-table"><thead><tr><th>类型</th><th>名称</th><th>状态/时间</th></tr></thead><tbody>${issueRows}${fileRows}</tbody></table></div></div></div>`;
  })():'<div class="summary-empty">暂无样品，点击上方“管理样品”新增。</div>';
  const sampleHtml=ms.length?`<div class="sample-tabs-wrap"><div class="sample-tabs">${sampleTabsHtml}</div>${sampleDetailHtml}</div>`:'<div class="summary-empty">暂无样品，点击上方“样品管理”新增。</div>';

  const heroCards=[];
  if(isSummaryVisible('overview')) heroCards.push(`<div class="summary-main-card"><h3>项目一眼看清</h3><div class="hint">${esc(p.project_no||'-')} ｜ ${esc(p.customer||'未填客户')} ｜ ${esc(p.engineer||'-')} ｜ ${esc(p.due_date?('计划 '+dateOnly(p.due_date)):'未填计划日期')}</div><div class="summary-big"><div><b>${ms.length}</b><span>样品</span></div><div><b>${g.flowPct}%</b><span>工序进度</span></div><div><b>${g.testPct}%</b><span>测试进度</span></div><div><b>${openIssues.length}</b><span>未关闭问题</span></div></div><div class="project-progress-pair" style="margin-top:12px"><div class="project-mini-progress-row flow"><span>工序</span><div class="bar"><i style="width:${g.flowPct}%"></i></div><b>${g.flowPct}%</b></div><div class="project-mini-progress-row test"><span>测试</span><div class="bar green"><i style="width:${g.testPct}%"></i></div><b>${g.testPct}%</b></div></div></div>`);
  if(isSummaryVisible('actions')) heroCards.push(`<div class="summary-side-card"><h3>下一步建议</h3><div class="next-actions">${actions.slice(0,4).join('')}</div></div>`);
  const gridCards=[];
  if(isSummaryVisible('samples')) gridCards.push(`<div class="summary-card"><div class="sample-mini-head"><h3>样品进度</h3><button class="btn small" onclick="gotoTab('models')">管理样品</button></div>${sampleHtml}</div>`);
  if(isSummaryVisible('tests')) gridCards.push(`<div class="summary-card"><div class="sample-mini-head"><h3>测试与问题</h3><button class="btn small" onclick="gotoTab('tests')">进入测试</button></div><div class="tags">${Object.entries(typeCounts).map(([k,v])=>`<span class="tag blue">${esc(k)} ${v}</span>`).join('')||'<span class="tag">暂无测试</span>'}</div><div class="compact-table-wrap" style="margin-top:8px"><table class="compact-table"><thead><tr><th>事项</th><th>状态</th><th>说明</th></tr></thead><tbody>${[...failTests.slice(0,5).map(t=>`<tr><td>${esc(t.test_type||'测试')}</td><td>${esc(t.status||t.result||'-')}</td><td>${esc(t.test_conclusion||t.note||'-')}</td></tr>`),...openIssues.slice(0,5).map(i=>`<tr><td>${esc(i.title||'问题')}</td><td>${esc(i.status||'待处理')}</td><td>${esc(i.owner||'-')} ｜ ${esc(i.severity||'中')}</td></tr>`)].join('')||'<tr><td colspan="3">暂无异常测试和未关闭问题</td></tr>'}</tbody></table></div></div>`);
  if(isSummaryVisible('flow')) gridCards.push(`<div class="summary-card"><div class="sample-mini-head"><h3>进行中的流程</h3><button class="btn small" onclick="gotoTab('flow')">开发导航图</button></div><div class="compact-table-wrap"><table class="compact-table"><thead><tr><th>样品</th><th>步骤</th><th>状态</th><th>计划</th></tr></thead><tbody>${[...lateSteps,...doingSteps,...openSteps].slice(0,10).map(s=>{const m=ms.find(x=>Number(x.id)===Number(s.model_id));return `<tr><td>${esc(m?modelLabel(m):'公共')}</td><td>${esc(s.title||'步骤')}</td><td>${esc(s.status||'')}</td><td>${esc(dateOnly(s.plan_end||s.plan_date)||'-')}</td></tr>`}).join('')||'<tr><td colspan="4">暂无待推进流程</td></tr>'}</tbody></table></div></div>`);
  if(isSummaryVisible('files')) gridCards.push(`<div class="summary-card"><div class="sample-mini-head"><h3>最近资料 / 日志</h3><button class="btn small" onclick="gotoTab('files')">文件中心</button></div><div class="compact-table-wrap"><table class="compact-table"><thead><tr><th>类型</th><th>名称</th><th>时间</th></tr></thead><tbody>${recentFiles.map(f=>`<tr><td>${esc(f.category||'文件')}</td><td>${fileChip(f)}</td><td>${esc(dateOnly(f.created_at)||'-')}</td></tr>`).join('')||recentLogs.map(l=>`<tr><td>${esc(l.action||'日志')}</td><td>${esc(l.note||'-')}</td><td>${esc(dateOnly(l.created_at)||'-')}</td></tr>`).join('')||'<tr><td colspan="3">暂无资料和日志</td></tr>'}</tbody></table></div></div>`);
  const hiddenAll=!heroCards.length&&!gridCards.length;
  $('tabbody').innerHTML=`
    <div id="tab-summary">
      ${summaryVisibilityBar()}
      ${heroCards.length?`<div class="summary-hero ${heroCards.length===1?'single':''}">${heroCards.join('')}</div>`:''}
      ${gridCards.length?`<div class="summary-grid ${gridCards.length===1?'single':''}">${gridCards.join('')}</div>`:''}
      ${hiddenAll?'<div class="summary-empty">项目总览版块已全部隐藏。点击上方“全显示”恢复。</div>':''}
    </div>`;
}

function renderSummary(p){
  if(!p){$('tabbody').innerHTML='<div class="empty">请选择项目</div>';return}
  const ms=pModels(p.id), ts=pTests(p.id), fs=pFiles(p.id);
  const ss=steps.filter(s=>Number(s.project_id)===Number(p.id));
  const is=issues.filter(x=>Number(x.project_id)===Number(p.id));
  const flow=flowStatsForSteps(ss), tstat=summaryTestStats(ts), ds=rndAllDispatchSummary(Number(p.id));
  const openIssues=is.filter(x=>!closedIssue(x));
  const seriousIssues=openIssues.filter(seriousIssue);
  const failedTests=ts.filter(t=>testResultValue(t)==='不通过');
  const retestTests=ts.filter(t=>testStatusValue(t)==='待复测'||testRetestCount(t,ts)>0);
  const runningTests=ts.filter(t=>testStatusValue(t)==='进行中');
  const pendingTests=ts.filter(t=>['未开始','待测'].includes(testStatusValue(t)));
  const lateSteps=ss.filter(isStepLate);
  const abnormalSteps=ss.filter(s=>/异常|退回|重来|卡住/i.test(String(s.status||'')));
  const openSteps=ss.filter(isStepOpen).sort((a,b)=>(Number(a.sort_order||0)-Number(b.sort_order||0))||(Number(a.id||0)-Number(b.id||0)));
  const customerFiles=fs.filter(f=>Number(f.customer_visible)===1);
  const recentFiles=[...fs].sort((a,b)=>String(b.updated_at||b.created_at||'').localeCompare(String(a.updated_at||a.created_at||''))).slice(0,6);
  const recentLogs=logs.filter(l=>Number(l.project_id)===Number(p.id)).sort((a,b)=>String(b.created_at||'').localeCompare(String(a.created_at||''))).slice(0,8);
  const currentSteps=ss.filter(s=>String(s.status||'')==='进行中').sort((a,b)=>(Number(a.sort_order||0)-Number(b.sort_order||0))||(Number(a.id||0)-Number(b.id||0)));
  const primaryStep=currentSteps[0]||openSteps[0]||null;
  const primaryModel=primaryStep?ms.find(m=>Number(m.id)===Number(primaryStep.model_id)):null;
  const nextStep=primaryStep?(
    ss.filter(s=>Number(s.model_id)===Number(primaryStep.model_id)).sort((a,b)=>(Number(a.sort_order||0)-Number(b.sort_order||0))||(Number(a.id||0)-Number(b.id||0))).slice(
      ss.filter(s=>Number(s.model_id)===Number(primaryStep.model_id)).sort((a,b)=>(Number(a.sort_order||0)-Number(b.sort_order||0))||(Number(a.id||0)-Number(b.id||0))).findIndex(s=>Number(s.id)===Number(primaryStep.id))+1
    ).find(isStepOpen)
  ):openSteps[1]||null;
  if(ms.length && !ms.some(m=>Number(m.id)===Number(summarySampleId))){summarySampleId=Number(ms[0].id)||0;localStorage.setItem('plm_v85_summary_sample_id',summarySampleId)}
  const scopedSample=ms.find(m=>Number(m.id)===Number(summarySampleId))||null;
  const scopedSampleId=scopedSample?Number(scopedSample.id):0;
  const scopedLabel=scopedSample?`当前样品：${modelLabel(scopedSample)}`:'当前项目全部样品';
  const viewSteps=scopedSampleId?ss.filter(s=>Number(s.model_id)===scopedSampleId):ss;
  const viewTests=scopedSampleId?ts.filter(t=>Number(t.model_id)===scopedSampleId):ts;
  const viewIssues=scopedSampleId?is.filter(i=>Number(i.model_id)===scopedSampleId):is;
  const viewOpenIssues=viewIssues.filter(i=>!closedIssue(i));
  const viewFiles=scopedSampleId?fs.filter(f=>Number(f.model_id)===scopedSampleId):fs;
  const viewCurrentSteps=viewSteps.filter(s=>String(s.status||'')==='进行中').sort((a,b)=>(Number(a.sort_order||0)-Number(b.sort_order||0))||(Number(a.id||0)-Number(b.id||0)));
  const viewLateSteps=viewSteps.filter(isStepLate);
  const viewAbnormalSteps=viewSteps.filter(s=>/异常|退回|重来|卡住/i.test(String(s.status||'')));
  const viewOpenSteps=viewSteps.filter(isStepOpen).sort((a,b)=>(Number(a.sort_order||0)-Number(b.sort_order||0))||(Number(a.id||0)-Number(b.id||0)));
  const viewTstat=summaryTestStats(viewTests);
  const viewFailedTests=viewTests.filter(t=>testResultValue(t)==='不通过');
  const viewRetestTests=viewTests.filter(t=>testStatusValue(t)==='待复测'||testRetestCount(t,ts)>0);
  const viewRunningTests=viewTests.filter(t=>testStatusValue(t)==='进行中');
  const viewPendingTests=viewTests.filter(t=>['未开始','待测'].includes(testStatusValue(t)));
  const metric=(ico,name,val,cls='')=>`<div class="summary-ref-metric ${cls}"><div class="metric-ico">${esc(ico)}</div><div><span>${esc(name)}</span><b>${esc(val)}</b></div></div>`;
  const progressLine=(name,pct,desc,cls='')=>`<div><div class="summary-ref-progress-line ${cls}"><b>${esc(name)}</b><i><em style="width:${Math.max(0,Math.min(100,Number(pct||0)))}%"></em></i><span>${Number(pct||0)}%</span></div><div class="summary-ref-progress-note">${esc(desc)}</div></div>`;
  const statusLine=`当前推进：${primaryStep?esc(primaryStep.title||'流程节点'):(flow.total?'开发流程已完成':'暂无流程')} · 客户资料 ${customerFiles.length} 份`;
  const overview=isSummaryVisible('overview')?`<section class="summary-ref-panel"><div class="summary-ref-head"><h3>项目一眼看清</h3></div><div class="summary-ref-metrics">${metric('样','样品',ms.length)}${metric('流','流程',`${flow.done}/${flow.total}`)}${metric('测','测试',`${tstat.passed}/${tstat.total}`)}${metric('!','未关闭问题',openIssues.length,openIssues.length?'danger':'')}${metric('资','客户资料',customerFiles.length)}${metric('派','派工',`${ds.done}/${ds.total}`,ds.total&&ds.done>=ds.total?'good':'')}</div><div class="summary-ref-progress">${progressLine('开发流程',flow.pct,`${flow.done}/${flow.total} 步骤已完成`)}${progressLine('测试进度',tstat.pct,`${tstat.passed}/${tstat.total} 测试通过${tstat.failed?`，不通过 ${tstat.failed}`:''}${tstat.retest?`，待复测 ${tstat.retest}`:''}`,'green')}</div><div class="summary-ref-status">${statusLine}</div></section>`:'';
  const adviceRow=(ico,title,desc,click='',cls='')=>click?`<button class="summary-advice-row clickable ${cls}" onclick="${click}"><i>${esc(ico)}</i><div><b>${esc(title)}</b><span>${esc(desc)}</span></div></button>`:`<div class="summary-advice-row ${cls}"><i>${esc(ico)}</i><div><b>${esc(title)}</b><span>${esc(desc)}</span></div></div>`;
  const issueTarget=seriousIssues[0]||openIssues[0]||null;
  const testTarget=failedTests[0]||retestTests[0]||runningTests[0]||pendingTests[0]||null;
  const advice=[
    primaryStep?adviceRow('◎','当前步骤：'+(primaryStep.title||'流程节点'),`${primaryModel?modelLabel(primaryModel):'项目公共'} ｜ ${primaryStep.owner||primaryStep.owner_name||'未指定'}`,`summaryJump('flow',{model_id:${Number(primaryStep.model_id||0)},step_id:${Number(primaryStep.id)}})`,lateSteps.some(s=>Number(s.id)===Number(primaryStep.id))?'warn':''):adviceRow('◎','当前步骤',flow.total?'开发流程已完成':'暂无流程','',flow.total?'good':''),
    nextStep?adviceRow('→','下一步：'+(nextStep.title||'流程节点'),`${(ms.find(m=>Number(m.id)===Number(nextStep.model_id))?modelLabel(ms.find(m=>Number(m.id)===Number(nextStep.model_id))):'项目公共')} ｜ ${nextStep.status||'待开始'}`,`summaryJump('flow',{model_id:${Number(nextStep.model_id||0)},step_id:${Number(nextStep.id)}})`):adviceRow('→','下一步',flow.total?'暂无未完成步骤':'等待建立流程','',flow.total?'good':''),
    testTarget?adviceRow('测',failedTests.length?`${failedTests.length} 个测试不通过`:retestTests.length?`${retestTests.length} 个测试待复测`:pendingTests.length?`${pendingTests.length} 个测试未开始`:'测试进行中',`${testTarget.title||testTarget.test_type||'测试'} ｜ ${testStatusValue(testTarget)} ｜ ${testResultValue(testTarget)}`,`summaryJump('tests',{model_id:${Number(testTarget.model_id||0)},test_id:${Number(testTarget.id)}})`,failedTests.length?'danger':(retestTests.length?'warn':'')):adviceRow('测','测试提醒','暂无测试风险','',tstat.total?'good':''),
    issueTarget?adviceRow('问',`${openIssues.length} 个未关闭问题`,`${issueTarget.title||'问题'} ｜ ${issueTarget.severity||'中'} ｜ ${issueTarget.status||'待处理'}`,`summaryJump('issues',{model_id:${Number(issueTarget.model_id||0)},issue_id:${Number(issueTarget.id)}})`,seriousIssue(issueTarget)?'danger':'warn'):adviceRow('问','暂无未关闭问题','问题闭环当前正常','', 'good'),
    customerFiles.length?adviceRow('资',`客户资料已上传 ${customerFiles.length} 份`,'可进入文件中心或生成客户资料包',`summaryJump('files')`,'good'):adviceRow('资','客户资料待补充','暂无可发客户资料',`summaryJump('files')`,'warn')
  ].slice(0,5).join('');
  const actions=isSummaryVisible('actions')?`<section class="summary-ref-panel"><div class="summary-ref-head"><h3>下一步建议 / 风险提醒</h3></div><div class="summary-ref-advice">${advice}</div></section>`:'';
  const sampleCards=ms.map(m=>{
    const mSteps=ss.filter(s=>Number(s.model_id)===Number(m.id)), mf=flowStatsForSteps(mSteps), curNext=currentAndNextStep(mSteps);
    const mTests=ts.filter(t=>Number(t.model_id)===Number(m.id)), mt=summaryTestStats(mTests);
    const mIssues=openIssues.filter(i=>Number(i.model_id)===Number(m.id));
    const mFiles=fs.filter(f=>Number(f.model_id)===Number(m.id));
    const comp=componentReady(m), bom=projectHasBomForModel(m);
    const testText=mt.total?`通过 ${mt.passed}${mt.failed?` · 不通过 ${mt.failed}`:''}${mt.retest?` · 待复测 ${mt.retest}`:''}${mt.pending?` · 未开始 ${mt.pending}`:''}`:'0/0 未开始';
    const bomText=bom?'BOM 已生成':`BOM 未完成 · 元器件 ${comp.done}/${comp.total}`;
    const mid=Number(m.id), stepId=Number(curNext.current?.id||curNext.next?.id||0);
    return `<article class="summary-sample-ref-card ${mid===Number(summarySampleId)?'active':''}" role="button" tabindex="0" onclick="setSummarySample(${mid})" onkeydown="if(event.key==='Enter'||event.key===' '){event.preventDefault();setSummarySample(${mid})}"><div class="summary-sample-ref-head"><h4 title="${esc(modelLabel(m))}">${esc(modelLabel(m))}</h4><span class="summary-ver">${esc(m.sample_version||'V1.0')}</span></div><div class="summary-sample-model">型号：${esc(m.model||m.naming_model_no||m.sample_no||'-')}</div><div class="summary-sample-progress"><span>${esc(m.status||'开发中')}</span><i><em style="width:${mf.pct}%"></em></i><span>${mf.pct}%</span></div><div class="summary-sample-split"><div><b>当前步骤：${esc(curNext.current?curNext.current.title:'暂无进行中')}</b><b>下一步：${esc(curNext.next?curNext.next.title:(mf.total?'流程已完成':'暂无流程'))}</b></div><div><span>测试：${esc(testText)}</span><span>问题：${mIssues.length}</span><span>文件：${mFiles.length}</span><span>BOM：${esc(bomText)}</span></div></div><div class="summary-sample-actions"><button type="button" onclick="event.stopPropagation();summaryJump('models',{model_id:${mid}})">样品详情</button><button type="button" onclick="event.stopPropagation();summaryJump('flow',{model_id:${mid},step_id:${stepId}})">开发流程</button><button type="button" onclick="event.stopPropagation();summaryJump('tests',{model_id:${mid}})">测试</button><button type="button" onclick="event.stopPropagation();summaryJump('issues',{model_id:${mid}})">问题</button><button type="button" onclick="event.stopPropagation();summaryJump('files',{model_id:${mid}})">文件</button><button type="button" onclick="event.stopPropagation();createBomFromModel(${mid})">BOM</button></div></article>`;
  }).join('')||'<div class="summary-empty">当前项目暂未建立样品。</div>';
  const samples=isSummaryVisible('samples')?`<section class="summary-ref-panel"><div class="summary-ref-head"><h3>样品推进</h3><button class="btn small" onclick="summaryJump('models')">进入样品管理</button></div><div class="summary-sample-ref-grid">${sampleCards}</div></section>`:'';
  const focusSteps=[...viewCurrentSteps,...viewLateSteps,...viewAbnormalSteps,...viewOpenSteps].filter((v,i,a)=>a.findIndex(x=>Number(x.id)===Number(v.id))===i).slice(0,6);
  const flowRows=focusSteps.length?focusSteps.map((st,i)=>{const m=ms.find(x=>Number(x.id)===Number(st.model_id));return `<tr><td class="idx">${i+1}</td><td title="${esc(st.title||'流程节点')}">${esc(st.title||'流程节点')}</td><td title="${esc(m?modelLabel(m):'项目公共')}">${esc(m?modelLabel(m):'项目公共')}</td><td class="status-col">${esc(st.status||'待开始')}</td><td class="op"><button class="btn small" onclick="summaryJump('flow',{model_id:${Number(st.model_id||0)},step_id:${Number(st.id)}})">查看</button></td></tr>`}).join(''):`<tr><td colspan="5"><div class="summary-empty small">暂无待推进流程。</div></td></tr>`;
  const flowBlock=isSummaryVisible('flow')?`<section class="summary-ref-panel"><div class="summary-ref-head"><div><h3>当前开发流程</h3><span>${esc(scopedLabel)}</span></div><button class="btn small" onclick="summaryJump('flow'${scopedSampleId?`,{model_id:${scopedSampleId}}`:''})">开发导航图</button></div><div class="summary-ref-table-wrap"><table class="summary-ref-table"><thead><tr><th class="idx">序号</th><th>步骤</th><th>样品</th><th class="status-col">状态</th><th class="op">操作</th></tr></thead><tbody>${flowRows}</tbody></table></div></section>`:'';
  const focusTests=[...viewFailedTests,...viewRetestTests,...viewRunningTests,...viewPendingTests].filter((v,i,a)=>a.findIndex(x=>Number(x.id)===Number(v.id))===i).slice(0,5);
  const testRows=focusTests.length?focusTests.map(t=>`<tr><td title="${esc(t.title||t.test_type||'测试')}">${esc(t.title||t.test_type||'测试')}</td><td class="status-col">${esc(testStatusValue(t))}</td><td class="op"><button class="btn small" onclick="summaryJump('tests',{model_id:${Number(t.model_id||0)},test_id:${Number(t.id)}})">查看</button></td></tr>`).join(''):'<tr><td colspan="3"><div class="summary-empty small">暂无需关注测试。</div></td></tr>';
  const issueFocus=viewOpenIssues.slice().sort((a,b)=>(seriousIssue(b)-seriousIssue(a))||String(b.updated_at||b.created_at||'').localeCompare(String(a.updated_at||a.created_at||''))).slice(0,5);
  const issueRows=issueFocus.length?issueFocus.map(i=>`<tr><td title="${esc(i.title||'问题')}">${esc(i.title||'问题')}</td><td class="status-col">${esc(i.status||'待处理')}</td><td class="op"><button class="btn small" onclick="summaryJump('issues',{model_id:${Number(i.model_id||0)},issue_id:${Number(i.id)}})">查看</button></td></tr>`).join(''):'<tr><td colspan="3"><div class="summary-empty small">暂无未关闭问题。</div></td></tr>';
  const testsBlock=isSummaryVisible('tests')?`<section class="summary-ref-panel"><div class="summary-ref-head"><div><h3>测试与问题</h3><span>${esc(scopedLabel)}</span></div><button class="btn small" onclick="summaryJump('tests'${scopedSampleId?`,{model_id:${scopedSampleId}}`:''})">查看全部测试</button></div><div class="summary-ref-stat-strip"><span>总数 <b>${viewTstat.total}</b></span><span class="good">通过 <b>${viewTstat.passed}</b></span><span class="bad">不通过 <b>${viewTstat.failed}</b></span><span class="warn">待复测 <b>${viewTstat.retest}</b></span><span>未开始 <b>${viewTstat.pending}</b></span></div><div class="summary-focus-grid"><div><h4>测试关注</h4><div class="summary-ref-table-wrap"><table class="summary-ref-table"><tbody>${testRows}</tbody></table></div></div><div><h4>问题关注</h4><div class="summary-ref-table-wrap"><table class="summary-ref-table"><tbody>${issueRows}</tbody></table></div></div></div></section>`:'';
  const viewRecentFiles=[...viewFiles].sort((a,b)=>String(b.updated_at||b.created_at||'').localeCompare(String(a.updated_at||a.created_at||''))).slice(0,6);
  const fileRows=viewRecentFiles.length?viewRecentFiles.map(f=>{const type=(f.category||String(f.original_name||f.file_name||'').split('.').pop()||'文件');return `<tr><td title="${esc(f.title||f.original_name||f.file_name||'文件')}">${esc(f.title||f.original_name||f.file_name||'文件')}</td><td class="type-col"><span class="summary-file-type">${fileIcon(f)}${esc(type)}</span></td><td title="${esc(fileSourceLabel(fileSourceKey(f)))}">${esc(fileSourceLabel(fileSourceKey(f)))}</td><td class="time-col">${esc((f.updated_at||f.created_at||'').slice(0,16)||'-')}</td><td class="op"><button class="btn small" onclick="summaryJump('files',{file_id:${Number(f.id)}})">预览</button></td></tr>`}).join(''):`<tr><td colspan="5"><div class="summary-empty small">暂无最近资料。</div></td></tr>`;
  const filesBlock=isSummaryVisible('files')?`<section class="summary-ref-panel"><div class="summary-ref-head"><div><h3>最近资料</h3><span>${esc(scopedLabel)}</span></div><div class="actions"><button class="btn small" onclick="summaryJump('files'${scopedSampleId?`,{model_id:${scopedSampleId}}`:''})">文件中心</button><button class="btn small good" onclick="openCustomerPackageModal()">客户资料包</button></div></div><div class="summary-ref-table-wrap"><table class="summary-ref-table"><thead><tr><th>文件名</th><th class="type-col">类型</th><th>来源</th><th class="time-col">更新时间</th><th class="op">操作</th></tr></thead><tbody>${fileRows}</tbody></table></div></section>`:'';
  const logRows=recentLogs.length?recentLogs.map(l=>`<tr><td class="time-col">${esc((l.created_at||'').slice(5,16)||'-')}</td><td class="status-col">${esc(l.actor_name||l.user_name||l.operator_name||'-')}</td><td class="type-col">${esc(l.module||l.target_type||'-')}</td><td title="${esc(l.note||l.action||'')}">${esc(l.note||l.action||'-')}</td></tr>`).join(''):`<tr><td colspan="4"><div class="summary-empty small">暂无最近动态。</div></td></tr>`;
  const logsBlock=isSummaryVisible('logs')?`<section class="summary-ref-panel"><div class="summary-ref-head"><h3>最近动态</h3><button class="btn small" onclick="openPlmLogModal()">查看全部日志</button></div><div class="summary-ref-table-wrap"><table class="summary-ref-table"><thead><tr><th class="time-col">时间</th><th class="status-col">操作人</th><th class="type-col">模块</th><th>动态内容</th></tr></thead><tbody>${logRows}</tbody></table></div></section>`:'';
  const topRow=[overview,actions].filter(Boolean);
  const midRow=[flowBlock,testsBlock].filter(Boolean);
  const bottomRow=[filesBlock,logsBlock].filter(Boolean);
  $('tabbody').innerHTML=`<div id="tab-summary" class="summary-ref"><div class="summary-top-tools">${summaryVisibilityBar()}</div>${topRow.length?`<div class="summary-ref-row summary-ref-top ${topRow.length===1?'single':''}">${topRow.join('')}</div>`:''}${samples}${midRow.length?`<div class="summary-ref-row summary-ref-two ${midRow.length===1?'single':''}">${midRow.join('')}</div>`:''}${bottomRow.length?`<div class="summary-ref-row summary-ref-two ${bottomRow.length===1?'single':''}">${bottomRow.join('')}</div>`:''}</div>`;
}
async function openDispatch(){
  if(!guardPerm('create_dispatch','生成派工'))return;
  const p=cur();
  if(!p){toast('请先选择项目');return;}
  const ms=pModels(p.id)||[];
  const mainModel=ms[0]||{};
  await openPlmDispatchModal({kind:'project',sourceText:'PLM项目派工',project_id:p.id||0,model_id:Number(mainModel.id||0),step_id:0,projectName:p.name||'',customer:p.customer||'',modelName:p.model||p.series||currentModelName(mainModel)||'',stepTitle:'',title:'【PLM项目】'+(p.name||'项目派工'),projectText:[p.name||'',p.customer||'',p.model||p.series||''].filter(Boolean).join(' / '),task_date:new Date().toISOString().slice(0,10),due_date:dateOnly(p.due_date)||'',priority:'normal',reason:'项目派工事由：\n\n1. 请按 PLM 项目资料处理。\n2. 请在派工详情里反馈进度。\n3. 如有异常，请写明原因和下一步建议。',linked:{system:'PLM',type:'project',project_id:p.id||0,project_name:p.name||'',customer:p.customer||'',model:p.model||p.series||''},linked_url:'plm.php?project_id='+(p.id||0)});
}
async function openRecycleBin(){
  if(!guardPerm('view_recycle','查看回收站'))return;
  const r=await api('recycle_bin');
  if(!r.ok){toast(r.error||'无法打开回收站');return}
  const ps=r.projects||[], ms=r.models||[], ns=r.notifications||[];
  const html=`<div class="modal-mask" onclick="if(event.target===this)this.remove()"><div class="modal" style="width:min(1080px,96vw)"><div class="modal-head"><h3>PLM 回收站 / 站内信</h3><button class="btn" onclick="this.closest('.modal-mask').remove()">关闭</button></div><div class="modal-body"><div class="hint" style="margin-bottom:10px">项目和产品/样品删除后先进入回收站，管理员可还原。非管理员每天只能删除 1 个项目、1 个产品/样品。</div><div class="recycle-modal-grid"><div class="recycle-panel"><h3>已删除项目 ${ps.length}</h3>${ps.map(p=>`<div class="recycle-row"><div><b>${esc(p.name||'未命名项目')}</b><div class="hint">删除人：${esc(p.deleted_by_name||'-')} ｜ ${esc(p.deleted_at||'-')}</div><div class="hint">原因：${esc(p.delete_reason||'-')}</div></div><button class="btn small good" onclick="restoreProject(${p.id})">还原</button></div>`).join('')||'<div class="empty">暂无删除项目</div>'}</div><div class="recycle-panel"><h3>已删除产品/样品 ${ms.length}</h3>${ms.map(m=>`<div class="recycle-row"><div><b>${esc(m.name||m.model||'未命名样品')}</b><div class="hint">项目：${esc(m.project_name||m.project_id||'-')} ｜ 删除人：${esc(m.deleted_by_name||'-')} ｜ ${esc(m.deleted_at||'-')}</div><div class="hint">原因：${esc(m.delete_reason||'-')}</div></div><button class="btn small good" onclick="restoreModel(${m.id})">还原</button></div>`).join('')||'<div class="empty">暂无删除产品/样品</div>'}</div></div><div class="recycle-panel" style="margin-top:12px"><div class="actions" style="justify-content:space-between"><h3>站内信 ${ns.filter(x=>Number(x.is_read||0)===0).length} 未读</h3><button class="btn" onclick="markPlmNotificationsRead()">全部已读</button></div>${ns.map(n=>`<div class="recycle-row"><div><b>${esc(n.title||'通知')}</b><div class="hint">${esc(n.created_at||'-')} ｜ ${Number(n.is_read||0)?'已读':'未读'}</div><div class="hint">${esc(n.message||'')}</div></div></div>`).join('')||'<div class="empty">暂无站内信</div>'}</div></div></div></div>`;
  document.body.insertAdjacentHTML('beforeend',html);
}
async function openPlmNotifications(){await openRecycleBin()}
async function restoreProject(id){const r=await api('restore_project',{id});toast(r.ok?'项目已还原':r.error);document.querySelector('.modal-mask')?.remove();await load();await openRecycleBin()}
async function restoreModel(id){const r=await api('restore_model',{id});toast(r.ok?'产品/样品已还原':r.error);document.querySelector('.modal-mask')?.remove();await load();await openRecycleBin()}
async function markPlmNotificationsRead(){const r=await api('mark_notifications_read',{});toast(r.ok?'站内信已标记已读':r.error);document.querySelector('.modal-mask')?.remove();await load();await openRecycleBin()}

function allProjectImageCell(p){
  const name=String(p.name||p.customer||'项');
  if(p.image_path){return `<img class="all-project-mini-img" src="${esc(p.image_path)}" onerror="this.outerHTML='<div class=&quot;all-project-mini-img no&quot;>${esc(name.slice(0,1)||'项')}</div>'">`;}
  return `<div class="all-project-mini-img no">${esc(name.slice(0,1)||'项')}</div>`;
}
function allProjectFilterValues(){
  return {
    q:($('ap_q')?.value||'').trim().toLowerCase(),
    engineer:$('ap_engineer')?.value||'',
    customer:$('ap_customer')?.value||'',
    source:$('ap_source')?.value||'',
    priority:$('ap_priority')?.value||'',
    status:$('ap_status')?.value||'',
    hasImage:$('ap_image')?.value||'',
    hasFile:$('ap_file')?.value||'',
    hasDispatch:$('ap_dispatch')?.value||'',
    dueStart:$('ap_due_start')?.value||'',
    dueEnd:$('ap_due_end')?.value||'',
    updatedStart:$('ap_updated_start')?.value||'',
    updatedEnd:$('ap_updated_end')?.value||'',
    sort:$('ap_sort')?.value||'updated_desc',
    limit:Number($('ap_limit')?.value||200)
  };
}
function allProjectFilteredList(){
  const f=allProjectFilterValues();
  let arr=projects.filter(p=>{
    const g=prog(p.id); const ps=projectDispatchSummary(p.id);
    const hay=[p.project_no,p.name,p.customer,p.engineer,p.series,p.model,p.product_type,p.source,p.priority,p.status,p.remark].join(' ').toLowerCase();
    const due=dateOnly(p.due_date); const upd=dateOnly(p.updated_at);
    return (!f.q||hay.includes(f.q))
      && (!f.engineer||p.engineer===f.engineer)
      && (!f.customer||p.customer===f.customer)
      && (!f.source||p.source===f.source)
      && (!f.priority||p.priority===f.priority)
      && (!f.status||p.status===f.status)
      && (!f.hasImage||(f.hasImage==='yes'?!!p.image_path:!p.image_path))
      && (!f.hasFile||(f.hasFile==='yes'?g.files>0:g.files===0))
      && (!f.hasDispatch||(f.hasDispatch==='yes'?ps.total>0:ps.total===0))
      && (!f.dueStart||due>=f.dueStart)
      && (!f.dueEnd||due<=f.dueEnd)
      && (!f.updatedStart||upd>=f.updatedStart)
      && (!f.updatedEnd||upd<=f.updatedEnd);
  });
  const byDate=(v)=>v?String(v):'';
  arr.sort((a,b)=>{
    const ga=prog(a.id), gb=prog(b.id);
    if(f.sort==='name_asc')return String(a.name||'').localeCompare(String(b.name||''),'zh-Hans-CN');
    if(f.sort==='name_desc')return String(b.name||'').localeCompare(String(a.name||''),'zh-Hans-CN');
    if(f.sort==='due_asc')return byDate(a.due_date).localeCompare(byDate(b.due_date));
    if(f.sort==='due_desc')return byDate(b.due_date).localeCompare(byDate(a.due_date));
    if(f.sort==='flow_desc')return (gb.flowPct-ga.flowPct)||Number(b.id)-Number(a.id);
    if(f.sort==='test_desc')return (gb.testPct-ga.testPct)||Number(b.id)-Number(a.id);
    if(f.sort==='created_desc')return String(b.created_at||'').localeCompare(String(a.created_at||''));
    if(f.sort==='created_asc')return String(a.created_at||'').localeCompare(String(b.created_at||''));
    return String(b.updated_at||'').localeCompare(String(a.updated_at||''));
  });
  return {list:arr.slice(0,Math.max(20,Math.min(1000,f.limit||200))),total:arr.length,filters:f};
}
function openAllProjectsModal(){
  const host=$('modalHost')||document.body.appendChild(Object.assign(document.createElement('div'),{id:'modalHost'}));
  const engineers=uniq(projects.map(p=>p.engineer));
  const customers=uniq(projects.map(p=>p.customer));
  const sources=uniq(projects.map(p=>p.source));
  const priorities=uniq(projects.map(p=>p.priority));
  const statuses=uniq(projects.map(p=>p.status));
  host.innerHTML=`<div class="modal-mask all-project-modal" onclick="if(event.target===this)this.remove()"><div class="modal"><div class="modal-head"><div><h3>所有项目列表</h3><div class="hint">全功能筛选项目，可按客户、工程师、状态、日期、图片、文件、派工进度筛选。</div></div><button class="btn" onclick="this.closest('.modal-mask').remove()">关闭</button></div><div class="modal-body"><div class="all-project-filter-grid"><div class="field"><label>关键词</label><input id="ap_q" placeholder="项目号 / 项目名 / 客户 / 系列 / 型号 / 备注" oninput="renderAllProjectsModal()"></div><div class="field"><label>工程师</label><select id="ap_engineer" onchange="renderAllProjectsModal()"><option value="">全部工程师</option>${engineers.map(x=>`<option>${esc(x)}</option>`).join('')}</select></div><div class="field"><label>客户</label><select id="ap_customer" onchange="renderAllProjectsModal()"><option value="">全部客户</option>${customers.map(x=>`<option>${esc(x)}</option>`).join('')}</select></div><div class="field"><label>来源</label><select id="ap_source" onchange="renderAllProjectsModal()"><option value="">全部来源</option>${sources.map(x=>`<option>${esc(x)}</option>`).join('')}</select></div><div class="field"><label>优先级</label><select id="ap_priority" onchange="renderAllProjectsModal()"><option value="">全部优先级</option>${priorities.map(x=>`<option>${esc(x)}</option>`).join('')}</select></div><div class="field"><label>状态</label><select id="ap_status" onchange="renderAllProjectsModal()"><option value="">全部状态</option>${statuses.map(x=>`<option>${esc(x)}</option>`).join('')}</select></div><div class="field"><label>项目图</label><select id="ap_image" onchange="renderAllProjectsModal()"><option value="">全部</option><option value="yes">有项目图</option><option value="no">无项目图</option></select></div><div class="field"><label>文件资料</label><select id="ap_file" onchange="renderAllProjectsModal()"><option value="">全部</option><option value="yes">有文件</option><option value="no">无文件</option></select></div><div class="field"><label>项目派工</label><select id="ap_dispatch" onchange="renderAllProjectsModal()"><option value="">全部</option><option value="yes">有项目派工</option><option value="no">无项目派工</option></select></div><div class="field"><label>计划开始</label><input id="ap_due_start" type="date" onchange="renderAllProjectsModal()"></div><div class="field"><label>计划结束</label><input id="ap_due_end" type="date" onchange="renderAllProjectsModal()"></div><div class="field"><label>更新开始</label><input id="ap_updated_start" type="date" onchange="renderAllProjectsModal()"></div><div class="field"><label>更新结束</label><input id="ap_updated_end" type="date" onchange="renderAllProjectsModal()"></div><div class="field"><label>排序</label><select id="ap_sort" onchange="renderAllProjectsModal()"><option value="updated_desc">最近更新</option><option value="created_desc">最新创建</option><option value="created_asc">最早创建</option><option value="due_asc">计划日期升序</option><option value="due_desc">计划日期降序</option><option value="name_asc">项目名升序</option><option value="name_desc">项目名降序</option><option value="flow_desc">流程进度最高</option><option value="test_desc">测试进度最高</option></select></div><div class="field"><label>显示数量</label><select id="ap_limit" onchange="renderAllProjectsModal()"><option value="50">50</option><option value="100">100</option><option value="200" selected>200</option><option value="500">500</option><option value="1000">1000</option></select></div></div><div class="all-project-modal-actions"><button class="all-project-toolbar-btn" onclick="renderAllProjectsModal()">筛选</button><button class="btn" onclick="resetAllProjectsModal()">清空筛选</button><button class="btn good" onclick="exportAllProjectsModalCsv()">导出当前结果 CSV</button><span id="ap_summary" class="hint">准备筛选</span></div><div id="allProjectResults" class="all-project-result-wrap"><div class="empty">正在加载项目列表...</div></div></div></div></div>`;
  renderAllProjectsModal();
}
function resetAllProjectsModal(){
  ['ap_q','ap_due_start','ap_due_end','ap_updated_start','ap_updated_end'].forEach(id=>{if($(id))$(id).value=''});
  ['ap_engineer','ap_customer','ap_source','ap_priority','ap_status','ap_image','ap_file','ap_dispatch'].forEach(id=>{if($(id))$(id).value=''});
  if($('ap_sort'))$('ap_sort').value='updated_desc'; if($('ap_limit'))$('ap_limit').value='200';
  renderAllProjectsModal();
}
function renderAllProjectsModal(){
  const box=$('allProjectResults'); if(!box)return;
  const r=allProjectFilteredList();
  if($('ap_summary'))$('ap_summary').textContent=`共 ${r.total} 个符合条件，当前显示 ${r.list.length} 个`;
  if(!r.list.length){box.innerHTML='<div class="empty">没有符合条件的项目</div>';return;}
  box.innerHTML=`<table class="all-project-table"><thead><tr><th>图</th><th>项目</th><th>客户/工程师</th><th>状态</th><th>优先级</th><th>来源</th><th>样品</th><th>流程</th><th>测试</th><th>文件</th><th>项目派工</th><th>计划</th><th>更新</th><th>操作</th></tr></thead><tbody>${r.list.map(p=>{const g=prog(p.id);const ps=projectDispatchSummary(p.id);return `<tr><td>${allProjectImageCell(p)}</td><td><div class="all-project-title">${esc(p.name||'未命名项目')}</div><div class="all-project-sub">${esc(p.project_no||'-')} ｜ ${esc(p.series||'')} ${esc(p.model||'')} ${esc(p.product_type||'')}</div></td><td><b>${esc(p.customer||'-')}</b><div class="all-project-sub">工程师：${esc(p.engineer||'-')}</div></td><td>${statusTag(p.status)}</td><td><span class="all-project-stat-pill warn">${esc(p.priority||'-')}</span></td><td>${esc(p.source||'-')}</td><td><span class="all-project-stat-pill blue">${g.models}</span></td><td><span class="all-project-stat-pill ${g.flowPct>=100?'good':'blue'}">${g.flowDone}/${g.flowTotal} · ${g.flowPct}%</span></td><td><span class="all-project-stat-pill ${g.testPct>=100?'good':'blue'}">${g.testDone}/${g.tests} · ${g.testPct}%</span></td><td><span class="all-project-stat-pill">${g.files}</span></td><td><span class="all-project-stat-pill ${ps.total?'good':''}">${ps.total?ps.done+'/'+ps.total:'无'}</span></td><td>${esc(dateOnly(p.due_date)||'-')}</td><td>${esc(dateOnly(p.updated_at)||'-')}</td><td><button class="btn small primary" onclick="selectProjectFromAllModal(${Number(p.id)||0})">打开</button></td></tr>`}).join('')}</tbody></table>`;
}
function selectProjectFromAllModal(id){
  selectedId=Number(id)||0; localStorage.setItem('plm_v85_selected',selectedId);
  document.querySelector('.all-project-modal')?.remove();
  render();
}
function exportAllProjectsModalCsv(){
  const r=allProjectFilteredList();
  const rows=[['项目ID','项目号','项目名称','客户','工程师','系列','型号','产品类型','状态','优先级','来源','样品数','流程完成','流程总数','测试完成','测试总数','文件数','项目派工完成','项目派工总数','计划日期','更新时间']];
  r.list.forEach(p=>{const g=prog(p.id),ps=projectDispatchSummary(p.id);rows.push([p.id,p.project_no||'',p.name||'',p.customer||'',p.engineer||'',p.series||'',p.model||'',p.product_type||'',p.status||'',p.priority||'',p.source||'',g.models,g.flowDone,g.flowTotal,g.testDone,g.tests,g.files,ps.done,ps.total,dateOnly(p.due_date)||'',p.updated_at||'']);});
  const csv='\ufeff'+rows.map(row=>row.map(v=>'"'+String(v??'').replaceAll('"','""')+'"').join(',')).join('\n');
  const blob=new Blob([csv],{type:'text/csv;charset=utf-8'}); const a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='plm_projects_'+new Date().toISOString().slice(0,10)+'.csv';a.click();setTimeout(()=>URL.revokeObjectURL(a.href),1000);
}


// ===== PLM V8.5.51 研发看板 =====
let rndDashboardActive='overdue';
function rndToday(){return new Date(new Date().toISOString().slice(0,10)+'T00:00:00');}
function rndDate(v){const d=dateOnly(v);return d?new Date(d+'T00:00:00'):null;}
function rndAddDays(d,n){const x=new Date(d);x.setDate(x.getDate()+n);return x;}
function rndNotFinishedProject(p){const s=String(p.status||'');return !['已完成','已取消','取消','关闭'].includes(s);}
function rndIsClosedIssue(x){const s=String(x.status||'');return ['已关闭','关闭','已完成','已解决','解决','通过'].includes(s)||!!x.closed_at;}
function rndIsFailedTest(t){const s=String(t.status||''), r=String(t.result||'');return ['不通过','NG','FAIL','需整改','待复测'].some(k=>s.includes(k)||r.includes(k));}
function rndIsPassTest(t){const s=String(t.status||''), r=String(t.result||'');return ['通过','PASS','合格','已完成'].some(k=>s.includes(k)||r.includes(k));}
function rndAllDispatchSummary(pid){const arr=dispatchLinks.filter(x=>Number(x.project_id)===Number(pid));const done=arr.filter(dispatchDone).length;return{total:arr.length,done,pct:arr.length?Math.round(done/arr.length*100):0};}
function rndProjectHasBom(pid){
  return logs.some(l=>Number(l.project_id)===Number(pid)&&(String(l.target_type||'').toLowerCase()==='bom'||String(l.action||'').toUpperCase().includes('BOM')||String(l.note||'').toUpperCase().includes('BOM项目UID')));
}
function rndProjectWarnText(p){
  const pid=Number(p.id), g=prog(pid), ds=rndAllDispatchSummary(pid), badT=pTests(pid).filter(rndIsFailedTest).length, openI=issues.filter(x=>Number(x.project_id)===pid&&!rndIsClosedIssue(x)).length;
  const arr=[]; if(rndDate(p.due_date)&&rndDate(p.due_date)<rndToday()&&rndNotFinishedProject(p))arr.push('逾期'); if(badT)arr.push('测试异常 '+badT); if(openI)arr.push('问题未关 '+openI); if(ds.total&&ds.done<ds.total)arr.push('派工 '+ds.done+'/'+ds.total); if(g.flowTotal&&g.flowDone<g.flowTotal)arr.push('流程 '+g.flowDone+'/'+g.flowTotal); return arr.join(' ｜ ')||'正常';
}
function rndDashboardData(){
  const today=rndToday(), weekEnd=rndAddDays(today,7), ym=new Date().toISOString().slice(0,7);
  const map={
    dev:{title:'开发中项目',desc:'状态为开发中/测试中/未开始，未关闭',color:'blue',list:[]},
    dueweek:{title:'本周到期',desc:'计划日期在未来 7 天内',color:'orange',list:[]},
    overdue:{title:'逾期项目',desc:'计划日期小于今天，且未完成',color:'red',list:[]},
    failedtest:{title:'测试不通过',desc:'测试结果不通过、需整改或待复测',color:'red',list:[]},
    openissue:{title:'问题未关闭',desc:'问题闭环仍待处理',color:'orange',list:[]},
    nobom:{title:'BOM未生成',desc:'有样品但未发现 BOM 生成记录',color:'purple',list:[]},
    dispatch:{title:'派工未完成',desc:'项目/流程派工未全部完成',color:'blue',list:[]},
    customer:{title:'等待客户确认',desc:'状态或备注包含客户确认/待确认',color:'purple',list:[]},
    donemonth:{title:'本月完成',desc:'本月更新且状态已完成',color:'green',list:[]}
  };
  projects.forEach(p=>{
    const pid=Number(p.id), due=rndDate(p.due_date), status=String(p.status||''), remark=String(p.remark||'');
    const pm=pModels(pid), pt=pTests(pid), pi=issues.filter(x=>Number(x.project_id)===pid), ds=rndAllDispatchSummary(pid);
    if(rndNotFinishedProject(p) && ['开发中','测试中','未开始','暂停'].some(k=>status.includes(k)||(!status&&k==='开发中'))) map.dev.list.push(p);
    if(due && due>=today && due<=weekEnd && rndNotFinishedProject(p)) map.dueweek.list.push(p);
    if(due && due<today && rndNotFinishedProject(p)) map.overdue.list.push(p);
    if(pt.some(rndIsFailedTest)) map.failedtest.list.push(p);
    if(pi.some(x=>!rndIsClosedIssue(x))) map.openissue.list.push(p);
    if(pm.length && !rndProjectHasBom(pid)) map.nobom.list.push(p);
    if(ds.total && ds.done<ds.total) map.dispatch.list.push(p);
    if(/客户确认|待确认|客户待确认|客户要求修改/.test(status+remark)) map.customer.list.push(p);
    if(status==='已完成' && String(p.updated_at||'').slice(0,7)===ym) map.donemonth.list.push(p);
  });
  // 默认把最紧急的放前面
  Object.values(map).forEach(g=>g.list.sort((a,b)=>String(a.due_date||'9999').localeCompare(String(b.due_date||'9999'))||String(b.updated_at||'').localeCompare(String(a.updated_at||''))));
  return map;
}
function openRndDashboardModal(active=''){
  if(!guardPerm('view_dashboard','查看研发看板'))return;
  if(active)rndDashboardActive=active;
  const host=$('modalHost')||document.body.appendChild(Object.assign(document.createElement('div'),{id:'modalHost'}));
  const data=rndDashboardData();
  host.innerHTML=`<div class="modal-mask rnd-modal" onclick="if(event.target===this)this.remove()"><div class="modal"><div class="modal-head"><div><h3>研发看板</h3><div class="hint">老板视图：集中查看逾期、测试异常、问题未关闭、BOM 未生成、派工未完成等卡点。</div></div><button class="btn" onclick="this.closest('.modal-mask').remove()">关闭</button></div><div class="modal-body"><div class="rnd-board-grid">${Object.entries(data).map(([k,g])=>`<div class="rnd-card ${esc(g.color)} ${rndDashboardActive===k?'active':''}" onclick="rndDashboardActive='${k}';renderRndDashboardList()"><b>${g.list.length}</b><span>${esc(g.title)}</span><small>${esc(g.desc)}</small></div>`).join('')}</div><div class="rnd-tools"><div class="rnd-tools-left"><input id="rnd_q" placeholder="搜索项目 / 客户 / 工程师 / 型号" oninput="renderRndDashboardList()"><select id="rnd_engineer" onchange="renderRndDashboardList()"><option value="">全部工程师</option>${uniq(projects.map(p=>p.engineer)).map(x=>`<option>${esc(x)}</option>`).join('')}</select><select id="rnd_priority" onchange="renderRndDashboardList()"><option value="">全部优先级</option>${uniq(projects.map(p=>p.priority)).map(x=>`<option>${esc(x)}</option>`).join('')}</select></div><div class="actions"><button class="btn" onclick="renderRndDashboardList()">刷新</button><button class="btn good" onclick="exportRndDashboardCsv()">导出当前 CSV</button></div></div><div id="rnd_summary" class="hint" style="margin:6px 0 10px">准备加载</div><div id="rnd_result" class="rnd-table-wrap"><div class="empty">正在加载研发看板...</div></div></div></div></div>`;
  renderRndDashboardList();
}
function rndFilteredList(){
  const data=rndDashboardData(), group=data[rndDashboardActive]||data.overdue;
  const q=($('rnd_q')?.value||'').toLowerCase().trim(), eng=$('rnd_engineer')?.value||'', pri=$('rnd_priority')?.value||'';
  let arr=[...group.list];
  if(q)arr=arr.filter(p=>[p.project_no,p.name,p.customer,p.engineer,p.series,p.model,p.product_type,p.remark].join(' ').toLowerCase().includes(q));
  if(eng)arr=arr.filter(p=>String(p.engineer||'')===eng);
  if(pri)arr=arr.filter(p=>String(p.priority||'')===pri);
  return {group,list:arr};
}
function renderRndDashboardList(){
  const box=$('rnd_result'); if(!box)return;
  document.querySelectorAll('.rnd-card').forEach(c=>c.classList.remove('active'));
  const keys=Object.keys(rndDashboardData()); const idx=keys.indexOf(rndDashboardActive); if(idx>=0)document.querySelectorAll('.rnd-card')[idx]?.classList.add('active');
  const r=rndFilteredList(); if($('rnd_summary'))$('rnd_summary').textContent=`${r.group.title}：${r.list.length} 个项目`;
  if(!r.list.length){box.innerHTML='<div class="empty">当前分类没有项目</div>';return;}
  box.innerHTML=`<table class="rnd-table"><thead><tr><th>项目</th><th>客户/工程师</th><th>状态</th><th>流程</th><th>测试</th><th>问题</th><th>派工</th><th>BOM</th><th>计划</th><th>卡点说明</th><th>操作</th></tr></thead><tbody>${r.list.map(p=>{const pid=Number(p.id),g=prog(pid),ts=pTests(pid),bad=ts.filter(rndIsFailedTest).length,openI=issues.filter(x=>Number(x.project_id)===pid&&!rndIsClosedIssue(x)).length,ds=rndAllDispatchSummary(pid),bom=rndProjectHasBom(pid);return `<tr><td><div class="rnd-project-title">${esc(p.name||'未命名项目')}</div><div class="rnd-sub">${esc(p.project_no||'-')} ｜ ${esc(p.series||'')} ${esc(p.model||'')} ${esc(p.product_type||'')}</div></td><td><b>${esc(p.customer||'-')}</b><div class="rnd-sub">工程师：${esc(p.engineer||'-')}</div></td><td>${statusTag(p.status)}</td><td><span class="rnd-pill blue">${g.flowDone}/${g.flowTotal} · ${g.flowPct}%</span><div class="rnd-mini-bar"><i style="width:${g.flowPct}%"></i></div></td><td><span class="rnd-pill ${bad?'red':(g.testPct>=100?'green':'blue')}">${g.testDone}/${g.tests}${bad?' · 异常'+bad:''}</span><div class="rnd-mini-bar green"><i style="width:${g.testPct}%"></i></div></td><td><span class="rnd-pill ${openI?'orange':'green'}">${openI?openI+' 未关':'正常'}</span></td><td><span class="rnd-pill ${ds.total&&ds.done<ds.total?'orange':(ds.total?'green':'')}">${ds.total?ds.done+'/'+ds.total:'无'}</span></td><td><span class="rnd-pill ${bom?'green':'purple'}">${bom?'已生成':'未生成'}</span></td><td>${esc(dateOnly(p.due_date)||'-')}</td><td><span class="rnd-pill ${rndProjectWarnText(p).includes('逾期')||bad?'red':'blue'}">${esc(rndProjectWarnText(p))}</span></td><td><div class="actions"><button class="btn small primary" onclick="selectProjectFromRnd(${pid},'basic')">打开</button><button class="btn small" onclick="selectProjectFromRnd(${pid},'tests')">测试</button><button class="btn small" onclick="selectProjectFromRnd(${pid},'issues')">问题</button></div></td></tr>`}).join('')}</tbody></table>`;
}
function selectProjectFromRnd(id,nextTab='basic'){
  selectedId=Number(id)||0; tab=nextTab||'basic'; localStorage.setItem('plm_v85_selected',selectedId); localStorage.setItem('plm_v85_tab',tab);
  document.querySelector('.rnd-modal')?.remove(); render();
}
function exportRndDashboardCsv(){
  const r=rndFilteredList();
  const rows=[['分类','项目ID','项目号','项目名称','客户','工程师','状态','优先级','流程完成','流程总数','测试通过','测试总数','测试异常数','未关闭问题','派工完成','派工总数','BOM状态','计划日期','卡点说明']];
  r.list.forEach(p=>{const pid=Number(p.id),g=prog(pid),bad=pTests(pid).filter(rndIsFailedTest).length,openI=issues.filter(x=>Number(x.project_id)===pid&&!rndIsClosedIssue(x)).length,ds=rndAllDispatchSummary(pid);rows.push([r.group.title,p.id,p.project_no||'',p.name||'',p.customer||'',p.engineer||'',p.status||'',p.priority||'',g.flowDone,g.flowTotal,g.testDone,g.tests,bad,openI,ds.done,ds.total,rndProjectHasBom(pid)?'已生成':'未生成',dateOnly(p.due_date)||'',rndProjectWarnText(p)]);});
  const csv='\ufeff'+rows.map(row=>row.map(v=>'"'+String(v??'').replaceAll('"','""')+'"').join(',')).join('\n');
  const blob=new Blob([csv],{type:'text/csv;charset=utf-8'}); const a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='plm_rnd_dashboard_'+new Date().toISOString().slice(0,10)+'.csv';a.click();setTimeout(()=>URL.revokeObjectURL(a.href),1000);
}


async function openPlmOnlineModal(){
  const host=$('modalHost')||document.body.appendChild(Object.assign(document.createElement('div'),{id:'modalHost'}));
  host.innerHTML=`<div class="modal-mask" onclick="if(event.target===this)closeModal()"><div class="modal" style="width:min(920px,96vw)"><div class="modal-head"><div><h3>谁在线</h3><div class="hint">显示最近 10 分钟访问 PLM 的账号。页面会自动刷新当前在线状态。</div></div><div class="actions"><button class="btn small" onclick="refreshPlmOnlineUsers()">刷新</button><button class="btn small" onclick="closeModal()">关闭</button></div></div><div class="modal-body"><div id="plmOnlineBody"><div class="empty">正在读取在线人员...</div></div></div></div></div>`;
  await refreshPlmOnlineUsers();
}
async function refreshPlmOnlineUsers(){
  const r=await api('plm_online_users',{minutes:10});
  const box=$('plmOnlineBody');
  if(!box)return;
  if(!r.ok){box.innerHTML=`<div class="empty dangerText">${esc(r.error||'读取失败')}</div>`;return;}
  const users=r.users||[]; plmOnlineCount=Number(r.online_count||users.length||0); renderTopInfo();
  box.innerHTML=`<div class="plm-online-grid">${users.map(u=>`<div class="plm-online-card"><b>${esc(u.user_name||u.username||'未识别账号')}</b><span>账号：${esc(u.username||'-')}</span><span>角色：${esc(u.user_role||'-')}</span><span>最后活动：${esc(u.last_seen||'-')}（${esc(u.idle_label||'')}）</span><span>页面：${esc(u.page||'PLM')}</span></div>`).join('')||'<div class="empty">暂无在线人员</div>'}</div>`;
}
async function plmOnlinePing(){
  const r=await api('plm_online_ping',{});
  if(r&&r.ok){plmOnlineCount=Number(r.online_count||0);renderTopInfo();}
}
async function openPlmLogModal(){
  if(!guardPerm('view_logs','查看操作日志'))return;
  const host=$('modalHost')||document.body.appendChild(Object.assign(document.createElement('div'),{id:'modalHost'}));
  const today=new Date().toISOString().slice(0,10);
  host.innerHTML=`<div class="modal-mask" onclick="if(event.target===this)closeModal()"><div class="modal" style="width:min(1180px,97vw)"><div class="modal-head"><div><h3>PLM 操作日志</h3><div class="hint">按人员、项目、动作、日期查看操作记录，可导出 CSV。</div></div><div class="actions"><button class="btn small good" onclick="exportPlmLogsCsv()">导出 CSV</button><button class="btn small" onclick="closeModal()">关闭</button></div></div><div class="modal-body"><div class="plm-log-filter"><div class="field"><label>关键词</label><input id="plm_log_q" placeholder="项目 / 样品 / 动作 / 说明 / 人员" oninput="loadPlmLogs()"></div><div class="field"><label>开始日期</label><input id="plm_log_from" type="date" onchange="loadPlmLogs()"></div><div class="field"><label>结束日期</label><input id="plm_log_to" type="date" value="${today}" onchange="loadPlmLogs()"></div><div class="field"><label>操作人</label><input id="plm_log_person" placeholder="姓名/账号" oninput="loadPlmLogs()"></div><button class="btn primary" onclick="loadPlmLogs()">筛选</button></div><div id="plmLogBody"><div class="empty">正在读取日志...</div></div></div></div></div>`;
  await loadPlmLogs();
}
function plmLogParams(){return {q:$('plm_log_q')?.value||'',date_from:$('plm_log_from')?.value||'',date_to:$('plm_log_to')?.value||'',person:$('plm_log_person')?.value||'',limit:500};}
async function loadPlmLogs(){
  const box=$('plmLogBody'); if(!box)return;
  const r=await api('plm_logs',plmLogParams());
  if(!r.ok){box.innerHTML=`<div class="empty dangerText">${esc(r.error||'读取失败')}</div>`;return;}
  const rows=r.logs||[];
  box.innerHTML=`<div class="hint" style="margin-bottom:8px">共 ${rows.length} 条记录</div><div style="overflow:auto;max-height:62vh"><table class="plm-mini-table"><thead><tr><th>时间</th><th>操作人</th><th>项目</th><th>样品</th><th>对象</th><th>动作</th><th>说明</th></tr></thead><tbody>${rows.map(l=>`<tr><td>${esc(l.created_at||'-')}</td><td>${esc(l.user_name||l.username||'-')}</td><td>${esc(l.project_name||l.project_id||'-')}</td><td>${esc((l.model_name||'')+(l.model_code?' / '+l.model_code:''))}</td><td>${esc(l.target_type||'-')} #${esc(l.target_id||'')}</td><td>${esc(l.action||'-')}</td><td>${esc(l.note||'')}</td></tr>`).join('')||'<tr><td colspan="7">暂无日志</td></tr>'}</tbody></table></div>`;
}
function exportPlmLogsCsv(){
  const p=plmLogParams();
  const qs=new URLSearchParams(Object.assign({action:'plm_logs_export'},p));
  location.href=API+'?'+qs.toString();
}

async function showHealth(){const r=await api('health');if(!r.ok){showFatal(r.error);return}$('detail').innerHTML=`<h2>PLM V8.5.31 健康检查</h2><pre class="health">${esc(JSON.stringify(r,null,2))}</pre><button class="btn" onclick="renderDetail()">返回项目</button>`}
load();
setInterval(plmOnlinePing,60000);
</script>

